-- Poems batch 26
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('54e0d1e4-1585-48f0-996f-ca4b78660871','楊柳枝詞五首 五','姚合','唐','唐诗','tang','','[]','江亭楊柳折還垂，月照深黃幾樹絲。',32,'全唐诗/poet.tang.26000.json','["江亭楊柳折還垂，月照深黃幾樹絲。", "見說隋堤枯已盡，年年行客怪春遲。"]'),
('8a1ff478-e757-4b1d-933f-5a2d41000f42','郡中冬夜聞蛩','姚合','唐','唐诗','tang','','[]','秋蛩聲尚在，切切起蒼苔。',48,'全唐诗/poet.tang.26000.json','["秋蛩聲尚在，切切起蒼苔。", "久是忘情者，今還有事來。", "微霜風稍靜，圓月霧初開。", "此思誰能遣，應須執酒杯。"]'),
('1766005d-5639-4940-a8d8-75d358dddfb7','聞新蟬寄李餘','姚合','唐','唐诗','tang','','[]','往年六月蟬應到，每到聞時骨欲驚。',32,'全唐诗/poet.tang.26000.json','["往年六月蟬應到，每到聞時骨欲驚。", "今日槐花還似發，却愁聽盡更無聲。"]'),
('4653406d-ebc0-472c-9e93-7e4d184aedc9','聞蟬寄賈島','姚合','唐','唐诗','tang','','[]','秋來吟更苦，半咽半隨風。',48,'全唐诗/poet.tang.26000.json','["秋來吟更苦，半咽半隨風。", "禪客心應亂，愁人耳願聾。", "雨晴煙樹裏，日晚古城中。", "遠思應難盡，誰當與我同。"]'),
('0c5ba304-50ee-4272-85cb-dc5b66a11be3','題鶴雛','姚合','唐','唐诗','tang','','[]','羽毛生未齊，嶛峭醜於雞。',24,'全唐诗/poet.tang.26000.json','["羽毛生未齊，嶛峭醜於雞。", "夜夜穿籠出，擣衣碪上棲。"]'),
('27134196-0612-4123-b002-63e4c997b773','詠鶯','姚合','唐','唐诗','tang','','[]','春來深谷雪方消，鶯別寒林傍翠條。',64,'全唐诗/poet.tang.26000.json','["春來深谷雪方消，鶯別寒林傍翠條。", "到處爲憐煙景好，隔簾多愛語聲嬌。", "不同蜀魄啼殘月，唯逐天雞囀詰朝。", "少婦聽時思舊曲，玉樓從此動雲韶。"]'),
('fca1ed02-8646-4f54-95a1-452ab4385c44','老馬','姚合','唐','唐诗','tang','','["\u9a6c", "\u5199\u9a6c", "\u52b1\u5fd7"]','臥來扶不起，唯向主人嘶。',24,'全唐诗/poet.tang.26000.json','["臥來扶不起，唯向主人嘶。", "惆悵東郊道，秋來雨作泥。"]'),
('9d4e353b-f753-4ba5-a5f2-46d4d6b323aa','詠鏡','姚合','唐','唐诗','tang','','[]','鑄爲明鏡絕塵埃，翡翠窗前挂玉臺。',64,'全唐诗/poet.tang.26000.json','["鑄爲明鏡絕塵埃，翡翠窗前挂玉臺。", "繡帶共尋龍口出，菱花爭向匣中開。", "孤光常見鸞蹤在，分處還因鵲影迴。", "好是照身宜謝女，嫦娥飛向玉宮來。"]'),
('18de78ae-3992-47f1-8310-1d9e763d51a3','詠破屏風','姚合','唐','唐诗','tang','','[]','時人嫌古畫，倚壁不曾收。',48,'全唐诗/poet.tang.26000.json','["時人嫌古畫，倚壁不曾收。", "露滴膠山斷，風吹絹海秋。", "殘雲飛屋裏，片水落牀頭。", "尚勝凡花鳥，君能補綴不。"]'),
('86368bc3-181c-49f2-983c-c2e5d58db957','古碑','姚合','唐','唐诗','tang','','[]','荒田一片石，文字滿青苔。',24,'全唐诗/poet.tang.27000.json','["荒田一片石，文字滿青苔。", "不是逢閑客，何人肯讀來。"]'),
('3e0a8dea-f7cd-4026-967a-c19e8a2f6d17','拾得古硯','姚合','唐','唐诗','tang','','["\u9ec4\u6cb3"]','僻性愛古物，終歲求不獲。',120,'全唐诗/poet.tang.27000.json','["僻性愛古物，終歲求不獲。", "昨朝得古硯，黃河灘之側。", "念此黃河中，應有昔人宅。", "宅亦作流水，斯硯未變易。", "波瀾所激觸，背面生罅隙。", "質狀朴且醜，今人作不得。", "捧持且驚歎，不敢施筆墨。", "或恐先聖人，嘗用修六籍。", "置之潔淨室，一日三磨拭。", "大喜豪貴嫌，久長得保惜。"]'),
('c2aa67b7-6fe5-42ee-8906-c3b165f09b9b','裴大夫見過','姚合','唐','唐诗','tang','','[]','湖南譙國盡英髦，心事相期節義高。',32,'全唐诗/poet.tang.27000.json','["湖南譙國盡英髦，心事相期節義高。", "解下佩刀無所惜，新聞天子付三刀。"]'),
('f7c74a64-fb3e-4a8e-bbdd-f8334fa4713c','謝韜光上人贈百齡藤杖','姚合','唐','唐诗','tang','','[]','衰病近來行少力，光公乞我百齡藤。',32,'全唐诗/poet.tang.27000.json','["衰病近來行少力，光公乞我百齡藤。", "閑來杖此向何處，過水緣山只訪僧。"]'),
('86a314d1-f78d-4c5e-9ae4-a8b3cd209f6a','詠貴遊','姚合','唐','唐诗','tang','','[]','貴遊多愛向深春，到處香凝數里塵。',64,'全唐诗/poet.tang.27000.json','["貴遊多愛向深春，到處香凝數里塵。", "紅杏花開連錦障，綠楊陰合拂朱輪。", "鳳凰尊畔飛金盞，絲竹聲中醉玉人。", "日暮垂鞭共歸去，西園賓客附龍鱗。"]'),
('471f6a79-5613-4eb3-92e6-e0d7be59ceee','窮邊詞二首 一','姚合','唐','唐诗','tang','','[]','將軍作鎮古汧洲，水膩山春節氣柔。',32,'全唐诗/poet.tang.27000.json','["將軍作鎮古汧洲，水膩山春節氣柔。", "清夜滿城絲管散，行人不信是邊頭。"]'),
('1215d307-3061-42b3-ac8b-3028b20f668c','窮邊詞二首 二','姚合','唐','唐诗','tang','','[]','箭利弓調四鎮兵，蕃人不敢近東行。',32,'全唐诗/poet.tang.27000.json','["箭利弓調四鎮兵，蕃人不敢近東行。", "沿邊千里渾無事，唯見平安火入城。"]'),
('25006f73-9c04-4513-bd90-80ad99c57f4e','劍器詞三首 一','姚合','唐','唐诗','tang','','[]','聖朝能用將，破敵速如神。',48,'全唐诗/poet.tang.27000.json','["聖朝能用將，破敵速如神。", "掉劍龍纏臂，開旗火滿身。", "積屍川沒岸，流血野無塵。", "今日當場舞，應知是戰人。"]'),
('2cc39dd5-2a57-48db-895a-7ca403b79649','劍器詞三首 二','姚合','唐','唐诗','tang','','["\u9ec4\u6cb3"]','晝渡黃河水，將軍險用師。',48,'全唐诗/poet.tang.27000.json','["晝渡黃河水，將軍險用師。", "雪光偏著甲，風力不禁旗。", "陣變龍蛇活，軍雄鼓角知。", "今朝重起舞，記得戰酣時。"]'),
('2509ebb5-76c2-4aa9-87a9-da9218953650','劍器詞三首 三','姚合','唐','唐诗','tang','','[]','破虜行千里，三軍意氣麤。',48,'全唐诗/poet.tang.27000.json','["破虜行千里，三軍意氣麤。", "展旗遮日黑，驅馬飲河枯。", "鄰境求兵略，皇恩索陣圖。", "元和太平樂，自古恐應無。"]'),
('fef8ee27-bca1-494f-9205-3f712688287d','從軍樂二首 一','姚合','唐','唐诗','tang','','[]','每日尋兵籍，經年別酒徒。',48,'全唐诗/poet.tang.27000.json','["每日尋兵籍，經年別酒徒。", "眼疼長不校，肺病且還無。", "僮僕驚衣窄，親情覺語麤。", "幾時得歸去，依舊作山夫。"]'),
('fb7d9187-cd4e-46e2-9f8d-fb13e3264298','從軍樂二首 二','姚合','唐','唐诗','tang','','[]','朝朝十指痛，唯署點兵符。',48,'全唐诗/poet.tang.27000.json','["朝朝十指痛，唯署點兵符。", "貧賤依前在，顛狂一半無。", "身慙山友棄，膽賴酒杯扶。", "誰道從軍樂，年來鑷白鬚。"]'),
('38890c98-37a2-4f3d-9bf6-8b27a725d20d','敬宗皇帝挽詞三首 一','姚合','唐','唐诗','tang','','[]','從諫停東幸，垂衣寶曆昌。',48,'全唐诗/poet.tang.27000.json','["從諫停東幸，垂衣寶曆昌。", "漢昭登位少，周代卜年長。", "綵仗三清路，麻衣萬國喪。", "玄宮今一閉，終古柏蒼蒼。"]'),
('940a7513-8fcb-4b7b-bae4-9ed2d914b193','敬宗皇帝挽詞三首 二','姚合','唐','唐诗','tang','','[]','晚色啓重扉，旌旗路漸移。',48,'全唐诗/poet.tang.27000.json','["晚色啓重扉，旌旗路漸移。", "荆山鼎成日，湘浦竹斑時。", "臣子終身感，山園七月期。", "金莖看尚在，承露復何爲。"]'),
('b617fe25-89d9-41cd-89ab-bab237230c6d','敬宗皇帝挽詞三首 三','姚合','唐','唐诗','tang','','[]','紫陌起仙飆，川原共寂寥。',48,'全唐诗/poet.tang.27000.json','["紫陌起仙飆，川原共寂寥。", "靈輴萬國護，儀殿百神朝。", "漏滴秋風路，笳吟灞水橋。", "微臣空感咽，踊絕覺天遙。"]'),
('4547c263-338b-45a0-aa4c-f5df4f353d4b','文宗皇帝挽詞三首 一','姚合','唐','唐诗','tang','','[]','垂拱開成化，愔愔雅樂全。',48,'全唐诗/poet.tang.27000.json','["垂拱開成化，愔愔雅樂全。", "千官方就日，四海忽無天。", "堯舜非傳子，殷周但卜年。", "聖功青史外，刊石在陵前。"]'),
('aa1e8310-db3b-4856-aa11-8f252bd327c5','文宗皇帝挽詞三首 二','姚合','唐','唐诗','tang','','[]','代以無爲理，車書萬國同。',48,'全唐诗/poet.tang.27000.json','["代以無爲理，車書萬國同。", "繼兄還付弟，授聖悉推公。", "雲霧疑無日，笳簫別起風。", "金莖難復見，寒露落空中。"]'),
('ea042894-4c65-4f8f-a66b-9aa05d5d7eef','文宗皇帝挽詞三首 三','姚合','唐','唐诗','tang','','[]','龍歸攀不得，髯在侍臣邊。',48,'全唐诗/poet.tang.27000.json','["龍歸攀不得，髯在侍臣邊。", "徹奠新阡起，登山吉從全。", "關河佳氣散，夷夏哭聲連。", "寂寞玄宮閉，朝昏千萬年。"]'),
('b0192954-3cc1-4011-8e38-42306e393558','莊恪太子挽詞二首 一','姚合','唐','唐诗','tang','','[]','曉漏啓嚴城，宮臣縞素行。',48,'全唐诗/poet.tang.27000.json','["曉漏啓嚴城，宮臣縞素行。", "靈儀先鹵簿，新諡在銘旌。", "雲晦郊原色，風連霰雪聲。", "淒涼望苑路，春草即應生。"]'),
('afa360a0-2b50-42a4-992f-ec0b678b52b5','莊恪太子挽詞二首 二','姚合','唐','唐诗','tang','','[]','寒日春宮閉，玄堂渭水濱。',48,'全唐诗/poet.tang.27000.json','["寒日春宮閉，玄堂渭水濱。", "華夷牋乍絕，凶吉禮空新。", "薤露歌連哭，泉扉夜作晨。", "吹笙今一去，千古在逡巡。"]'),
('d9d1d9e2-070a-46d1-b2d8-d20daa48fae6','哭費拾遺徵君','姚合','唐','唐诗','tang','','[]','服儒師道旨，糲食臥中林。',48,'全唐诗/poet.tang.27000.json','["服儒師道旨，糲食臥中林。", "誰識先生事，無身是本心。", "空山流水遠，故國白雲深。", "日夕誰來哭，唯應猨鳥吟。"]'),
('772fc049-bbd0-4e0d-bc69-037bcfbc8507','哭硯山孫道士','姚合','唐','唐诗','tang','','[]','修短皆由命，暗懷師出塵。',48,'全唐诗/poet.tang.27000.json','["修短皆由命，暗懷師出塵。", "豈知修道者，難免不亡身。", "永祕黃庭訣，高懸漉酒巾。", "可憐白犬子，閑吠遠行人。"]'),
('b8363f30-9288-4a31-9f33-1455bf6ce49d','哭賈島二首 一','姚合','唐','唐诗','tang','','[]','白日西邊沒，滄波東去流。',48,'全唐诗/poet.tang.27000.json','["白日西邊沒，滄波東去流。", "名雖千古在，身已一生休。", "豈料文章遠，那知瑞草秋。", "曾聞有書劍，應是別人收。"]'),
('9e99c38d-8a96-4627-98d0-219f8e2e41ac','哭賈島二首 二','姚合','唐','唐诗','tang','','[]','杳杳黃泉下，嗟君向此行。',48,'全唐诗/poet.tang.27000.json','["杳杳黃泉下，嗟君向此行。", "有名傳後世，無子過今生。", "新墓松三尺，空堦月二更。", "從今舊詩卷，人覓寫應爭。"]'),
('d2dc697e-9e07-43d0-a857-c60c38483079','楊給事師臯哭亡愛姬英英竊聞詩人多賦因而繼和','姚合','唐','唐诗','tang','','[]','真珠爲土玉爲塵，未識遙聞鼻亦辛。',64,'全唐诗/poet.tang.27000.json','["真珠爲土玉爲塵，未識遙聞鼻亦辛。", "天上還應收至寶，世間難得是佳人。", "朱絲自斷虛銀燭，紅粉潛銷冷繡裀。", "見說忘情唯有酒，夕陽對酒更傷神。"]'),
('b0fe05d3-f1a7-444c-9507-697ceb2869c3','喜覽涇州盧侍御詩卷','姚合','唐','唐诗','tang','','[]','新詩十九首，麗格出青冥。',48,'全唐诗/poet.tang.27000.json','["新詩十九首，麗格出青冥。", "得處神應駭，成時力盡停。", "正愁聞更喜，沈醉見還醒。", "自是天才健，非關筆硯靈。"]'),
('50f44e3f-f1ec-4ad2-9688-f7389b912c70','喜覽裴中丞詩卷','姚合','唐','唐诗','tang','','[]','新詩盈道路，清韻似敲金。',48,'全唐诗/poet.tang.27000.json','["新詩盈道路，清韻似敲金。", "調格江山峻，功夫日月深。", "蜀牋方入寫，越客始消吟。", "後輩難知處，朝朝枉用心。"]'),
('8be3d04c-daf4-423a-8ea8-e754201bdf3c','心懷霜','姚合','唐','唐诗','tang','','[]','欲識爲詩苦，秋霜若在心。',72,'全唐诗/poet.tang.27000.json','["欲識爲詩苦，秋霜若在心。", "神清方耿耿，氣肅覺沈沈。", "皓素中方委，嚴凝得更深。", "依稀輕夕渚，髣髴在寒林。", "思勁淒孤韻，聲酸激冷吟。", "還如飲冰士，勵節望知音。"]'),
('71825319-9f76-44c8-b45a-62556a392c85','聽僧雲端講經','姚合','唐','唐诗','tang','','[]','無生深旨誠難解，唯是師言得正真。',32,'全唐诗/poet.tang.27000.json','["無生深旨誠難解，唯是師言得正真。", "遠近遲齋來諦聽，酒坊魚市盡無人。"]'),
('314c2e77-273a-4ae3-883a-0f06eed2a507','臘日獵','姚合','唐','唐诗','tang','','["\u957f\u6c5f"]','健夫結束執旌旗，曉度長江自合圍。',64,'全唐诗/poet.tang.27000.json','["健夫結束執旌旗，曉度長江自合圍。", "野外狐狸搜得盡，天邊鴻雁射來稀。", "蒼鷹落日飢唯急，白馬平川走似飛。", "蜡節畋遊非爲己，莫驚刺史夜深歸。"]'),
('7c9225fa-d258-41da-bc99-fc26ffa5aadd','聞魏州破賊','姚合','唐','唐诗','tang','','[]','生靈蘇息到元和，上將功成自執戈。',64,'全唐诗/poet.tang.27000.json','["生靈蘇息到元和，上將功成自執戈。", "煙霧掃開尊北岳，蛟龍斬斷淨南河。", "旗迴海眼軍容壯，兵合天心殺氣多。", "從此四方無一事，朝朝雨露是恩波。"]'),
('c0c9f2bd-43d9-45d5-8621-024c4e636210','下第','姚合','唐','唐诗','tang','','[]','枉爲鄉里舉，射鵠藝渾疎。',48,'全唐诗/poet.tang.27000.json','["枉爲鄉里舉，射鵠藝渾疎。", "歸路羞人問，春城賃舍居。", "閉門辭雜客，開篋讀生書。", "以此投知己，還因勝自餘。"]'),
('87ec9916-7290-4d04-bb0e-b5c7ae5912dc','得舍弟書','姚合','唐','唐诗','tang','','[]','親戚多離散，三年獨在城。',36,'全唐诗/poet.tang.27000.json','["親戚多離散，三年獨在城。", "貧居深穩臥，晚學愛閑名。", "小弟有書至，異鄉無地行。"]'),
('560fc1bf-3e71-44a6-b7b2-0b5cf29c7ed9','病僧','姚合','唐','唐诗','tang','','[]','三年病不出，苔蘚滿藤鞋。',48,'全唐诗/poet.tang.27000.json','["三年病不出，苔蘚滿藤鞋。", "倚壁看經坐，聞鐘喫藥齋。", "茶烟熏殺竹，簷雨滴穿堦。", "無暇頻相訪，秋風寂寞懷。"]'),
('bd683292-ee3f-4147-afd5-a5736256b6b9','成名後留別從兄','姚合','唐','唐诗','tang','','[]','一辭山舍廢躬耕，無事悠悠住帝城。',64,'全唐诗/poet.tang.27000.json','["一辭山舍廢躬耕，無事悠悠住帝城。", "爲客衣裳多不穩，和人詩句固難精。", "幾年秋賦唯知病，昨日春闈偶有名。", "却出關東悲復喜，歸尋弟妹別仁兄。"]'),
('297cebe2-a920-49df-92a4-2a1603525860','佛舍見胡子有嘲','姚合','唐','唐诗','tang','','[]','明明復夜夜，胡子即成翁。',24,'全唐诗/poet.tang.27000.json','["明明復夜夜，胡子即成翁。", "唯是真知性，不來生滅中。"]'),
('ddb3e27f-6d99-442a-8a6a-db814057dfab','白鼻騧','姚合','唐','唐诗','tang','','[]','爲底胡姬酒，長來白鼻騧。',24,'全唐诗/poet.tang.27000.json','["爲底胡姬酒，長來白鼻騧。", "摘蓮拋水上，郎意在浮花。"]'),
('addfe0d6-daeb-4314-bc82-7b9ffe987a5d','崔少卿鶴','姚合','唐','唐诗','tang','','[]','入門石徑半高低，閑處無非是藥畦。',32,'全唐诗/poet.tang.27000.json','["入門石徑半高低，閑處無非是藥畦。", "致得仙禽無去意，花間舞罷洞中棲。"]'),
('9652d226-f357-4777-b5cf-3ce338eb665a','新昌里','姚合','唐','唐诗','tang','','[]','舊客常樂坊，井泉濁而鹹。',96,'全唐诗/poet.tang.27000.json','["舊客常樂坊，井泉濁而鹹。", "新屋新昌里，井泉清而甘。", "僮僕慣苦飲，食美翻憎嫌。", "朝朝忍飢行，戚戚如難堪。", "中下無正性，所習便淫耽。", "一染不可變，甚於茜與藍。", "近貧日益廉，近富日益貪。", "以此當自警，慎勿信邪讒。"]'),
('7f0ef758-e22b-470b-919b-3cd6788777fc','塞下曲','姚合','唐','唐诗','tang','','[]','磧露黃雲下，凝寒鼓不鳴。',48,'全唐诗/poet.tang.27000.json','["磧露黃雲下，凝寒鼓不鳴。", "戰須移死地，軍諱殺降兵。", "印馬秋遮虜，蒸沙夜築城。", "舊鄉歸不得，都尉負功名。"]'),
('a1781a53-e928-422a-a6aa-a1c9e1e5bb03','從軍行','姚合','唐','唐诗','tang','','[]','濫得進士名，才用苦不長。',144,'全唐诗/poet.tang.27000.json','["濫得進士名，才用苦不長。", "性癖藝亦獨，十年作詩章。", "六義雖粗成，名字猶未揚。", "將軍俯招引，遣脫儒衣裳。", "常恐虛受恩，不慣把刀鎗。", "又無遠籌略，坐使虜滅亡。", "昨來發兵師，各各赴戰場。", "顧我同老弱，不得隨戎行。", "丈夫生世間，職分貴所當。", "從軍不出門，豈異病在牀。", "誰不戀其家，其家無風霜。", "鷹鶻念搏擊，豈貴食滿腸。"]'),
('9a64fc76-a86c-4810-80f5-e945c262013a','杏園','姚合','唐','唐诗','tang','','[]','江頭數頃杏花開，車馬爭先盡此來。',32,'全唐诗/poet.tang.27000.json','["江頭數頃杏花開，車馬爭先盡此來。", "欲待無人連夜看，黃昏樹樹滿塵埃。"]'),
('b2486eb7-6ad1-45c6-959c-20d8ae99f0f1','閑居','姚合','唐','唐诗','tang','','[]','日日門長閉，隣家亦懶過。',48,'全唐诗/poet.tang.27000.json','["日日門長閉，隣家亦懶過。", "頭風春飲苦，眼暈夜書多。", "幽鳥偏栖竹，凡人笑種莎。", "近來難得酒，無計奈愁何。"]'),
('283e47ac-1da0-4dbe-b39d-c5b5d68bcdd3','句','姚合','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','天遙來鴈小，江闊去帆孤。',76,'全唐诗/poet.tang.27000.json','["天遙來鴈小，江闊去帆孤。", "南陌遊人回首去，東林道者杖藜歸。", "萄藤洞庭頭，引葉漾盈搖。", "皎潔鉤高掛，玲瓏影落寮。", "陰煙壓幽屋，濛密夢冥苗。", "清秋青且翠，冬到凍都凋。"]'),
('bd7e6d52-7290-4cfa-b879-34cdb535858a','留辭杭州姚合郎中','周賀','唐','唐诗','tang','','[]','波濤千里隔，抱疾亦相尋。',48,'全唐诗/poet.tang.27000.json','["波濤千里隔，抱疾亦相尋。", "會宿逢高士，辭歸值積霖。", "叢桑山店迥，孤燭海船深。", "尚有重來約，知無省閣心。"]'),
('482474aa-e3c4-4b3d-a674-19e34c629cf3','酬吳之問見贈','周賀','唐','唐诗','tang','','[]','已當鳴鴈夜，多事不同居。',48,'全唐诗/poet.tang.27000.json','["已當鳴鴈夜，多事不同居。", "故疾離城晚，秋霖見月疎。", "趂風開靜戶，帶葉卷殘書。", "盪槳期南去，荒園久廢鋤。"]'),
('2e646038-3c38-49a1-a03b-177acf998bca','送分定歸靈夏','周賀','唐','唐诗','tang','','[]','南遊多老病，見說講經稀。',48,'全唐诗/poet.tang.27000.json','["南遊多老病，見說講經稀。", "塞寺幾僧在，關城空自歸。", "帶河衰草斷，映日旱沙飛。", "却到禪齋後，邊軍識衲衣。"]'),
('964ef6eb-ddd3-4e93-89be-bd6b29ff980e','與崔弇話別','周賀','唐','唐诗','tang','','[]','歸思緣平澤，幽齋夜話遲。',48,'全唐诗/poet.tang.27000.json','["歸思緣平澤，幽齋夜話遲。", "人尋馮翊去，草向建康衰。", "雨雪生中路，干戈阻後期。", "幾年方見面，應是鑷蒼髭。"]'),
('d838c11e-a7fb-4923-b62b-02bca391e754','題何氏池亭','周賀','唐','唐诗','tang','','[]','信是虛閑地，亭高亦有苔。',48,'全唐诗/poet.tang.27000.json','["信是虛閑地，亭高亦有苔。", "繞池逢石坐，穿竹引山回。", "果落纖萍散，龜行細草開。", "主人偏好事，終不厭頻來。"]'),
('cd5052da-5171-43d9-b95e-861b52e9a1a8','送表兄東南遊','周賀','唐','唐诗','tang','','[]','山水疊層層，吾兄涉又登。',48,'全唐诗/poet.tang.27000.json','["山水疊層層，吾兄涉又登。", "挂帆春背鴈，尋磬夜逢僧。", "雪溜懸衡嶽，江雲蓋秣陵。", "評文永不忘，此說是中興。"]'),
('9475e75b-57c7-4e46-88ff-ad944a7fcbda','送康紹歸建業','周賀','唐','唐诗','tang','','[]','南朝秋色滿，君去意如何。',48,'全唐诗/poet.tang.27000.json','["南朝秋色滿，君去意如何。", "帝業空城在，民田壞塚多。", "月圓臺獨上，栗綻寺頻過。", "籬下西江闊，相思見白波。"]'),
('40114e57-5d42-41e0-9f4e-afb6047b7e87','再過王輅原居納涼','周賀','唐','唐诗','tang','','[]','夏天多憶此，早晚得秋分。',48,'全唐诗/poet.tang.27000.json','["夏天多憶此，早晚得秋分。", "舊月來還見，新蟬坐忽聞。", "扇風調病葉，溝水隔殘雲。", "別有微涼處，從容不似君。"]'),
('8835f67a-9c1c-4191-9b4e-d7b537b1c633','送耿山人歸湖南','周賀','唐','唐诗','tang','','[]','南行隨越僧，別業幾池菱。',48,'全唐诗/poet.tang.27000.json','["南行隨越僧，別業幾池菱。", "兩鬢已垂白，五湖歸挂罾。", "夜濤鳴柵鏁，寒葦露船燈。", "去此應無事，却來知不能。"]'),
('36bd0333-5165-4f22-b5c6-63a6e87102dd','送省己上人歸太原','周賀','唐','唐诗','tang','','[]','惜別聽邊漏，窗燈落燼重。',48,'全唐诗/poet.tang.27000.json','["惜別聽邊漏，窗燈落燼重。", "寒僧迴絕塞，夕雪下窮冬。", "出定聞殘角，休兵見壞鋒。", "何年更來此，老却倚堦松。"]'),
('5116d785-f548-46c3-aa12-787f9e207a05','宿甄山南溪晝公院','周賀','唐','唐诗','tang','','[]','從作兩河客，別離經半年。',48,'全唐诗/poet.tang.27000.json','["從作兩河客，別離經半年。", "却來峰頂宿，知廢甄南禪。", "餘霧沈斜月，孤燈照落泉。", "何當閑事盡，相伴老溪邊。"]'),
('54ac7641-0227-45f4-8441-d25907aa1be2','相次尋舉客寄住人','周賀','唐','唐诗','tang','','[]','停橈因舊識，白髮向波濤。',48,'全唐诗/poet.tang.27000.json','["停橈因舊識，白髮向波濤。", "以我往來倦，知君耕稼勞。", "渚田臨舍盡，坂路出簷高。", "遊者還南去，終期伴爾曹。"]'),
('b51cb24b-97cf-4301-8a58-2cbc0920ab3a','出關寄賈島','周賀','唐','唐诗','tang','','[]','舊鄉無子孫，誰共老青門。',48,'全唐诗/poet.tang.27000.json','["舊鄉無子孫，誰共老青門。", "迢遞早秋路，別離深夜村。", "伊流偕行客，岳響答啼猿。", "去後期招隱，何當復此言。"]'),
('e877ba74-231b-4b4a-9c90-cc9eb8aacf70','暮冬長安旅舍','周賀','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','湖外誰相識，思歸日日頻。',48,'全唐诗/poet.tang.27000.json','["湖外誰相識，思歸日日頻。", "遍尋新住客，少見故鄉人。", "失計空知命，勞生耻爲身。", "惟看洞庭樹，即是舊山春。"]'),
('c821b5c9-f076-4bf1-ade3-da81946beca1','贈胡僧','周賀','唐','唐诗','tang','','[]','瘦形無血色，草履著行穿。',48,'全唐诗/poet.tang.27000.json','["瘦形無血色，草履著行穿。", "閑話似持咒，不眠同坐禪。", "背經來漢地，袒膊過冬天。", "情性人難會，遊方應信緣。"]'),
('a762bfed-fe92-47f4-9729-c50eddc8dc4a','贈李主簿','周賀','唐','唐诗','tang','','[]','稅時兼主印，每日得閑稀。',48,'全唐诗/poet.tang.27000.json','["稅時兼主印，每日得閑稀。", "對酒妨料吏，爲官亦典衣。", "案遲吟坐待，宅近步行歸。", "見說論詩道，應愁判是非。"]'),
('b386fffa-a03b-4c3a-965c-736faea9b839','同朱慶餘宿翊西上人房','周賀','唐','唐诗','tang','','[]','溪僧還共謁，相與坐寒天。',48,'全唐诗/poet.tang.27000.json','["溪僧還共謁，相與坐寒天。", "屋雪凌高燭，山茶稱遠泉。", "夜清更徹寺，空闊雁衝煙。", "莫怪多時話，重來又隔年。"]'),
('ae71e98d-dd8d-4232-86b2-151f8e94e3b7','寄姚合郎中','周賀','唐','唐诗','tang','','[]','轉刺名山郡，連年別省曹。',48,'全唐诗/poet.tang.27000.json','["轉刺名山郡，連年別省曹。", "分題得客少，著價買書高。", "晚柳蟬和角，寒城燭照濤。", "鄱溪臥疾久，未獲後乘騷。"]'),
('1c71e03f-06bf-4977-b139-ce4d41f79522','休糧僧','周賀','唐','唐诗','tang','','[]','一齋難過日，況是更休糧。',48,'全唐诗/poet.tang.27000.json','["一齋難過日，況是更休糧。", "養力時行道，聞鐘不上堂。", "惟留溫藥火，未寫化金方。", "舊有山廚在，從僧請作房。"]'),
('1a0605fe-c927-4232-88a3-ec0bb3c844ef','懷西峰隱者','周賀','唐','唐诗','tang','','[]','灌木藏岑色，天寒望即愁。',48,'全唐诗/poet.tang.27000.json','["灌木藏岑色，天寒望即愁。", "高齋何日去，遠瀑入城流。", "臘近溪書絕，燈殘夜雪稠。", "邇來相憶處，枕上苦吟休。"]'),
('fc418804-a826-4621-9ca9-5540537e61e1','贈栢巖禪師','周賀','唐','唐诗','tang','','[]','野寺絕依念，靈山會遍行。',48,'全唐诗/poet.tang.27000.json','["野寺絕依念，靈山會遍行。", "老來披衲重，病後讀經生。", "乞食嫌村遠，尋溪愛路平。", "多年栢巖住，不記栢巖名。"]'),
('74865fb6-18fa-4dc2-8f23-4d88738f0f5a','旅懷','周賀','唐','唐诗','tang','','[]','不覺月又盡，未歸還到春。',48,'全唐诗/poet.tang.27000.json','["不覺月又盡，未歸還到春。", "雪通廬岳夢，樹匝草堂身。", "澤鴈和寒露，江槎帶遠薪。", "何年自此去，舊國復爲隣。"]'),
('83ac99c1-df3d-4870-8d4d-8eb738023777','緱氏韋明府廳','周賀','唐','唐诗','tang','','[]','貴邑清風滿，誰同上宰心。',48,'全唐诗/poet.tang.27000.json','["貴邑清風滿，誰同上宰心。", "杉松出郭外，雨電下嵩陰。", "度鴈方離壘，來僧始別岑。", "西池月纔迥，會接一宵吟。"]'),
('f9b55609-e291-4ada-8afd-d3322d3e02fd','送朱慶餘','周賀','唐','唐诗','tang','','[]','野客行無定，全家在浦東。',48,'全唐诗/poet.tang.27000.json','["野客行無定，全家在浦東。", "寄眠僧閣靜，贈別橐金空。", "舊里千山隔，歸舟百計同。", "藥資如有分，相約老吳中。"]'),
('d3411d81-2a52-46f6-a93a-6f23d8a46169','宿開元寺樓','周賀','唐','唐诗','tang','','[]','西峰殘日落，誰見寂寥心。',48,'全唐诗/poet.tang.27000.json','["西峰殘日落，誰見寂寥心。", "孤枕客眠久，兩廊僧話深。", "寒扉關雨氣，風葉隱鐘音。", "此愛東樓望，仍期別夜尋。"]'),
('fbab71b3-07b0-4eb3-890c-ad1cf5898bf5','送僧還南岳','周賀','唐','唐诗','tang','','[]','辭僧下水柵，因夢嶽鐘聲。',48,'全唐诗/poet.tang.27000.json','["辭僧下水柵，因夢嶽鐘聲。", "遠路獨歸寺，幾時重到城。", "風高寒葉落，雨絕夜堂清。", "自說深居後，隣州亦不行。"]'),
('5ae6575a-a11c-46f8-bbcf-561bdf6c37aa','秋思','周賀','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','楊柳已秋思，楚田仍刈禾。',48,'全唐诗/poet.tang.27000.json','["楊柳已秋思，楚田仍刈禾。", "歸心病起切，敗葉夜來多。", "細雨城蟬噪，殘陽嶠客過。", "舊山餘業在，杳隔洞庭波。"]'),
('71e35a76-b0f6-44d6-810d-dc398c78b637','旅情','周賀','唐','唐诗','tang','','[]','黃葉下堦頻，徐徐起病身。',48,'全唐诗/poet.tang.27000.json','["黃葉下堦頻，徐徐起病身。", "殘秋螢出盡，獨夜鴈來新。", "別業去千里，舊鄉空四隣。", "孤舟尋幾度，又識岳陽人。"]'),
('514dab56-217e-436a-8eb2-72e611bbd72f','送靈應禪師','周賀','唐','唐诗','tang','','[]','寒天仍遠去，離寺雪霏霏。',48,'全唐诗/poet.tang.27000.json','["寒天仍遠去，離寺雪霏霏。", "古跡曾重到，生涯不暫歸。", "坐禪山店暝，補衲夜燈微。", "巡禮何時住，相逢的是稀。"]'),
('d7e39698-6921-4aea-90f7-e5607c257f6c','送陸判官防秋','周賀','唐','唐诗','tang','','[]','匹馬無窮地，三年逐大軍。',48,'全唐诗/poet.tang.27000.json','["匹馬無窮地，三年逐大軍。", "筭程淮邑遠，起帳夕陽曛。", "瀑浪行時漱，邊笳語次聞。", "要傳書札去，應到磧東雲。"]'),
('00dd6d9a-598e-402e-a8f1-194c1a2eb301','山居秋思','周賀','唐','唐诗','tang','','[]','一從雲水住，曾不下西岑。',48,'全唐诗/poet.tang.27000.json','["一從雲水住，曾不下西岑。", "落木孤猨在，秋庭積霧深。", "泉流通井脉，蟲響出牆陰。", "夜靜溪聲徹，寒燈尚獨吟。"]'),
('880d36d4-1579-43de-9652-8de3588b5ec8','贈皎然上人','周賀','唐','唐诗','tang','','[]','竹庭瓶水新，深稱北窗人。',48,'全唐诗/poet.tang.27000.json','["竹庭瓶水新，深稱北窗人。", "講罷見黃葉，詩成尋舊隣。", "錫陰迷坐石，池影露齋身。", "苦作南行約，勞生始問津。"]'),
('67990313-eb65-4f52-bd0c-5fdc7480f138','春日山居寄友人','周賀','唐','唐诗','tang','','[]','春居無俗喧，時立澗前村。',48,'全唐诗/poet.tang.27000.json','["春居無俗喧，時立澗前村。", "路遠少來客，山深多過猨。", "帶巖松色老，臨水杏花繁。", "除憶文流外，何人更可言。"]'),
('4e514269-e2cb-41f6-b82f-d702795044cd','留別南徐故人','周賀','唐','唐诗','tang','','[]','三年蒙見待，此夕是前程。',50,'全唐诗/poet.tang.27000.json','["三年蒙見待，此夕是前程。", "未斷却來約，且伸臨去情。", "潮[迴]灘鳥下，月上客船明。", "他日南徐道，緣君又重行。"]'),
('7f667bc9-3950-4867-88e8-2d9c4ee6fb45','送僧歸江南','周賀','唐','唐诗','tang','','[]','洗足北林去，遠途今已分。',48,'全唐诗/poet.tang.27000.json','["洗足北林去，遠途今已分。", "麻衣行嶽色，竹杖帶湘雲。", "飢鼠緣危壁，寒狸出壞墳。", "前峰一聲磬，此夕不同聞。"]'),
('17ad1311-7dfb-4121-b2b9-912a919f76bb','早春越中留故人','周賀','唐','唐诗','tang','','[]','此行經歲近，唯約半年迴。',48,'全唐诗/poet.tang.27000.json','["此行經歲近，唯約半年迴。", "野渡人初過，前山雲未開。", "鴈羣逢曉斷，林色映川來。", "清夜蘆中客，嚴家舊釣臺。"]'),
('26ebbb5a-c457-4802-928e-b3aab829273c','送友人','周賀','唐','唐诗','tang','','[]','彈琴多去情，浮檝背潮行。',48,'全唐诗/poet.tang.27000.json','["彈琴多去情，浮檝背潮行。", "人望豐壖宿，蟲依蠹木鳴。", "檣煙離浦色，蘆雨入船聲。", "如疾登雲路，憑君寄此生。"]'),
('e0acce92-6b0a-4ba6-8e26-f0169a47a7fa','春日重到王依村居','周賀','唐','唐诗','tang','','[]','野煙居舍在，曾約此重過。',48,'全唐诗/poet.tang.27000.json','["野煙居舍在，曾約此重過。", "久雨初招客，新田未種禾。", "夜蟲鳴井浪，春鳥宿庭柯。", "莫爲兒孫役，餘生能幾何。"]'),
('a084ed37-cecd-406f-9575-9368c419beff','入靜隱寺途中作','周賀','唐','唐诗','tang','','[]','亂雲迷遠寺，入路認青松。',48,'全唐诗/poet.tang.27000.json','["亂雲迷遠寺，入路認青松。", "鳥道緣巢影，僧鞋印雪踪。", "草煙連野燒，溪霧隔霜鐘。", "更遇樵人問，猶言過數峰。"]'),
('cf8149fa-8eb1-4eb3-b2a1-337111a5c021','送楊嶽歸巴陵','周賀','唐','唐诗','tang','','[]','何處得鄉信，告行當雨天。',48,'全唐诗/poet.tang.27000.json','["何處得鄉信，告行當雨天。", "人離京口日，潮送岳陽船。", "孤鳥背林色，遠帆開浦煙。", "悲君惟此別，不肯話迴年。"]'),
('51411760-ad76-42be-848f-0ac8f42b5068','贈朱慶餘校書','周賀','唐','唐诗','tang','','[]','風泉盡結冰，寒夢徹西陵。',48,'全唐诗/poet.tang.27000.json','["風泉盡結冰，寒夢徹西陵。", "越信楚城得，遠懷中夜興。", "樹停沙島鶴，茶會石橋僧。", "寺閣連官舍，行吟過幾層。"]'),
('cd7ed5af-3abb-4765-83a6-d8ccccf8839e','逢播公','周賀','唐','唐诗','tang','','[]','帶病希相見，西城早晚來。',48,'全唐诗/poet.tang.27000.json','["帶病希相見，西城早晚來。", "衲衣風壞帛，香印雨霑灰。", "坐久鐘聲盡，談餘嶽影迴。", "却思同宿夜，高枕說天台。"]'),
('190d7dce-1b19-497c-9f92-1cd0070e9437','尋北岡韓處士','周賀','唐','唐诗','tang','','[]','相過值早涼，松帚掃山牀。',48,'全唐诗/poet.tang.27000.json','["相過值早涼，松帚掃山牀。", "坐石泉痕黑，登城蘚色黃。", "逆風沈寺磬，初日曬隣桑。", "幾處逢僧說，期來宿北岡。"]'),
('b8fc55b9-a01a-4006-a5ed-1f29caaedce1','哭閑霄上人','周賀','唐','唐诗','tang','','[]','林逕西風急，松枝講鈔餘。',48,'全唐诗/poet.tang.27000.json','["林逕西風急，松枝講鈔餘。", "凍髭亡夜剃，遺偈病時書。", "地燥焚身後，堂空著影初。", "弔來頻落淚，曾憶到吾廬。"]'),
('59f6efd0-abbf-451c-b905-5d79ecceebc0','城中秋作','周賀','唐','唐诗','tang','','[]','已落關東葉，空懸浙右心。',48,'全唐诗/poet.tang.27000.json','["已落關東葉，空懸浙右心。", "寒燈隨故病，伏雨接秋霖。", "客話曾誰和，蟲聲少我吟。", "蒹葭半波水，夜夜宿邊禽。"]'),
('c14f9cfa-d6c2-4c5a-b819-98c161ef75dd','玉芝觀王道士','周賀','唐','唐诗','tang','','[]','四面杉蘿合，空堂畫老仙。',48,'全唐诗/poet.tang.27000.json','["四面杉蘿合，空堂畫老仙。", "蠹根停雪水，曲角積茶煙。", "道至心機盡，宵晴瑟韻全。", "暫來還又去，未得坐經年。"]'),
('d7b265bf-08b8-4445-a38e-38fa83ef28dc','出關後寄賈島','周賀','唐','唐诗','tang','','[]','故國知何處，西風已度關。',48,'全唐诗/poet.tang.27000.json','["故國知何處，西風已度關。", "歸人值落葉，遠路入寒山。", "多難喜相識，久貧寧自閑。", "唯將往來信，遙慰別離顏。"]'),
('ce974b96-9cef-45a3-8b26-5b107a0ddef1','題晝公院','周賀','唐','唐诗','tang','','[]','叢木開風徑，過從白晝寒。',48,'全唐诗/poet.tang.27000.json','["叢木開風徑，過從白晝寒。", "舍深原草合，茶疾竹薪乾。", "夕雨生眠興，禪心少話端。", "頻來覺無事，盡日坐相看。"]'),
('f53482d3-a593-442d-8c08-53e8c50193b9','京口贈崔固','周賀','唐','唐诗','tang','','[]','積雨晴時近，西風葉滿泉。',48,'全唐诗/poet.tang.27000.json','["積雨晴時近，西風葉滿泉。", "相逢嵩嶽客，共聽楚城蟬。", "宿館橫秋島，歸帆漲遠田。", "別多還寂寞，不似剡中年。"]'),
('9ea6391f-f3a2-4996-82b4-b62ed3878707','書實上人房','周賀','唐','唐诗','tang','','[]','絕頂言無伴，長懷剃髮師。',48,'全唐诗/poet.tang.27000.json','["絕頂言無伴，長懷剃髮師。", "禪中燈落燼，講次栢生枝。", "沙井泉澄疾，秋鐘韻盡遲。", "里閭還受請，空有向南期。"]'),
('ccfdc487-6187-4e68-8daa-bfa80e78dae1','送張諲之睦州','周賀','唐','唐诗','tang','','[]','遙憶新安舊，扁舟往復還。',48,'全唐诗/poet.tang.27000.json','["遙憶新安舊，扁舟往復還。", "淺深看水石，來往逐雲山。", "到縣餘花在，過門五柳閑。", "東征隨子去，俱隱薜蘿間。"]'),
('ab987151-3ffa-4ded-bce7-3fb95f6d2112','贈王道士','周賀','唐','唐诗','tang','','[]','藥力資蒼鬢，應非舊日身。',48,'全唐诗/poet.tang.27000.json','["藥力資蒼鬢，應非舊日身。", "一爲嵩嶽客，幾葬洛陽人。", "石縫瓢探水，雲根斧斫薪。", "關西來往路，誰得水銀銀。"]'),
('51d625c5-dae5-4e22-9be9-352fd0c560f9','冬日山居思鄉','周賀','唐','唐诗','tang','','[]','大野始嚴凝，雲天曉色澄。',48,'全唐诗/poet.tang.27000.json','["大野始嚴凝，雲天曉色澄。", "樹寒稀宿鳥，山迥少來僧。", "背日收窗雪，開爐釋硯冰。", "忽然歸故國，孤想寓西陵。"]'),
('2301e72b-9242-4c23-bf20-28d240fa4e98','如空上人移居大雲寺','周賀','唐','唐诗','tang','','[]','竹溪人請住，何日向中峰。',48,'全唐诗/poet.tang.27000.json','["竹溪人請住，何日向中峰。", "瓦舍山情少，齋身疾色濃。", "夏高移坐次，菊淺露行蹤。", "來往湓城下，三年兩度逢。"]'),
('7aa4ba33-ae12-4c98-9b6f-0a84f4f21132','送幻羣法師','周賀','唐','唐诗','tang','','[]','北京一別後，吳楚幾聽砧。',48,'全唐诗/poet.tang.27000.json','["北京一別後，吳楚幾聽砧。", "住久白髮出，講長枯葉深。", "香連隣舍像，磬徹遠巢禽。", "寂默應關道，何人見此心。"]'),
('592b4682-b899-4587-9729-f198d92fb970','春喜友人至山舍','周賀','唐','唐诗','tang','','[]','鳥鳴春日曉，喜見竹門開。',48,'全唐诗/poet.tang.27000.json','["鳥鳴春日曉，喜見竹門開。", "路自高巖出，人騎大馬來。", "折花林影斷，移石洞陰迴。", "更欲留深語，重城暮色催。"]'),
('5d908b94-09d9-425e-990c-60e003c38963','春日重至南徐舊居','周賀','唐','唐诗','tang','','[]','綠水陰空院，春深喜再來。',48,'全唐诗/poet.tang.27000.json','["綠水陰空院，春深喜再來。", "獨眠從草長，留酒看花開。", "過雨遠山出，向風孤鳥迴。", "忽思秋夕事，雲物却悠哉。"]'),
('29a0be45-0689-464f-b3e9-bd70798e4ecf','早秋過郭涯書堂','周賀','唐','唐诗','tang','','[]','暑消岡舍清，閑語有餘情。',48,'全唐诗/poet.tang.27000.json','["暑消岡舍清，閑語有餘情。", "澗水生茶味，松風滅扇聲。", "遠分臨海雨，靜覺掩山城。", "此地秋吟苦，時來遶菊行。"]'),
('548eb482-c3e5-487f-8cdd-09058d6b03ee','長安送人','周賀','唐','唐诗','tang','','[]','上國多離別，年年渭水濱。',48,'全唐诗/poet.tang.27000.json','["上國多離別，年年渭水濱。", "空將未歸意，說向欲行人。", "鴈度池塘月，山連井邑春。", "臨岐惜分手，日暮一霑巾。"]'),
('eb64fcbb-bb3c-4d32-91da-3fcc4d3b4564','寄寧海李明府','周賀','唐','唐诗','tang','','[]','山縣風光異，公門水石清。',96,'全唐诗/poet.tang.27000.json','["山縣風光異，公門水石清。", "一官居外府，幾載別東京。", "故疾梅天發，新詩雪夜成。", "家貧思減選，時靜憶歸耕。", "把疏尋書義，澄心得獄情。", "夢靈邀客解，劒古揀人呈。", "守月通宵坐，尋花迥路行。", "從來愛知道，何慮白髭生。"]'),
('95c14014-8374-47ac-9e32-e308eee5e427','投江州張郎中','周賀','唐','唐诗','tang','','[]','要地無閑日，仍容冒謁頻。',96,'全唐诗/poet.tang.27000.json','["要地無閑日，仍容冒謁頻。", "借山年涉閏，寢郡月逾旬。", "驛徑曾衝雪，方泉省滌塵。", "隨行溪路細，接話草堂新。", "減藥痊餘癖，飛書苦問貧。", "噪蟬離宿殼，吟客寄秋身。", "鍊句貽箱篋，懸圖見蜀岷。", "使君匡嶽近，終作社中人。"]'),
('fdac2121-9469-4968-bad0-1e32389b7ae8','晚題江館','周賀','唐','唐诗','tang','','[]','病寄曲江居帶城，傍門孤柳一蟬鳴。',64,'全唐诗/poet.tang.27000.json','["病寄曲江居帶城，傍門孤柳一蟬鳴。", "澄波月上見魚擲，晚徑葉多聞犬行。", "越島夜無侵閣色，寺鐘涼有隔原聲。", "故園盡賣休官去，潮水秋來空自平。"]'),
('34f3ce94-52e8-41ab-8f75-1263baa3bb82','秋晚歸廬山留別道友','周賀','唐','唐诗','tang','','["\u5e90\u5c71"]','病起陵陽思翠微，秋風動後著行衣。',64,'全唐诗/poet.tang.27000.json','["病起陵陽思翠微，秋風動後著行衣。", "月生石齒人同見，霜落木梢愁獨歸。", "已許衲僧修靜社，便將樵叟對閑扉。", "不嫌舊隱相隨去，廬岳臨天好息機。"]'),
('bcf2e0b1-9cb0-4d31-b397-322340f0f60a','同徐處士秋懷少室舊居','周賀','唐','唐诗','tang','','["\u9ec4\u6cb3"]','曾居少室黃河畔，秋夢長懸未得回。',64,'全唐诗/poet.tang.27000.json','["曾居少室黃河畔，秋夢長懸未得回。", "扶病半年離水石，思歸一夜隔風雷。", "荒齋幾遇僧眠後，晚菊頻經鹿踏來。", "燈下此心誰共說，傍松幽徑已多栽。"]'),
('d596cf07-c733-4267-9f3f-d392c7cc214d','贈神遘上人','周賀','唐','唐诗','tang','','[]','草履蒲團山意存，坐看庭木長桐孫。',64,'全唐诗/poet.tang.27000.json','["草履蒲團山意存，坐看庭木長桐孫。", "行齋罷講仍香氣，布褐離牀帶雨痕。", "夏滿尋醫還出寺，晴來曬疏暫開門。", "道情淡薄閑愁盡，霜色何因入鬢根。"]'),
('6d57d65f-37ee-4a44-aa47-e6ce570ed99d','贈道人','周賀','唐','唐诗','tang','','[]','布褐高眠石竇春，迸泉多濺黑紗巾。',64,'全唐诗/poet.tang.27000.json','["布褐高眠石竇春，迸泉多濺黑紗巾。", "搖頭說易當朝客，落手圍碁對俗人。", "自筭天年窮甲子，誰同雨夜守庚申。", "擬歸太華何時去，他日相尋乞藥銀。"]'),
('26733326-42b3-4fec-bb4f-8fc88963d1f7','贈厲玄侍御','周賀','唐','唐诗','tang','','[]','山松徑與瀑泉通，巾舃行吟想越中。',64,'全唐诗/poet.tang.27000.json','["山松徑與瀑泉通，巾舃行吟想越中。", "塞鴈去經華頂末，鄉僧來自海濤東。", "關分河漢秋鐘絕，露滴獮猴夜嶽空。", "抱疾因尋周柱史，杜陵寒葉落無窮。"]'),
('653b3c13-bbf1-4587-83b4-0289a79b55a5','送韓評事','周賀','唐','唐诗','tang','','[]','門枕平湖秋景好，水煙松色遠相依。',64,'全唐诗/poet.tang.27000.json','["門枕平湖秋景好，水煙松色遠相依。", "罷官餘俸租田種，送客回舟載石歸。", "離岸遊魚逢浪返，望巢寒鳥逆風飛。", "嵩陽舊隱多時別，閉目閑吟憶翠微。"]'),
('caacfb48-8635-403e-a1cc-f44c6cf6e0f1','宿隱靜寺上人','周賀','唐','唐诗','tang','','[]','一宿五峰杯度寺，虛廊中夜磬聲分。',64,'全唐诗/poet.tang.27000.json','["一宿五峰杯度寺，虛廊中夜磬聲分。", "疎林未落上方月，深澗忽生平地雲。", "幽鳥背泉棲靜境，遠人當燭想遺文。", "暫來此地歇勞足，望斷故山滄海濆。"]'),
('77e75eda-6c4b-40e6-8ea7-f958cbaf5cac','寄新頭陀','周賀','唐','唐诗','tang','','[]','見說北京尋祖後，瓶盂自挈遶窮邊。',64,'全唐诗/poet.tang.27000.json','["見說北京尋祖後，瓶盂自挈遶窮邊。", "相逢竹塢晦暝夜，一別苕溪多少年。", "遠洞省穿湖底過，斷崖曾向壁中禪。", "青城不得師同住，坐想滄江憶浩然。"]'),
('0fa97983-b8dc-4bd5-9c81-663ef1d1a713','湘漢旅懷翁傑','周賀','唐','唐诗','tang','','[]','一宿空江聽急流，仍同賈客坐歸舟。',63,'全唐诗/poet.tang.27000.json','["一宿空江聽急流，仍同賈客坐歸舟。", "遠書來隔巴陵雨，衰鬢去經彭蠡秋。", "不擬爲身謀舊業，終期斷穀隱高丘。", "吾宗尚無憀者，中夜閑吟生旅愁。"]'),
('efa256af-569f-4b3a-ab60-766a5292beeb','寄韓司兵','周賀','唐','唐诗','tang','','[]','多病十年無舊識，滄州亂後只逢君。',64,'全唐诗/poet.tang.27000.json','["多病十年無舊識，滄州亂後只逢君。", "已知罷秩辭瀧水，相勸移家近岳雲。", "泗上旅帆侵疊浪，雪中歸路踏荒墳。", "若爲此別終期老，書札何因寄北軍。"]'),
('7c97f06e-5559-41e7-a21a-9d672ff5e066','寺居寄楊侍御','周賀','唐','唐诗','tang','','[]','雨過北林空晚涼，院閑人去掩斜陽。',64,'全唐诗/poet.tang.27000.json','["雨過北林空晚涼，院閑人去掩斜陽。", "十年多病度落葉，萬里亂愁生夜牀。", "終欲返耕甘性拙，久慚他事與身忙。", "還知謝客名先重，肯爲詩篇問楚狂。"]'),
('5575be1b-3356-4fd7-bbba-9aec230c3f56','上陝府姚中丞','周賀','唐','唐诗','tang','','[]','此心長愛狎禽魚，仍候登封獨著書。',64,'全唐诗/poet.tang.27000.json','["此心長愛狎禽魚，仍候登封獨著書。", "領郡只嫌生藥少，在官長恨與山疎。", "成家盡是經綸後，得句應多諫諍餘。", "見說養真求退靜，溪南泉石許同居。"]'),
('ac16ead9-601b-49ab-8274-4f03ce263a24','贈僧','周賀','唐','唐诗','tang','','[]','藩府十年爲律業，南朝本寺往來新。',64,'全唐诗/poet.tang.27000.json','["藩府十年爲律業，南朝本寺往來新。", "辭歸幾別深山客，赴請多從遠處人。", "松吹入堂資講力，野蔬供飯爽禪身。", "他年更息登壇計，應與雲泉作四鄰。"]'),
('394efaa6-9d7f-4b15-a737-384be65d82ff','送石協律歸吳','周賀','唐','唐诗','tang','','[]','僧窗夢後憶歸耕，水涉應多半月程。',64,'全唐诗/poet.tang.27000.json','["僧窗夢後憶歸耕，水涉應多半月程。", "幕府罷來無藥價，紗巾帶去有山情。", "夜隨淨渚離蛩語，早過寒潮背井行。", "已讓辟書稱抱疾，滄洲便許白髭生。"]'),
('497e85ba-f23e-4f59-b17c-b3aaca697e2f','寄金陵僧','周賀','唐','唐诗','tang','','[]','水石致身閑自得，平雲竹閣少炎蒸。',64,'全唐诗/poet.tang.27000.json','["水石致身閑自得，平雲竹閣少炎蒸。", "齋牀幾減供禽食，禪徑寒通照像燈。", "覓句當秋山落葉，臨書近臘硯生冰。", "行登總到諸山寺，坐聽蟬聲滿四稜。"]'),
('8e0e1ef9-208b-43b6-bad8-44ae823f877b','送忍禪師歸廬嶽','周賀','唐','唐诗','tang','','[]','浪匝湓城岳壁青，白頭僧去掃禪扃。',64,'全唐诗/poet.tang.27000.json','["浪匝湓城岳壁青，白頭僧去掃禪扃。", "龕燈度雪補殘衲，山日上軒看舊經。", "泉水帶冰寒溜澀，薜蘿新雨曙煙腥。", "已知身事非吾道，甘臥荒齋竹滿庭。"]'),
('a0b894b2-fcc9-43ad-bd49-ba393929bebb','贈姚合郎中','周賀','唐','唐诗','tang','','[]','望重來爲守土臣，清高還似武功貧。',64,'全唐诗/poet.tang.27000.json','["望重來爲守土臣，清高還似武功貧。", "道從會解唯求靜，時造玄微不趁新。", "玉帛已知難撓思，雲泉終是得閑身。", "兩衙向後長無事，門館多逢請益人。"]'),
('3a0298a2-bfcb-4e19-a69f-ab601f1a87fa','宿李主簿','周賀','唐','唐诗','tang','','[]','獨樹倚亭新月入，城牆四面鏁山多。',32,'全唐诗/poet.tang.27000.json','["獨樹倚亭新月入，城牆四面鏁山多。", "去年今夜還來此，坐見西風褭鵲窠。"]'),
('4a441d17-7596-4d0f-9f8c-7c74d6e35b43','寄潘緯','周賀','唐','唐诗','tang','','[]','楊柳垂絲與地連，歸來一醉向溪邊。',32,'全唐诗/poet.tang.27000.json','["楊柳垂絲與地連，歸來一醉向溪邊。", "相逢頭白莫惆悵，世上無人長少年。"]'),
('c331c785-4c69-4acc-ab99-085eee0d185a','潯陽與孫郎中宴迴','周賀','唐','唐诗','tang','','[]','別酒已酣春漏前，他人扶上北歸船。',32,'全唐诗/poet.tang.27000.json','["別酒已酣春漏前，他人扶上北歸船。", "潯陽渡口月未上，漁火照江仍獨眠。"]'),
('89222eca-e91b-4824-a733-bad20771160e','送宗禪師','周賀','唐','唐诗','tang','','[]','衡陽到却十三春，行脚同來有幾人。',32,'全唐诗/poet.tang.27000.json','["衡陽到却十三春，行脚同來有幾人。", "老大又思歸嶽裏，當時來漆祖師身。"]'),
('0740a684-6283-46b3-abcf-15af27b632dd','送僧','周賀','唐','唐诗','tang','','[]','草履初登南客船，銅瓶猶貯北山泉。',32,'全唐诗/poet.tang.27000.json','["草履初登南客船，銅瓶猶貯北山泉。", "衡陽舊寺秋歸去，門鏁寒潭幾樹蟬。"]'),
('0263907d-2423-4b92-bb24-71241f95e7b6','送蜀僧','周賀','唐','唐诗','tang','','[]','萬里獨行無弟子，惟齎筇竹與檀龕。',32,'全唐诗/poet.tang.27000.json','["萬里獨行無弟子，惟齎筇竹與檀龕。", "看經更向吳中老，應是山川似劒南。"]'),
('8a4a6d8c-9e4a-4f8f-b740-5d7d9f66086e','過僧竹院','周賀','唐','唐诗','tang','','[]','一生愛竹自未有，每到此房歸不能。',32,'全唐诗/poet.tang.27000.json','["一生愛竹自未有，每到此房歸不能。", "高人留宿話禪後，寂寞雨堂空夜燈。"]'),
('5926f41c-dd7c-491f-a77d-233ac67fe267','憶潯陽舊居兼感長孫郎中','周賀','唐','唐诗','tang','','[]','潯陽却到是何日，此地今無舊使君。',32,'全唐诗/poet.tang.27000.json','["潯陽却到是何日，此地今無舊使君。", "長憶窮冬宿廬嶽，瀑泉冰折共僧聞。"]'),
('50f9fe64-24af-48d5-9f06-24132b883a0c','送郭秀才歸金陵','周賀','唐','唐诗','tang','','[]','夏後客堂黃葉多，又懷家國起悲歌。',64,'全唐诗/poet.tang.27000.json','["夏後客堂黃葉多，又懷家國起悲歌。", "酒前欲別語難盡，雲際相思心若何。", "鳥下獨山秋寺磬，人隨大舸晚江波。", "南徐舊業幾時到，門掩殘陽積翠蘿。"]'),
('d33076eb-855f-4d40-a8f6-096e374d9cf2','宿李樞書齋','周賀','唐','唐诗','tang','','[]','小齋經暮雨，四面絕纖埃。',48,'全唐诗/poet.tang.27000.json','["小齋經暮雨，四面絕纖埃。", "眠客聞風覺，飛蟲入燭來。", "夜涼書讀遍，月正戶全開。", "住遠稀相見，留連宿始迴。"]'),
('5f5be72b-2b67-4d8a-8c1f-c7fb42368967','杪秋登江樓','周賀','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','平楚起寒色，長沙猶未還。',48,'全唐诗/poet.tang.27000.json','["平楚起寒色，長沙猶未還。", "世情何處淡，湘水向人閑。", "空翠隱高鳥，夕陽歸遠山。", "孤雲萬餘里，惆悵洞庭間。"]'),
('ecd8f105-6939-4cea-ac3b-a29bd3150410','秋宿洞庭','周賀','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭初葉下，旅客不勝愁。',48,'全唐诗/poet.tang.27000.json','["洞庭初葉下，旅客不勝愁。", "明月天涯夜，青山江上秋。", "一官成白首，萬里寄滄洲。", "只被浮名繫，寧無媿海鷗。"]'),
('c4000dc0-54b8-4484-b96c-a5fd282abe68','重陽','周賀','唐','唐诗','tang','','[]','雲木疎黃秋滿川，茱萸風裏一樽前。',64,'全唐诗/poet.tang.27000.json','["雲木疎黃秋滿川，茱萸風裏一樽前。", "幾回爲客逢佳節，曾見何人再少年。", "霜報征衣冷針指，鴈驚幽隱泣雲泉。", "古來醉樂皆難得，留取窮通委上天。"]'),
('154611b9-c5e6-4b80-9d39-70fd961b1bf1','送李億東歸','周賀','唐','唐诗','tang','','["\u9ec4\u5c71"]','黃山遠隔秦樹，紫禁斜通渭城。',56,'全唐诗/poet.tang.27000.json','["黃山遠隔秦樹，紫禁斜通渭城。", "別路青青柳發，前溪漠漠花生。", "和風澹蕩歸客，落日殷勤早鶯。", "灞上金樽未飲，讌歌已有餘聲。"]'),
('4607534c-82c7-4881-899f-2aa59c6bb1fa','泊靈溪館','鄭巢','唐','唐诗','tang','','[]','孤吟疎雨絕，荒館亂峰前。',48,'全唐诗/poet.tang.27000.json','["孤吟疎雨絕，荒館亂峰前。", "曉鷺棲危石，秋萍滿敗船。", "溜從華頂落，樹與赤城連。", "已有求閑意，相期在暮年。"]'),
('c824482e-922d-4bcd-9a6c-63b21b20b56d','瀑布寺貞上人院','鄭巢','唐','唐诗','tang','','["\u534e\u5c71"]','林疎多暮蟬，師去宿山煙。',48,'全唐诗/poet.tang.27000.json','["林疎多暮蟬，師去宿山煙。", "古壁燈熏畫，秋琴雨潤弦。", "竹間窺遠鶴，巖上取寒泉。", "西嶽沙房在，歸期更幾年。"]'),
('88907e5e-ca2d-45e2-81a6-ffd06501739e','寄貞法師','鄭巢','唐','唐诗','tang','','[]','巡禮知難盡，幽人見亦稀。',48,'全唐诗/poet.tang.27000.json','["巡禮知難盡，幽人見亦稀。", "幾年潭上過，何待雪中歸。", "遠瀑穿經室，寒螿發定衣。", "無因尋道者，獨坐對松扉。"]'),
('636035b9-8dd9-47e1-83de-ea40e619eabc','送靈溪李侍郎','鄭巢','唐','唐诗','tang','','[]','貂裘離闕下，初佐漢元勳。',48,'全唐诗/poet.tang.27000.json','["貂裘離闕下，初佐漢元勳。", "河偃流澌疊，沙晴遠樹分。", "牛羊下暮靄，鼓角調寒雲。", "中夕蕭關宿，邊聲不可聞。"]'),
('f0560448-7b57-45be-92bd-fb428fc5bc64','送姚郎中罷郡遊越','鄭巢','唐','唐诗','tang','','[]','逍遙方罷郡，高興接東甌。',48,'全唐诗/poet.tang.27000.json','["逍遙方罷郡，高興接東甌。", "幾處行杉逕，何時宿石樓。", "湘聲穿古竇，華影在空舟。", "惆悵雲門路，無因得從遊。"]'),
('c027bdc0-1301-446e-b15c-3068b1a55e54','送魏校書赴夏口從事','鄭巢','唐','唐诗','tang','','[]','西風吹遠蟬，驛路在雲邊。',48,'全唐诗/poet.tang.27000.json','["西風吹遠蟬，驛路在雲邊。", "獨夢諸山外，高談大斾前。", "夜燈分楚塞，秋角滿湘船。", "郡邑多巖竇，何方便學仙。"]'),
('91f3a9f8-580f-41d8-b203-a68efa949436','送衡州薛從事','鄭巢','唐','唐诗','tang','','[]','吟去望雙旌，滄洲晚氣清。',48,'全唐诗/poet.tang.27000.json','["吟去望雙旌，滄洲晚氣清。", "遙分高岳色，亂出遠蟬聲。", "楚霽雲連寺，湘寒浪浸城。", "孤猨不可聽，一聽白髭生。"]'),
('19a94bc6-e084-4a96-9723-73e4813fbca3','送邊使','鄭巢','唐','唐诗','tang','','[]','關河度幾重，邊色上離容。',48,'全唐诗/poet.tang.27000.json','["關河度幾重，邊色上離容。", "灞水方爲別，沙場又入冬。", "曙鵰迴大旆，夕雪沒前峰。", "漢使多長策，須令遠國從。"]'),
('77a60918-aade-46c7-92f5-744c1f6d025c','送人赴舉','鄭巢','唐','唐诗','tang','','[]','篇章動玉京，墜葉滿前程。',48,'全唐诗/poet.tang.27000.json','["篇章動玉京，墜葉滿前程。", "舊國與僧別，秋江罷釣行。", "馬過隋代寺，檣出楚山城。", "應近嵩陽宿，潛聞瀑布聲。"]'),
('c88acbf1-27ff-4b73-9b96-834017a50722','送袁肇歸山陰','鄭巢','唐','唐诗','tang','','[]','論文意有違，寒雨灑行衣。',48,'全唐诗/poet.tang.27000.json','["論文意有違，寒雨灑行衣。", "南渡久誰語，後吟今獨歸。", "河帆因樹落，沙鳥背潮飛。", "若值雲門侶，多因宿翠微。"]'),
('ac1b01a1-c506-4cc2-ae46-4f47b7969c10','送李式','鄭巢','唐','唐诗','tang','','[]','瀟湘路杳然，清興起秋前。',48,'全唐诗/poet.tang.27000.json','["瀟湘路杳然，清興起秋前。", "去寺多隨磬，看山半在船。", "綠雲天外鶴，紅樹雨中蟬。", "莫使游華頂，逍遙更過年。"]'),
('913d4e73-71c6-404a-bcac-7dd25ca39344','送韋弇','鄭巢','唐','唐诗','tang','','[]','挂席曙鍾初，家山半在吳。',48,'全唐诗/poet.tang.27000.json','["挂席曙鍾初，家山半在吳。", "艣聲過遠寺，江色潤秋蕪。", "陂鶴巢城木，邊鴻宿岸蘆。", "知君當永夜，獨釣五湖隅。"]'),
('3ed2ae7b-9375-4b51-b594-de221820d73c','送人南游','鄭巢','唐','唐诗','tang','','[]','南京路悄然，欹石漱流泉。',48,'全唐诗/poet.tang.27000.json','["南京路悄然，欹石漱流泉。", "遠寺寒雲外，揚帆暑雨前。", "鴈行迴曉岫，蜃色上湖田。", "更想清吟處，多同隱者眠。"]'),
('ebd1b499-cda5-4f81-9bcb-8ca5830f92be','送省空上人歸南嶽','鄭巢','唐','唐诗','tang','','["\u8861\u5c71"]','又歸衡嶽寺，舊院樹冥冥。',48,'全唐诗/poet.tang.27000.json','["又歸衡嶽寺，舊院樹冥冥。", "坐石逢寒衲，尋龕補壞經。", "嶠雲籠曙磬，潭草落秋萍。", "誰伴高牕宿，禪衣挂桂馨。"]'),
('6fde0765-5dc1-4b36-9d4f-3aa5fac04b91','送象上人還山中','鄭巢','唐','唐诗','tang','','[]','竹錫與袈裟，靈山笑暗霞。',48,'全唐诗/poet.tang.27000.json','["竹錫與袈裟，靈山笑暗霞。", "泉痕生淨蘚，燒力落寒花。", "高戶閑聽雪，空窗靜擣茶。", "終期宿華頂，須會說三巴。"]'),
('0c834404-dc6b-4a8f-b7e8-a68f21e71c13','送僧歸富春','鄭巢','唐','唐诗','tang','','[]','憶過僧禪處，遙山抱竹門。',48,'全唐诗/poet.tang.27000.json','["憶過僧禪處，遙山抱竹門。", "古房關蘚色，秋徑掃潮痕。", "石淨聞泉落，沙寒見鶴翻。", "終當從此望，更與道人言。"]'),
('f3ebc174-4549-451d-993d-c45e4c4b4a25','送琇上人','鄭巢','唐','唐诗','tang','','[]','古殿焚香外，清羸坐石稜。',48,'全唐诗/poet.tang.27000.json','["古殿焚香外，清羸坐石稜。", "茶煙開瓦雪，鶴跡上潭冰。", "孤磬侵雲動，靈山隔水登。", "白雲歸意遠，舊寺在廬陵。"]'),
('975048b2-5ad0-47ad-86d8-438701a6e1df','哭虛海上人','鄭巢','唐','唐诗','tang','','[]','一化西風外，禪流稍稍分。',48,'全唐诗/poet.tang.27000.json','["一化西風外，禪流稍稍分。", "買碑行暮雨，斲石葬寒雲。", "靜戶關松色，荒齋聚鳥羣。", "朗吟聲不倦，高傳有遺文。"]'),
('e9dabd33-793a-4d65-a47a-e23834611b06','和姚郎中題凝公院','鄭巢','唐','唐诗','tang','','[]','後房寒竹連，白晝坐冥然。',48,'全唐诗/poet.tang.27000.json','["後房寒竹連，白晝坐冥然。", "片衲何山至，空堂幾夜禪。", "葉侵經上字，冰結硯中泉。", "雪夕誰同話，懸燈古像前。"]'),
('4fa17386-ad44-4005-a191-619b05f046a8','贈丘先生','鄭巢','唐','唐诗','tang','','[]','雲泉心不爽，垂日坐柴關。',48,'全唐诗/poet.tang.27000.json','["雲泉心不爽，垂日坐柴關。", "硯取簷前雨，圖開異國山。", "原僧招過宿，沙鳥伴長閑。", "地與中峰近，殘陽獨不還。"]'),
('0b3d8fac-be01-4b3f-899b-d5e549ddeff7','贈蠻僧','鄭巢','唐','唐诗','tang','','[]','南海何年過，中林一磬微。',48,'全唐诗/poet.tang.27000.json','["南海何年過，中林一磬微。", "病逢秋雨發，心逐暮潮歸。", "久臥前山寺，猶逢故國衣。", "近來慵步履，石蘚滿柴扉。"]'),
('901d23e1-9d34-4af2-b348-321909e6e87b','秋思','鄭巢','唐','唐诗','tang','','[]','寒蛩鳴不定，郭外水雲幽。',48,'全唐诗/poet.tang.27000.json','["寒蛩鳴不定，郭外水雲幽。", "南浦鴈來日，北窗人臥秋。", "病身多在遠，生計少於愁。", "薄暮西風急，清碪響未休。"]'),
('7c044c69-df54-43e1-b658-bdc6abee553a','楚城秋夕','鄭巢','唐','唐诗','tang','','[]','故苑多愁夕，西風木葉黃。',48,'全唐诗/poet.tang.27000.json','["故苑多愁夕，西風木葉黃。", "寒江浸霧月，曉角滿城霜。", "弟姪來書少，關河去路長。", "幾時停桂檝，故國隔瀟湘。"]'),
('5a871c36-d297-49c1-bdc2-2ffc13dcb908','秋日陪姚郎中登郡中南亭','鄭巢','唐','唐诗','tang','','[]','雲水生寒色，高亭發遠心。',48,'全唐诗/poet.tang.27000.json','["雲水生寒色，高亭發遠心。", "鴈來疎角韻，槐落減秋陰。", "隔石嘗茶坐，當山抱瑟吟。", "誰知瀟灑意，不似有朝簪。"]'),
('18b5078d-50e6-4e82-b53b-974d82425dd3','宿天竺寺','鄭巢','唐','唐诗','tang','','[]','暮過潭上寺，獨宿白雲間。',48,'全唐诗/poet.tang.27000.json','["暮過潭上寺，獨宿白雲間。", "鐘磬遙連樹，星河半隔山。", "石中泉暗落，松外戶初關。", "却憶終南裏，前秋此夕還。"]'),
('b5170187-ece8-4487-ac52-4ab5f3c86dee','陳氏園林','鄭巢','唐','唐诗','tang','','[]','當門三四峰，高興幾人同。',48,'全唐诗/poet.tang.27000.json','["當門三四峰，高興幾人同。", "尋鶴新泉外，留僧古木中。", "蟬鳴槐葉雨，魚散芰荷風。", "多喜陪幽賞，清吟繞石叢。"]'),
('0e49d201-5ab5-4757-bb16-2b25759f10b6','題崔中丞北齋','鄭巢','唐','唐诗','tang','','[]','湖近草侵庭，秋來道興生。',48,'全唐诗/poet.tang.27000.json','["湖近草侵庭，秋來道興生。", "寒潮添井味，遠漏帶松聲。", "放卷聽泉坐，尋僧踏雪行。", "何年各無事，高論宿青城。"]'),
('ec253744-021e-43e0-b260-280df8114625','題崔行先石室別墅','鄭巢','唐','唐诗','tang','','[]','山空水繞籬，幾日此棲遲。',48,'全唐诗/poet.tang.27000.json','["山空水繞籬，幾日此棲遲。", "採菊頻秋醉，留僧擬夜棊。", "桂陰生野菌，石縫結寒澌。", "更喜連幽洞，唯君與我知。"]'),
('b410891a-c820-4ee9-a30d-fc39e319df8d','題靈隱寺皖公院','鄭巢','唐','唐诗','tang','','[]','山寒葉滿衣，孤鶴偶清羸。',48,'全唐诗/poet.tang.27000.json','["山寒葉滿衣，孤鶴偶清羸。", "已在雲房老，休爲內殿期。", "嵐昏聲磬早，菓熟喚猨遲。", "未得終高論，明朝更別離。"]'),
('5b54fcfa-c609-47fe-a9f7-e33006c5dae8','題寺壁二首 一','呂羣','唐','唐诗','tang','','[]','路行三蜀盡，身及一陽生。',24,'全唐诗/poet.tang.27000.json','["路行三蜀盡，身及一陽生。", "賴有殘燈火，相依坐到明。"]'),
('54408778-51d3-4bea-8a7f-c2f9b05876c8','題寺壁二首 二','呂羣','唐','唐诗','tang','','[]','社後辭巢燕，霜前別蔕蓬。',24,'全唐诗/poet.tang.27000.json','["社後辭巢燕，霜前別蔕蓬。", "願爲蝴蝶夢，飛去覓關中。"]'),
('a0472daf-8392-431d-a542-f93ed8faf1c8','黃蜀葵','崔涯','唐','唐诗','tang','','[]','野欄秋景晚，疎散兩三枝。',48,'全唐诗/poet.tang.27000.json','["野欄秋景晚，疎散兩三枝。", "嫩碧淺輕態，幽香閑澹姿。", "露傾金盞小，風引道冠欹。", "獨立悄無語，清愁人詎知。"]'),
('cc9067e8-5143-42dd-9f85-fa1aaa2e4a04','詠春風','崔涯','唐','唐诗','tang','','[]','動地經天物不傷，高情逸韻住何方。',64,'全唐诗/poet.tang.27000.json','["動地經天物不傷，高情逸韻住何方。", "扶持燕雀連天去，斷送楊花盡日狂。", "遶桂月明過萬戶，弄帆晴晚渡三湘。", "孤雲雖是無心物，借便吹教到帝鄉。"]'),
('4e7818af-b432-424d-b011-21180f6e9053','竹','崔涯','唐','唐诗','tang','','[]','領得溪風不放迴，傍窗緣砌遍庭栽。',64,'全唐诗/poet.tang.27000.json','["領得溪風不放迴，傍窗緣砌遍庭栽。", "須招野客爲鄰住，看引山禽入郭來。", "幽院獨驚秋氣早，小門深向綠陰開。", "誰憐翠色兼寒影，靜落茶甌與酒杯。"]'),
('ad9bce2d-64ed-4195-8c28-a6172f42d37b','俠士詩','崔涯','唐','唐诗','tang','','[]','太行嶺上二尺雪，崔涯袖中三尺鐵。',32,'全唐诗/poet.tang.27000.json','["太行嶺上二尺雪，崔涯袖中三尺鐵。", "一朝若遇有心人，出門便與妻兒別。"]'),
('ba8ec97e-672f-4f3d-acd9-7af5140ae5e8','別妻','崔涯','唐','唐诗','tang','','[]','隴上泉流隴下分，斷腸嗚咽不堪聞。',32,'全唐诗/poet.tang.27000.json','["隴上泉流隴下分，斷腸嗚咽不堪聞。", "嫦娥一入月中去，巫峽千秋空白雲。"]'),
('b3869955-7214-4042-942d-a22afb8575eb','雜嘲二首 一','崔涯','唐','唐诗','tang','','[]','二年不到宋家東，阿母深居僻巷中。',32,'全唐诗/poet.tang.27000.json','["二年不到宋家東，阿母深居僻巷中。", "含淚向人羞不語，琵琶弦斷倚屏風。"]'),
('4f5b577e-df4e-4e09-97c0-fa8f6dfb40e2','雜嘲二首 二','崔涯','唐','唐诗','tang','','[]','日暮迎來香閤中，百年心事一宵同。',32,'全唐诗/poet.tang.27000.json','["日暮迎來香閤中，百年心事一宵同。", "寒雞鼓翼紗窗外，已覺恩情逐曉風。"]'),
('f4c17816-ff4a-4a3d-aa15-c8586f152873','悼妓','崔涯','唐','唐诗','tang','','[]','赤板橋西小竹籬，槿花還似去年時。',32,'全唐诗/poet.tang.27000.json','["赤板橋西小竹籬，槿花還似去年時。", "淡黃衫子渾無色，腸斷丁香畫雀兒。"]'),
('ba01a06a-d48f-4b98-bdc7-ffb5dd200438','自蘇州至望亭驛有作','郭良驥','唐','唐诗','tang','','[]','南浦菰蒲遶白蘋，東吳黎庶逐黃巾。',64,'全唐诗/poet.tang.27000.json','["南浦菰蒲遶白蘋，東吳黎庶逐黃巾。", "野棠自發空流水，江燕初歸不見人。", "遠岫依依如送客，平田渺渺獨傷春。", "那堪迴首長洲苑，烽火年年報虜塵。"]'),
('42c78cd9-8015-42f0-bb10-3dc90d735c25','鄴中行','郭良驥','唐','唐诗','tang','','[]','年去年來秋更春，魏家園廟已成塵。',32,'全唐诗/poet.tang.27000.json','["年去年來秋更春，魏家園廟已成塵。", "只今惟有西陵在，無復當時歌舞人。"]'),
('03043ea8-3d75-4451-9eab-ef34060ae2c9','公無渡河','王叡','唐','唐诗','tang','','[]','濁波洋洋兮凝曉霧，公無渡河兮公竟渡。',104,'全唐诗/poet.tang.27000.json','["濁波洋洋兮凝曉霧，公無渡河兮公竟渡。", "風號水激兮呼不聞，提壺看入兮中流去。", "浪擺衣裳兮隨步沒，沈屍深入兮蛟螭窟。", "蛟螭盡醉兮君血乾，推出黃沙兮泛君骨。", "當時君死妾何適，遂就波濤合魂魄。", "願持精衛銜石心，窮取河源塞泉脈。"]'),
('c1b4343c-4690-4147-ac48-5f0fb25b63de','松','王叡','唐','唐诗','tang','','[]','寒松聳拔倚蒼岑，綠葉扶疎自結陰。',64,'全唐诗/poet.tang.27000.json','["寒松聳拔倚蒼岑，綠葉扶疎自結陰。", "丁固夢時還有意，秦王封日豈無心。", "常將正節栖孤鶴，不遣高枝宿衆禽。", "好是特凋羣木後，護霜凌雪翠踰深。"]'),
('604b5022-fddd-442a-ba42-338bc4a9f0fb','竹','王叡','唐','唐诗','tang','','[]','庭竹森疎玉質寒，色包葱碧盡琅玕。',64,'全唐诗/poet.tang.27000.json','["庭竹森疎玉質寒，色包葱碧盡琅玕。", "翠筠不樂湘娥淚，斑籜堪裁漢主冠。", "成韻含風已蕭瑟，媚漣凝淥更檀欒。", "此君引鳳爲龍日，聳節稍雲直上看。"]'),
('36542c56-af0e-45a1-b3fa-01af82e901fc','解昭君怨','王叡','唐','唐诗','tang','','[]','莫怨工人醜畫身，莫嫌明主遣和親。',32,'全唐诗/poet.tang.27000.json','["莫怨工人醜畫身，莫嫌明主遣和親。", "當時若不嫁胡虜，秖是宮中一舞人。"]'),
('321b86b6-e0fe-4318-8502-3e731ecc21a6','祠漁山神女歌二首 一','王叡','唐','唐诗','tang','','[]','蓪草頭花椰葉裙，蒲葵樹下舞蠻雲。',32,'全唐诗/poet.tang.27000.json','["蓪草頭花椰葉裙，蒲葵樹下舞蠻雲。", "引領望江遙滴酒，白蘋風起水生文。"]'),
('1db13417-532d-4ee6-a1a2-a4457df8def1','祠漁山神女歌二首 二','王叡','唐','唐诗','tang','','[]','棖棖山響荅琵琶，酒濕青莎肉飼鴉。',32,'全唐诗/poet.tang.27000.json','["棖棖山響荅琵琶，酒濕青莎肉飼鴉。", "樹葉無聲神去後，紙錢灰出木綿花。"]'),
('b1688782-fd43-4347-be3b-54ccc09506fd','牡丹','王叡','唐','唐诗','tang','','[]','牡丹妖豔亂人心，一國如狂不惜金。',32,'全唐诗/poet.tang.27000.json','["牡丹妖豔亂人心，一國如狂不惜金。", "曷若東園桃與李，果成無語自成陰。"]'),
('45f4eabc-90bd-4ca3-9d19-c5251268b4b4','秋','王叡','唐','唐诗','tang','','[]','蟬噪古槐疏葉下，樹銜斜日映孤城。',32,'全唐诗/poet.tang.27000.json','["蟬噪古槐疏葉下，樹銜斜日映孤城。", "欲知潘鬢愁多少，一夜新添白數莖。"]'),
('54e334c1-d69e-4694-ad16-c3559d79c8fc','燕','王叡','唐','唐诗','tang','','[]','海燕雙飛意若何，曲梁嘔嘎語聲多。',32,'全唐诗/poet.tang.27000.json','["海燕雙飛意若何，曲梁嘔嘎語聲多。", "茅檐不必嫌卑陋，猶勝吳宮爇爾窠。"]'),
('9cf034e0-0f59-4233-9f0a-ab6844824707','白雲向空盡','焦郁','唐','唐诗','tang','','[]','白雲昇遠岫，搖曳入晴空。',72,'全唐诗/poet.tang.27000.json','["白雲昇遠岫，搖曳入晴空。", "乘化隨舒卷，無心任始終。", "欲銷仍帶日，將斷更因風。", "勢薄飛難定，天高色易窮。", "影收元氣表，光滅太虛中。", "儻若從龍去，還施濟物功。"]'),
('31feea38-3bc0-49d6-9010-16d2d2033c3e','春雪 一','焦郁','唐','唐诗','tang','','[]','散漫天涯色，乘春四望平。',72,'全唐诗/poet.tang.27000.json','["散漫天涯色，乘春四望平。", "不分殘照影，何處斷鴻聲。", "繚繞先經塞，霏微近過城。", "因風低未歛，帶雨重還輕。", "干呂知時泰，如膏候歲成。", "小儒同品物，無以荅皇明。"]'),
('4a3075a1-3a6d-46c9-802c-00e84fcd3ea8','春雪 二','焦郁','唐','唐诗','tang','','[]','春雪空濛簾外斜，霏微半入野人家。',32,'全唐诗/poet.tang.27000.json','["春雪空濛簾外斜，霏微半入野人家。", "長天遠樹山山白，不辨梅花與柳花。"]'),
('4c3d2d11-ba89-4153-95d0-454d492f27d6','贈去婢','崔郊','唐','唐诗','tang','','["\u7231\u60c5", "\u60b2\u5267"]','公子王孫逐後塵，綠珠垂淚滴羅巾。',32,'全唐诗/poet.tang.27000.json','["公子王孫逐後塵，綠珠垂淚滴羅巾。", "侯門一入深如海，從此蕭郎是路人。"]'),
('322b43ce-1f68-428b-bd27-9172128d546b','江西投謁所知爲典客所阻因賦','劉魯風','唐','唐诗','tang','','[]','萬卷書生劉魯風，煙波萬里謁文翁。',32,'全唐诗/poet.tang.27000.json','["萬卷書生劉魯風，煙波萬里謁文翁。", "無錢豈與韓知客，名紙毛生不肯通。"]'),
('ef14214c-fb44-4a51-af81-40e433d48805','玉清行','柳泌','唐','唐诗','tang','','[]','遙遙寒冬時，蕭蕭躡太無。',192,'全唐诗/poet.tang.27000.json','["遙遙寒冬時，蕭蕭躡太無。", "仰望蘂宮殿，橫天臨不虛。", "下看白日流，上造真皇居。", "西牖日門開，南衢星宿疎。", "王母來瑤池，慶雲擁瓊轝。", "嵬峩丹鳳冠，搖曳紫霞裾。", "照徹聖姿嚴，飄颻神步徐。", "仙郎執玉節，侍女捧金書。", "靈香散彩煙，北闕路軿闐。", "龍馬行無跡，歌鐘聲沸天。", "馭風升寶坐，鬱景晏華筵。", "妙奏三春曲，高羅萬古仙。", "七珍飛滿坐，九液酌如泉。", "靈佩垂軒下，旗旛列帳前。", "獅麟威赫赫，鸞鳳影翩翩。", "顧盼乃須臾，已是數千年。"]'),
('3d95dd5b-017b-4e27-80f9-f35c225c94b2','瓊臺','柳泌','唐','唐诗','tang','','[]','崖壁盤空天路回，白雲行盡見瓊臺。',32,'全唐诗/poet.tang.27000.json','["崖壁盤空天路回，白雲行盡見瓊臺。", "洞門黯黯陰雲閉，金闕曈曈日殿開。"]'),
('d8c0607c-212b-402d-91f8-f4a3fe225bed','操蓮曲','何希堯','唐','唐诗','tang','','[]','錦蓮浮處水粼粼，風外香生襪底塵。',32,'全唐诗/poet.tang.27000.json','["錦蓮浮處水粼粼，風外香生襪底塵。", "荷葉荷裙相映色，聞歌不見採蓮人。"]'),
('75eb0966-1633-49bb-bcd4-e0e8dfa4a95a','一枝花','何希堯','唐','唐诗','tang','','[]','幾樹晴葩映水開，亂紅狼籍點蒼苔。',32,'全唐诗/poet.tang.27000.json','["幾樹晴葩映水開，亂紅狼籍點蒼苔。", "東風留得殘枝在，爲惜餘芳獨看來。"]'),
('c1e80859-de7c-4f7b-bbc2-b0b524f83158','柳枝詞','何希堯','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u67f3\u6811", "\u548f\u7269\u8bd7"]','大堤楊柳雨沈沈，萬縷千條惹恨深。',32,'全唐诗/poet.tang.27000.json','["大堤楊柳雨沈沈，萬縷千條惹恨深。", "飛絮滿天人去遠，東風無力繫春心。"]'),
('6a536632-2842-4cd6-8a8d-445d99c8d732','海棠','何希堯','唐','唐诗','tang','','[]','著雨胭脂點點消，半開時節最妖嬈。',32,'全唐诗/poet.tang.27000.json','["著雨胭脂點點消，半開時節最妖嬈。", "誰家更有黃金屋，深鎖東風貯阿嬌。"]'),
('9d587834-dcf9-46a7-a387-0313e0a819b6','遺臨平監吏','朱沖和','唐','唐诗','tang','','[]','三千里外布干戈，果得鯨鯢入網羅。',32,'全唐诗/poet.tang.27000.json','["三千里外布干戈，果得鯨鯢入網羅。", "今日寶刀無殺氣，只緣君處受恩多。"]'),
('6e4bc89c-d12b-49b1-8daf-e33c6e33624b','荻塘西莊贈房元垂','張光朝','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','門在荻塘西，塘高何聯聯。',144,'全唐诗/poet.tang.27000.json','["門在荻塘西，塘高何聯聯。", "往昔分地利，遠近無閑田。", "水國信汙下，霖霪即成川。", "苗稼盡湮沒，茲鄉獨豐年。", "家肥待親懿，人樂思管弦。", "日晏始能起，盥漱看廚煙。", "醞酒寒正熟，養魚長食鮮。", "黃昏鐘未鳴，偃息早已眠。", "何意久城市，寂寥丘中緣。", "俯仰在顏色，區區人事間。", "憶昔炎漢時，乃知綺季賢。", "靜默不能仕，養老終南山。"]'),
('a8ffe7a3-5f14-43c9-b22e-28eea904da02','天門街西觀榮王聘妃','張光朝','唐','唐诗','tang','','[]','仙媛來朱邸，名山出紫微。',72,'全唐诗/poet.tang.27000.json','["仙媛來朱邸，名山出紫微。", "三周初展義，百兩遂言歸。", "鄭國通梁苑，天津接帝畿。", "橋成烏鵲助，蓋轉鳳皇飛。", "霜仗迎秋色，星缸滿夜輝。", "從茲磐石固，應爲得賢妃。"]'),
('ba35e964-379b-456f-b60b-6813f5783fb7','天門街西觀榮王聘妃','梁鉉','唐','唐诗','tang','','[]','帝子乘龍夜，三星照戶前。',72,'全唐诗/poet.tang.27000.json','["帝子乘龍夜，三星照戶前。", "兩行宮火出，十里道鋪筵。", "羅綺明中識，簫韶暗裏傳。", "燈攢九華扇，帳撒五銖錢。", "交頸文鴛合，和鳴彩鳳連。", "欲知來日美，雙拜紫微天。"]'),
('55a74fc3-204e-4016-b406-a1582c8d793f','上浙東元相','章孝標','唐','唐诗','tang','','[]','婺女星邊喜氣頻，越王臺上坐詩人。',64,'全唐诗/poet.tang.27000.json','["婺女星邊喜氣頻，越王臺上坐詩人。", "雪晴山水勾留客，風暖旌旗計會春。", "黎庶已同猗頓富，煙花却爲相公貧。", "何言禹跡無人繼，萬頃湖田又斬新。"]'),
('17f0729a-f861-48e2-92a1-2d2afe4aee4f','贈茅山高拾遺蔓','章孝標','唐','唐诗','tang','','[]','人皆貪祿利，白首更營營。',48,'全唐诗/poet.tang.27000.json','["人皆貪祿利，白首更營營。", "若見無爲理，兼忘不朽名。", "幽禽窺飯下，好藥入籬生。", "夢覺幽泉滴，應疑禁漏聲。"]'),
('aa9b3056-5dc2-48f7-8806-5eebc7d3060e','次韻和光祿錢卿二首 一','章孝標','唐','唐诗','tang','','[]','大隱嚴城內，閑門向水開。',48,'全唐诗/poet.tang.27000.json','["大隱嚴城內，閑門向水開。", "扇風知暑退，樹影覺秋來。", "望遠雲生海，行稀砌長苔。", "廢興今古事，何必歎池灰。"]'),
('52a92cf2-56a2-43b7-a71a-12d1ba335945','次韻和光祿錢卿二首 二','章孝標','唐','唐诗','tang','','[]','閑論憂王室，愁眉仗酒開。',48,'全唐诗/poet.tang.27000.json','["閑論憂王室，愁眉仗酒開。", "方嗟三覆役，又喜四愁來。", "晨起螢穿竹，晡餐鳥下苔。", "同期陽月至，靈室祝葭灰。"]'),
('baebbdba-389b-4bc0-847a-989746c94a2e','贈廬山錢卿','章孝標','唐','唐诗','tang','','["\u5e90\u5c71"]','象魏抽簪早，匡廬築室牢。',48,'全唐诗/poet.tang.27000.json','["象魏抽簪早，匡廬築室牢。", "宦情歸去薄，天爵隱來高。", "篋有新徵詔，囊餘舊緼袍。", "何如捨麋鹿，明主仰風騷。"]'),
('932b6028-5583-492c-baaa-531b1055318d','山中送進士劉蟾赴舉','章孝標','唐','唐诗','tang','','[]','去住跡雖異，愛憎情不同。',48,'全唐诗/poet.tang.27000.json','["去住跡雖異，愛憎情不同。", "因君向帝里，使我厭山中。", "故友多朝客，新文盡國風。", "藝精心更苦，何患不成功。"]'),
('57eb4f99-e63e-434f-ad64-911806c2467f','送進士陳嶢往睦州謁馮郎中','章孝標','唐','唐诗','tang','','[]','孤帆幾日程，投刺水邊城。',48,'全唐诗/poet.tang.27000.json','["孤帆幾日程，投刺水邊城。", "倚櫂逢春老，登筵見月生。", "飲酣盃有浪，棋散漏無聲。", "太守憐才者，從容禮不輕。"]'),
('7e6e3a99-fe99-4572-b944-300a0c95ca35','豐城劒池即事','章孝標','唐','唐诗','tang','','[]','神物不復見，小池空在茲。',48,'全唐诗/poet.tang.27000.json','["神物不復見，小池空在茲。", "因嫌衝斗夜，未是偃戈時。", "岸古魚藏穴，蒲凋翠立危。", "吾皇別有劒，何必鑄金爲。"]'),
('0bcd55da-0d5a-4a43-8524-322b9f25815a','詠弓','章孝標','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','較量武藝論勳庸，曾發將軍箭落鴻。',64,'全唐诗/poet.tang.27000.json','["較量武藝論勳庸，曾發將軍箭落鴻。", "握內從誇彎似月，眼前還怕撇來風。", "只知擊起穿雕鏃，不解容和射鵠功。", "得病自從盃裏後，至今形狀怕相逢。"]'),
('80e7a5a2-1f54-43da-9e83-411b0ca79177','送無相禪師入關','章孝標','唐','唐诗','tang','','[]','九衢車馬塵，不染了空人。',48,'全唐诗/poet.tang.27000.json','["九衢車馬塵，不染了空人。", "蹔舍中峰雪，應看內殿春。", "齋心無外事，定力見前身。", "聖主方崇教，深宜謁紫宸。"]'),
('77c81568-ee8c-4e09-95e1-cd0a0477d0fd','贈匡山道者','章孝標','唐','唐诗','tang','','["\u5e90\u5c71"]','嘗聞一粒功，足以反衰容。',48,'全唐诗/poet.tang.27000.json','["嘗聞一粒功，足以反衰容。", "方寸如不達，此生安可逢。", "寄書時態盡，憶語道情濃。", "爭得攜巾履，同歸鳥外峯。"]'),
('00dce7db-7305-49bd-a3c1-86bbc091ceb6','道者與金丹開合已失因爲二首再有投擲 一','章孝標','唐','唐诗','tang','','[]','木鑽鑽盤石，辛勤四十年。',48,'全唐诗/poet.tang.27000.json','["木鑽鑽盤石，辛勤四十年。", "一朝纔見物，五色互呈妍。", "七魄憎陽盛，三彭惡命延。", "被他迷失却，歎息只澘然。"]'),
('711440d6-c547-465f-a2e6-2a8bdb24431c','道者與金丹開合已失因爲二首再有投擲 二','章孝標','唐','唐诗','tang','','[]','陰陽曾作炭，造化亦分功。',48,'全唐诗/poet.tang.27000.json','["陰陽曾作炭，造化亦分功。", "減自青囊裏，收安玉合中。", "凡材難度世，神物自歸空。", "惆悵流年速，看成白首翁。"]'),
('a1891685-a25a-40ec-a6b6-4a0ca135b695','思越州山水寄朱慶餘','章孝標','唐','唐诗','tang','','[]','窗戶潮頭雪，雲霞鏡裏天。',48,'全唐诗/poet.tang.27000.json','["窗戶潮頭雪，雲霞鏡裏天。", "島桐秋送雨，江艇暮搖煙。", "藕折蓮芽脆，茶挑茗眼鮮。", "還將歐冶劒，更淬若耶泉。"]'),
('4cbf889d-5b0d-4915-8b31-ee5fb3dfb92c','蜀中上王尚書','章孝標','唐','唐诗','tang','','[]','梓桐花幕碧雲浮，天許文星寄上頭。',64,'全唐诗/poet.tang.27000.json','["梓桐花幕碧雲浮，天許文星寄上頭。", "武略劒峰環相府，詩情錦浪浴仙洲。", "丁香風裏飛牋草，邛竹煙中動酒鉤。", "自古名高閑不得，肯容王粲賦登樓。"]'),
('3ef3ba73-c958-435f-a9b0-9c37600394c9','贈陸鬯浙西進詩除官','章孝標','唐','唐诗','tang','','[]','帝城雲物得陽春，水國煙花失主人。',32,'全唐诗/poet.tang.27000.json','["帝城雲物得陽春，水國煙花失主人。", "昨日天風吹樂府，六宮絲管一時新。"]'),
('f6c73ea5-a277-4b68-80e0-050196fb26d8','古行宮','章孝標','唐','唐诗','tang','','[]','瓦煙疎冷古行宮，寂寞朱門反鏁空。',64,'全唐诗/poet.tang.27000.json','["瓦煙疎冷古行宮，寂寞朱門反鏁空。", "殘粉水銀流砌下，墮環秋月落泥中。", "鶯傳舊語嬌春日，花學嚴妝妬曉風。", "天子時清不巡幸，秖應鸞鳳集梧桐。"]'),
('8a1f180d-3585-4aef-91c1-ca8855b36782','題上皇觀','章孝標','唐','唐诗','tang','','[]','煙霞星蓋七星壇，想像先朝駐禁鑾。',64,'全唐诗/poet.tang.27000.json','["煙霞星蓋七星壇，想像先朝駐禁鑾。", "輦路已平栽藥地，皇風猶在步虛寒。", "樓臺瑞氣晴蕭索，杉檜龍身老屈蟠。", "翻感惠休并李郭，劒門空處望長安。"]'),
('842e189c-c9ae-42a4-92f2-e4598acc4831','鷹','章孝標','唐','唐诗','tang','','[]','星眸未放瞥秋毫，頻掣金鈴試雪毛。',64,'全唐诗/poet.tang.27000.json','["星眸未放瞥秋毫，頻掣金鈴試雪毛。", "會使老拳供口腹，莫辭親手啖腥臊。", "穿雲自怪身如電，煞兔誰知吻勝刀。", "可惜忍飢寒日暮，向人鵮斷碧絲縧。"]'),
('b42139a6-9bb3-40fe-b9ba-a595e8a0ebba','方山寺松下泉','章孝標','唐','唐诗','tang','','[]','石脉綻寒光，松根噴曉霜。',48,'全唐诗/poet.tang.27000.json','["石脉綻寒光，松根噴曉霜。", "注瓶雲母滑，漱齒茯苓香。", "野客偷煎茗，山僧惜淨床。", "三禪不要問，孤月在中央。"]'),
('f0d11fd0-26d2-4608-aeb0-dc841b80470b','瀑布','章孝標','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','秋河溢長空，天灑萬丈布。',48,'全唐诗/poet.tang.27000.json','["秋河溢長空，天灑萬丈布。", "深雷隱雲壑，孤電挂巖樹。", "滄溟曉噴寒，碧落晴盪素。", "非趨下流急，勢使不得住。"]'),
('0076b8e7-67de-44ee-8c18-5a429e8f0823','送張使君赴饒州','章孝標','唐','唐诗','tang','','[]','饒陽因富得州名，不獨農桑別有營。',64,'全唐诗/poet.tang.27000.json','["饒陽因富得州名，不獨農桑別有營。", "日暖提筐依茗樹，天陰把酒入銀坑。", "江寒魚動槍旗影，山晚雲和鼓角聲。", "太守能詩兼愛靜，西樓見月幾篇成。"]'),
('eaf4b233-c120-4652-94ff-a270887fc644','和滕邁先輩傷馬','章孝標','唐','唐诗','tang','','[]','浮雲變化失龍兒，始憶嘶風噴沫時。',64,'全唐诗/poet.tang.27000.json','["浮雲變化失龍兒，始憶嘶風噴沫時。", "蹄想塵中翻碧玉，尾休煙裏掉青絲。", "曾同客舍吞飢渴，久共名場踏嶮巘。", "今日櫪前興一歎，不關行李乏金羈。"]'),
('a59aef6d-cc23-4841-82c5-ff2eb71d0fd9','省試騏驥長鳴','章孝標','唐','唐诗','tang','','[]','有馬骨堪驚，無人眼暫明。',72,'全唐诗/poet.tang.27000.json','["有馬骨堪驚，無人眼暫明。", "力窮吳坂峻，嘶苦朔風生。", "逐逐懷良御，蕭蕭顧樂鳴。", "瑤池期弄影，天路擬飛聲。", "皎月誰知種，浮雲莫問程。", "鹽車今願脫，千里爲君行。"]'),
('f831e560-af7b-4d13-a7c7-730574d35dd2','鯉魚','章孝標','唐','唐诗','tang','','[]','眼似真珠鱗似金，時時動浪出還沈。',32,'全唐诗/poet.tang.27000.json','["眼似真珠鱗似金，時時動浪出還沈。", "河中得上龍門去，不歎江湖歲月深。"]'),
('076b203b-9dc4-4051-b379-b234efbdc107','飢鷹詞','章孝標','唐','唐诗','tang','','[]','遙想平原兔正肥，千迴礪吻振毛衣。',32,'全唐诗/poet.tang.27000.json','["遙想平原兔正肥，千迴礪吻振毛衣。", "縱令啄解絲縧結，未得人呼不敢飛。"]'),
('b528fab9-7892-4712-9455-f86b3de48c48','歸燕詞辭工部侍郎','章孝標','唐','唐诗','tang','','[]','舊壘危巢泥已落，今年故向社前歸。',32,'全唐诗/poet.tang.27000.json','["舊壘危巢泥已落，今年故向社前歸。", "連雲大廈無棲處，更望誰家門戶飛。"]'),
('a3e78b2e-f7e7-4d75-be89-aa1a390792b4','歸海上舊居','章孝標','唐','唐诗','tang','','[]','鄉路繞蒹葭，縈紆出海涯。',48,'全唐诗/poet.tang.27000.json','["鄉路繞蒹葭，縈紆出海涯。", "人衣披蜃氣，馬跡印鹽花。", "草沒題詩石，潮摧坐釣槎。", "還歸舊窗裏，凝思向餘霞。"]'),
('d919e5f3-a27a-46cb-bed7-8dff2e74098e','答友人惠牙簪','章孝標','唐','唐诗','tang','','[]','牙簪不可忘，來處隔炎荒。',48,'全唐诗/poet.tang.27000.json','["牙簪不可忘，來處隔炎荒。", "截得半環月，磨成四寸霜。", "曉辭梳齒膩，秋入髮根涼。", "好是紗巾下，纖纖錐出囊。"]'),
('d1cf3aed-bb38-4fbf-9feb-fb93121196ed','日者','章孝標','唐','唐诗','tang','','[]','十指中央了五行，說人休咎見前生。',32,'全唐诗/poet.tang.27000.json','["十指中央了五行，說人休咎見前生。", "我來本乞真消息，却怕呵錢卦欲成。"]'),
('cb0d7d54-de06-4996-b0fb-0114e361f071','送金可紀歸新羅','章孝標','唐','唐诗','tang','','[]','登唐科第語唐音，望日初生憶故林。',64,'全唐诗/poet.tang.27000.json','["登唐科第語唐音，望日初生憶故林。", "鮫室夜眠陰火冷，蜃樓朝泊曉霞深。", "風高一葉飛魚背，潮淨三山出海心。", "想把文章合夷樂，蟠桃花裏醉人參。"]'),
('0958ecac-304c-400f-8855-4f3013ebba6c','聞角','章孝標','唐','唐诗','tang','','[]','邊秋畫角怨金微，半夜對吹驚賊圍。',64,'全唐诗/poet.tang.27000.json','["邊秋畫角怨金微，半夜對吹驚賊圍。", "塞雁遶空秋不下，胡雲著草凍還飛。", "關頭老馬嘶看月，磧裏疲兵淚濕衣。", "餘韻嫋空何處盡，戍天寥落曉星稀。"]'),
('68c84939-4391-4209-9a3c-e520e3f6597e','夢鄉','章孝標','唐','唐诗','tang','','[]','家住吳王舊苑東，屋頭山水勝屏風。',32,'全唐诗/poet.tang.27000.json','["家住吳王舊苑東，屋頭山水勝屏風。", "尋常夢在秋江上，釣艇游揚藕葉中。"]'),
('e65d80c3-2979-4fdb-b543-2f9e5c35e5a5','織綾詞','章孝標','唐','唐诗','tang','','[]','去年蠶惡綾帛貴，官急無絲織紅淚。',80,'全唐诗/poet.tang.27000.json','["去年蠶惡綾帛貴，官急無絲織紅淚。", "殘經脆緯不通梭，鵲鳳闌珊失頭尾。", "今年蠶好繰白絲，鳥鮮花活人不知。", "瑤臺雪裏鶴張翅，禁苑風前梅折枝。", "不學隣家婦慵懶，蠟揩粉拭謾官眼。"]'),
('f1b62406-0209-401e-bde9-3d615eb62fef','諸葛武侯廟','章孝標','唐','唐诗','tang','','[]','木牛零落陣圖殘，山姥燒錢古栢寒。',32,'全唐诗/poet.tang.27000.json','["木牛零落陣圖殘，山姥燒錢古栢寒。", "七縱七擒何處在，茅花櫪葉蓋神壇。"]'),
('a3fce625-fbad-43b2-a6be-7044ed8a7f90','長安秋夜','章孝標','唐','唐诗','tang','','[]','田家無五行，水旱卜蛙聲。',48,'全唐诗/poet.tang.27000.json','["田家無五行，水旱卜蛙聲。", "牛犢乘春放，兒童候暖耕。", "池塘煙未起，桑柘雨初晴。", "歲晚香醪熟，村村自送迎。"]'),
('6527486b-e542-4150-a1cd-8c3bf7d81d48','錢塘贈武翊黃','章孝標','唐','唐诗','tang','','[]','曾將心劒作戈矛，一戰名場造化愁。',64,'全唐诗/poet.tang.27000.json','["曾將心劒作戈矛，一戰名場造化愁。", "花錦文章開四面，天人科第上三頭。", "鴛鴻待侶飛清禁，山水緣情住外州。", "時伴庾公看海月，好吟詩斷望潮樓。"]'),
('c94d575f-6126-40d6-a1b0-073ecdb1b946','風不鳴條','章孝標','唐','唐诗','tang','','[]','旭日懸清景，微風在綠條。',72,'全唐诗/poet.tang.27000.json','["旭日懸清景，微風在綠條。", "入松聲不發，過柳影空搖。", "長養應潛變，扶疎每暗飄。", "有林時杳杳，無樹蹔蕭蕭。", "慢逐清煙散，輕和瑞氣饒。", "豐年知有待，歌詠美唐堯。"]'),
('6cae3ced-6788-4a07-8d41-9a3cfbc11ea9','貽美人','章孝標','唐','唐诗','tang','','[]','諸侯帳下慣新妝，皆怯劉家薄媚娘。',64,'全唐诗/poet.tang.27000.json','["諸侯帳下慣新妝，皆怯劉家薄媚娘。", "寶髻巧梳金翡翠，羅裙宜著繡鴛鴦。", "輕輕舞汗初沾袖，細細歌聲欲遶梁。", "何事不歸巫峽去，故來人世斷人腸。"]'),
('4d9e43cf-3699-467d-8f44-22501903d98a','聞雲中唳鶴','章孝標','唐','唐诗','tang','','[]','久在青田唳，天高忽暫聞。',48,'全唐诗/poet.tang.27000.json','["久在青田唳，天高忽暫聞。", "翩翻縈碧落，嘹唳入重雲。", "出谷鶯何待，鳴岐鳳欲羣。", "九臯寧足道，此去透絪緼。"]'),
('4f8befa4-f6bb-454d-b59a-9de530a63de4','柘枝','章孝標','唐','唐诗','tang','','[]','柘枝初出鼓聲招，花鈿羅衫聳細腰。',64,'全唐诗/poet.tang.27000.json','["柘枝初出鼓聲招，花鈿羅衫聳細腰。", "移步錦靴空綽約，迎風繡帽動飄颻。", "亞身踏節鸞形轉，背面羞人鳳影嬌。", "祗恐相公看未足，便隨風雨上青霄。"]'),
('27e8f841-192d-4ae8-bdb3-aff42707af8e','上太皇先生','章孝標','唐','唐诗','tang','','[]','顥氣貫精神，蒼崖老姓名。',120,'全唐诗/poet.tang.27000.json','["顥氣貫精神，蒼崖老姓名。", "煙霞空送景，水木苦無情。", "斸藥雲根斷，眠花石面平。", "折松開月色，決水放秋聲。", "顏爲忘憂嫩，身緣絕粒輕。", "圍棋看局勢，對鏡戮妖精。", "過海量鯨力，歸天算鶴程。", "露凝鍾乳冷，風定玉簫清。", "坐覺衣裳古，行疑羽翼生。", "應憐市朝客，開眼鏁浮榮。"]'),
('e51090af-c7b8-43ae-9527-a02fa6f9e59d','破山水屏風','章孝標','唐','唐诗','tang','','[]','時人嫌古畫，倚壁不曾收。',48,'全唐诗/poet.tang.27000.json','["時人嫌古畫，倚壁不曾收。", "雨滴膠山斷，風吹絹海秋。", "殘雲飛屋裏，片水落牀頭。", "尚勝凡花鳥，君能補綴休。"]'),
('0be799ea-51f7-446f-b79b-d1bd9149b977','覽楊校書文卷','章孝標','唐','唐诗','tang','','[]','跪伸霜素剖琅玕，身墮瑤池魄暗寒。',64,'全唐诗/poet.tang.27000.json','["跪伸霜素剖琅玕，身墮瑤池魄暗寒。", "紅錦晚開雲母殿，白珠秋寫水精盤。", "情高鶴立崑崙峭，思壯鯨跳渤澥寬。", "誰有軒轅古銅片，爲持相並照妖看。"]'),
('d31b4eb0-82bb-4e67-b086-cd055201508d','送陳校書赴蔡州幕','章孝標','唐','唐诗','tang','','[]','天假縱橫入幕籌，東南頓減一方憂。',64,'全唐诗/poet.tang.27000.json','["天假縱橫入幕籌，東南頓減一方憂。", "行賷健筆辭天閣，坐見妖星落蔡州。", "青草袍襟翻日脚，黃金馬鐙照旄頭。", "此行領取從軍樂，莫慮功名不拜侯。"]'),
('b72182b4-d3eb-4a84-b6a8-02a0ac000711','少年行','章孝標','唐','唐诗','tang','','[]','平明小獵出中軍，異國名香滿袖薰。',64,'全唐诗/poet.tang.27000.json','["平明小獵出中軍，異國名香滿袖薰。", "畫榼倒懸鸚鵡觜，花衫對舞鳳凰文。", "手擡白馬嘶春雪，臂竦青骹入暮雲。", "落日胡姬樓上飲，風吹簫管滿樓聞。"]'),
('a8ee87a0-fc04-4d05-9a50-42ce03c1c523','蜀中贈廣上人','章孝標','唐','唐诗','tang','','[]','曾持麈尾引金根，萬乘前頭草五言。',64,'全唐诗/poet.tang.27000.json','["曾持麈尾引金根，萬乘前頭草五言。", "疏講青龍歸禁苑，歌抄白雪乞梨園。", "朝驚雲氣遮天閣，暮踏猨聲入劒門。", "今日西川無子美，詩風又起浣花村。"]'),
('1348bde4-6963-4915-9e46-ae4b0f3510d2','和顧校書新開井','章孝標','唐','唐诗','tang','','[]','霜鍤破桐陰，青絲試淺深。',48,'全唐诗/poet.tang.27000.json','["霜鍤破桐陰，青絲試淺深。", "月輪開地脉，鏡面寫天心。", "碧甃花千片，香泉乳百尋。", "欲知爭汲引，聽取轆轤音。"]'),
('db8a5d42-7de3-4ced-81f8-ac6b6d5e3900','遊雲際寺','章孝標','唐','唐诗','tang','','[]','衫袖拂青冥，推鞍上翠屏。',48,'全唐诗/poet.tang.27000.json','["衫袖拂青冥，推鞍上翠屏。", "塵埃辭馬尾，城闕入窗櫺。", "雲領浮名去，鐘撞大夢醒。", "茫茫山下事，滿眼送流萍。"]'),
('d0271453-1c42-44ab-94cd-fe044d2921b0','贈劉寬夫昆季','章孝標','唐','唐诗','tang','','[]','文聚星辰衣彩霞，問誰兄弟是劉家。',64,'全唐诗/poet.tang.27000.json','["文聚星辰衣彩霞，問誰兄弟是劉家。", "雁行雲摻參差翼，瓊樹風開次第花。", "天假聲名懸日月，國憑騷雅變浮華。", "曾窮晉漢儒林傳，龍虎雖多未足誇。"]'),
('d1addb3e-5c1e-4756-91c5-9f547e458b75','贈杭州嚴史君','章孝標','唐','唐诗','tang','','[]','州青縣白淛河濆，飽向蒼龍闕下聞。',64,'全唐诗/poet.tang.27000.json','["州青縣白淛河濆，飽向蒼龍闕下聞。", "鼓角自嚴寒海月，旌旗不動濕江雲。", "風騷處處文章主，井邑家家父母君。", "長恐抱轅留不住，九天鴛鷺待成羣。"]'),
('69d095ce-c097-435e-b7f6-291d8a8b0314','題朱秀城南亭子','章孝標','唐','唐诗','tang','','[]','朱家亭子象懸匏，階瑩青莎棟剪茆。',64,'全唐诗/poet.tang.27000.json','["朱家亭子象懸匏，階瑩青莎棟剪茆。", "癭挂眼開欺鴝鵒，花緣網結妬螵蛸。", "有時風月輸三虎，無壁琴書屬四郊。", "土木欲知精潔處，社天歸燕怯安巢。"]'),
('506850cf-cdda-48e2-9e2b-8ebf6d0f3d22','上西川王尚書','章孝標','唐','唐诗','tang','','[]','人人入蜀謁文翁，妍醜終須露鏡中。',64,'全唐诗/poet.tang.27000.json','["人人入蜀謁文翁，妍醜終須露鏡中。", "詩景荒涼難道合，客情疎密分當同。", "城南歌吹琴臺月，江上旌旗錦水風。", "下客低頭來又去，暗堆冰炭在深衷。"]'),
('a15f2368-e6c0-4eca-aac9-e26dafbdc548','駱谷行','章孝標','唐','唐诗','tang','','[]','捫雲褭棧入青冥，鞿馬鈴騾傍日星。',64,'全唐诗/poet.tang.27000.json','["捫雲褭棧入青冥，鞿馬鈴騾傍日星。", "仰踏劒稜梯萬仞，下緣冰岫杳千尋。", "山花織錦時聊看，澗水彈琴不暇聽。", "若比爭名求利處，尋思此路却安寧。"]'),
('704f75de-0215-474a-bc7d-0ac3b2d8efe2','初及第歸酬孟元翊見贈','章孝標','唐','唐诗','tang','','[]','六年衣破帝城塵，一日天池水脫鱗。',64,'全唐诗/poet.tang.27000.json','["六年衣破帝城塵，一日天池水脫鱗。", "未有片言驚後輩，不無慙色見同人。", "每登公讌思來日，漸聽鄉音認本身。", "何幸致詩相慰賀，東歸花發杏桃春。"]'),
('d951f54a-0f5b-4aa7-b9c3-796e2db30bf2','淮南李相公紳席上賦春雪','章孝標','唐','唐诗','tang','','[]','六出花飛處處飄，黏窗著砌上寒條。',32,'全唐诗/poet.tang.27000.json','["六出花飛處處飄，黏窗著砌上寒條。", "朱門到曉難盈尺，盡是三軍喜氣消。"]'),
('df5d6e66-1af1-404c-b5ed-9700789a5654','及第後寄廣陵故人','章孝標','唐','唐诗','tang','','[]','及第全勝十政官，金鞍鍍了出長安。',32,'全唐诗/poet.tang.27000.json','["及第全勝十政官，金鞍鍍了出長安。", "馬頭漸入揚州郭，爲報時人洗眼看。"]'),
('23acbfe3-398c-469d-901b-9fca7c70b726','小松','章孝標','唐','唐诗','tang','','[]','爪葉鱗條龍不盤，梳風幕翠一庭寒。',32,'全唐诗/poet.tang.27000.json','["爪葉鱗條龍不盤，梳風幕翠一庭寒。", "莫言只是人長短，須作浮雲向上看。"]'),
('48c86b27-0427-4f3c-b7dc-e623b1eeb3a4','宮詞','章孝標','唐','唐诗','tang','','[]','明日鑾輿欲向東，守宮金翠帶愁紅。',32,'全唐诗/poet.tang.27000.json','["明日鑾輿欲向東，守宮金翠帶愁紅。", "九門佳氣已西去，千里花開一夜風。"]'),
('db1e40a7-701f-4e50-a53a-5f51aaebae44','題杭州樟亭驛','章孝標','唐','唐诗','tang','','[]','樟亭驛上題詩客，一半尋爲山下塵。',32,'全唐诗/poet.tang.27000.json','["樟亭驛上題詩客，一半尋爲山下塵。", "世事日隨流水去，紅花還似白頭人。"]'),
('52763392-2468-4de1-9844-048ec74cd59d','劉侍中宅盤花紫薔薇','章孝標','唐','唐诗','tang','','["\u6625\u5929", "\u82b1", "\u5199\u82b1"]','真宰偏饒麗景家，當春盤出帶根霞。',32,'全唐诗/poet.tang.27000.json','["真宰偏饒麗景家，當春盤出帶根霞。", "從開一朵朝衣色，免踏塵埃看雜花。"]'),
('b8d91859-ecf1-4c1b-9587-61e0aaebd5d8','題東林寺寄江州李員外','章孝標','唐','唐诗','tang','','[]','山勢稜層入杳冥，寺形高下趂山行。',64,'全唐诗/poet.tang.27000.json','["山勢稜層入杳冥，寺形高下趂山行。", "象牙牀坐蓮花佛，瑪瑙函盛貝葉經。", "日映砌陰移寶閣，風吹天樂動金鈴。", "門前更有清江水，便是潯陽太守廳。"]'),
('9468242f-c446-41ef-ab8a-e3e7ee7fe4d3','玄都觀栽桃十韻','章孝標','唐','唐诗','tang','','[]','驅使鬼神功，攢栽萬樹紅。',120,'全唐诗/poet.tang.27000.json','["驅使鬼神功，攢栽萬樹紅。", "薰香丹鳳闕，妝點紫瓊宮。", "寶帳重遮日，妖金遍累空。", "色然燒藥火，影舞步虛風。", "粉撲青牛過，枝驚白鶴沖。", "拜星春錦上，服食晚霞中。", "棋局陰長合，簫聲祕不通。", "豔陽迷俗客，幽邃失壺公。", "根柢終盤石，桑麻自轉蓬。", "求師飽靈藥，他日訪遼東。"]'),
('486259c0-58ce-4ea8-af90-8fba4140e73c','僧院小松','章孝標','唐','唐诗','tang','','[]','拋杉背栢冷僧簾，鎖月梳風出殿簷。',32,'全唐诗/poet.tang.27000.json','["拋杉背栢冷僧簾，鎖月梳風出殿簷。", "還似天台新雨後，小峯雲外碧尖尖。"]'),
('6599ed30-febd-46a0-aa84-2cb7ec7f4b04','春原早望','章孝標','唐','唐诗','tang','','[]','一忝鄉書薦，長安未得回。',48,'全唐诗/poet.tang.27000.json','["一忝鄉書薦，長安未得回。", "年光逐渭水，春色上秦臺。", "燕掠平蕪去，人衝細雨來。", "東風生故里，又過幾花開。"]'),
('7c6596ae-69d3-44a4-a4e8-7f5afa84b1da','西山廣福院','章孝標','唐','唐诗','tang','','[]','野寺孤峯上，危樓聳翠微。',48,'全唐诗/poet.tang.27000.json','["野寺孤峯上，危樓聳翠微。", "捲簾滄海近，洗鉢白雲飛。", "竹影臨經案，松花點衲衣。", "日斜登望處，湖畔一僧歸。"]'),
('5a744fe9-3cf9-479e-ae56-897d9a65259e','遊地肺','章孝標','唐','唐诗','tang','','[]','市朝擾擾千古，林壑冥冥四賢。',56,'全唐诗/poet.tang.27000.json','["市朝擾擾千古，林壑冥冥四賢。", "黃鶴不歸丹竈，白雲自養芝田。", "溪灘永夜流月，羽翼清秋在天。", "高跡無人更躡，碧峯寥落孤煙。"]'),
('b397532d-1b16-45ce-a7dd-2c95ecda812f','八月','章孝標','唐','唐诗','tang','','[]','徙倚仙居遶翠樓，分明宮漏靜兼秋。',32,'全唐诗/poet.tang.27000.json','["徙倚仙居遶翠樓，分明宮漏靜兼秋。", "長安夜夜家家月，幾處笙歌幾處愁。"]'),
('c2d1ac22-c658-4307-abcf-3e73b7c36126','題紫微山上方','章孝標','唐','唐诗','tang','','[]','地勢連滄海，山名號紫微。',48,'全唐诗/poet.tang.27000.json','["地勢連滄海，山名號紫微。", "景閑僧坐久，路僻客來稀。", "峽影雲相照，河流石自圍。", "塵喧都不到，安得此忘歸。"]'),
('39752fac-4246-4b28-8716-b1d595780632','題杜賓客新豐里幽居','蔣防','唐','唐诗','tang','','[]','退跡依三逕，辭榮繼二疏。',72,'全唐诗/poet.tang.27000.json','["退跡依三逕，辭榮繼二疏。", "聖情容解印，帝里許懸車。", "已去龍樓籍，猶分御廩儲。", "風泉輸耳目，松竹助玄虛。", "調護心常在，山林意有餘。", "應嗤紫芝客，遠就白雲居。"]'),
('4c1e4e54-7b35-4306-9d2b-cb7c97a9dcc2','望禁苑祥光','蔣防','唐','唐诗','tang','','[]','嘉瑞生天色，蔥蘢幾效祥。',72,'全唐诗/poet.tang.27000.json','["嘉瑞生天色，蔥蘢幾效祥。", "樹搖三殿側，日映九城傍。", "仙霧今同色，卿雲未可章。", "拱汾疑鼎氣，臨渭比熒光。", "豈並春風舊，俄同聖壽長。", "微臣時一望，短羽欲翺翔。"]'),
('5e4edf73-eae4-4eae-b8e0-aa498385266e','冬至日祥風應候','蔣防','唐','唐诗','tang','','[]','節逢清景空，氣占二儀中。',72,'全唐诗/poet.tang.27000.json','["節逢清景空，氣占二儀中。", "獨喜登高日，先知應候風。", "瑞呈光舜化，慶表盛堯聰。", "況與承時叶，還將入律同。", "微微萬井逼，習習九門通。", "遶殿爐煙起，殷勤報歲功。"]'),
('bdc9d20e-772b-493d-ad98-bf272c8a490a','春風扇微和','蔣防','唐','唐诗','tang','','[]','麗日催遲景，和風扇早春。',72,'全唐诗/poet.tang.27000.json','["麗日催遲景，和風扇早春。", "暖浮丹鳳闕，韶媚黑龍津。", "澹蕩迎仙仗，霏微送畫輪。", "綠搖官柳散，紅待禁花新。", "舞席皆迴雪，歌筵暗送塵。", "幸當陽律候，惟願及佳辰。"]'),
('7dd47b79-e7fd-4667-8b14-1ce14f4e8078','日暖萬年枝','蔣防','唐','唐诗','tang','','[]','新陽歸上苑，嘉樹獨含妍。',72,'全唐诗/poet.tang.27000.json','["新陽歸上苑，嘉樹獨含妍。", "散漫添和氣，曈曨卷曙煙。", "流輝宜聖日，接影貴芳年。", "自與恩光近，那關煦嫗偏。", "結根誠得地，表壽願符天。", "誰道凌寒質，從茲不曖然。"]'),
('cf378ade-9421-4203-88cf-212ca41a9c24','秋月懸清輝','蔣防','唐','唐诗','tang','','[]','秋月沿霄漢，亭亭委素輝。',72,'全唐诗/poet.tang.27000.json','["秋月沿霄漢，亭亭委素輝。", "山明桂花發，池滿夜珠歸。", "入牖人偏攬，臨枝鵲正飛。", "影連平野淨，輪度曉雲微。", "晶晃浮輕露，裴回映薄帷。", "此時千里道，延望獨依依。"]'),
('cad0ec82-32bb-47eb-8852-abebac913d6b','八風從律','蔣防','唐','唐诗','tang','','[]','製律窺元化，因聲感八風。',72,'全唐诗/poet.tang.27000.json','["製律窺元化，因聲感八風。", "還從萬籟起，更與五音同。", "習習蘆灰上，泠泠玉管中。", "氣隨時物好，響徹霽天空。", "自得陰陽順，能令惠澤通。", "願吹寒谷裏，從此達前蒙。"]'),
('4406ad8c-c4b9-42c7-8b9d-667681101916','藩臣戀魏闕','蔣防','唐','唐诗','tang','','[]','剖竹隨皇命，分憂鎮大藩。',72,'全唐诗/poet.tang.27000.json','["剖竹隨皇命，分憂鎮大藩。", "恩波懷魏闕，獻納望天閽。", "政奉南風順，心依北極尊。", "夢魂通玉陛，動息寄朱軒。", "直以蒸黎念，思陳政化源。", "如何子牟意，今古道斯存。"]'),
('9e9cde18-db15-48e6-8dbe-549f24247bc9','[秋]稼如雲','蔣防','唐','唐诗','tang','','[]','肆目如雲處，三田大有秋。',72,'全唐诗/poet.tang.27000.json','["肆目如雲處，三田大有秋。", "蔥蘢初蔽野，散漫正盈疇。", "稍混從龍勢，寧同觸石幽。", "紫芒分羃羃，青頴澹油油。", "始愜倉箱望，終無滅裂憂。", "西成知不遠，雨露復何酬。"]'),
('2ff14c1c-6ecb-48f1-8bde-9c0859dffdeb','玉巵無當','蔣防','唐','唐诗','tang','','[]','美玉常爲器，茲焉變漏巵。',72,'全唐诗/poet.tang.27000.json','["美玉常爲器，茲焉變漏巵。", "酒漿悲莫挹，樽俎念空施。", "符彩功難補，盈虛數已虧。", "豈惟孤玩好，抑亦類瑕疵。", "清越音雖在，操持意漸隳。", "賦形期大匠，良璞勿同斯。"]'),
('adc4232e-bdf9-4910-9c74-a2f8614c8ea9','至人無夢','蔣防','唐','唐诗','tang','','[]','已賾希微理，知將靜默鄰。',72,'全唐诗/poet.tang.27000.json','["已賾希微理，知將靜默鄰。", "坐忘寧有夢，跡滅示凝神。", "化蝶誠知幻，徵蘭匪契真。", "抱玄雖解帶，守一自離塵。", "寥朗壺中曉，虛明洞裏春。", "翛然碧霞客，那比漆園人。"]'),
('adc3303c-aa3f-4844-9cfb-86755e5d47d2','玄都樓桃','蔣防','唐','唐诗','tang','','[]','舊傳天上千年熟，今日人間五日香。',32,'全唐诗/poet.tang.27000.json','["舊傳天上千年熟，今日人間五日香。", "紅軟滿枝須作意，莫交方朔施偷將。"]'),
('31451b83-556b-478f-870b-9b0d8f48014e','題李賓客舊居','李虞','唐','唐诗','tang','','[]','逢時不得致升平，豈是明君忘姓名。',32,'全唐诗/poet.tang.27000.json','["逢時不得致升平，豈是明君忘姓名。", "眼暗髮枯緣世事，今來無淚哭先生。"]'),
('6c226cda-99c1-4962-b3b8-bdfbae87da29','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 一','裴潾','唐','唐诗','tang','','[]','動復有原，進退有期。',50,'全唐诗/poet.tang.27000.json','["動復有原，進退有期。", "用在得正，明以知微。", "夫惟哲人，會且有歸。", "靜固勝熱，安每慮危。", "將憩於盤，止亦先機。"]'),
('c9079522-8d56-4a12-a1d0-e6f898973566','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 二','裴潾','唐','唐诗','tang','','[]','植愛在根，鍾福有兆。',50,'全唐诗/poet.tang.27000.json','["植愛在根，鍾福有兆。", "珠潛巨海，玉蘊崑嶠。", "披室生白，照夜成晝。", "揮翰飛文，入侍左右。", "出納帝命，弘茲在宥。"]'),
('4ca3715f-6e71-4948-bd73-1c270f0b908c','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 三','裴潾','唐','唐诗','tang','','[]','歷難求試，執憲成風。',50,'全唐诗/poet.tang.27000.json','["歷難求試，執憲成風。", "四鎮咸乂，三階以融。", "捧日柱天，造膝納忠。", "建儲固本，樹屏息戎。", "彼狐彼鼠，窒穴掃蹤。"]'),
('4020dc95-fde2-43c8-9c1b-1f8fe6ab57f3','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 四','裴潾','唐','唐诗','tang','','[]','我力或屈，我躬莫汚。',50,'全唐诗/poet.tang.27000.json','["我力或屈，我躬莫汚。", "三黜如飴，三起惟懼。", "再賓爲寵，一麾爲飫。", "昔在治繁，常思歸去。", "今則合契，行斯中慮。"]'),
('8bdaf2f2-dcc4-4e65-a3af-5f58f471a2d6','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 五','裴潾','唐','唐诗','tang','','[]','有鳳自南，亦翽其羽。',50,'全唐诗/poet.tang.27000.json','["有鳳自南，亦翽其羽。", "好姱佳麗，于伊之滸。", "五彩含章，九苞合矩。", "佩仁服義，鳴中律呂。", "我來思卷，薄言遵渚。"]'),
('ffa26c31-c17b-46b7-aa75-5a8d54703f70','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 六','裴潾','唐','唐诗','tang','','[]','鑿龍中闢，伊原古奔。',50,'全唐诗/poet.tang.27000.json','["鑿龍中闢，伊原古奔。", "下有秘洞，豁起石門。", "竹澗水橫，松架雪屯。", "岫環如壁，巖虛若軒。", "朝昏含景，夏凊冬溫。"]'),
('3c80ca01-61f5-46b4-93d7-b9742e96dc66','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 七','裴潾','唐','唐诗','tang','','[]','南溪迴舟，西嶺望竦。',50,'全唐诗/poet.tang.27000.json','["南溪迴舟，西嶺望竦。", "水遠如空，山微似𡾩。", "二室峯連，四山駢聳。", "五女乍欹，玉華獨踊。", "雲翔日耀，如戴如拱。"]'),
('745c1be3-14b2-4604-8768-054b2dce89c4','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 八','裴潾','唐','唐诗','tang','','[]','飛泉挂空，如決天潯。',50,'全唐诗/poet.tang.27000.json','["飛泉挂空，如決天潯。", "萬仞懸注，直貫潭心。", "月正中央，洞見淺深。", "羣山無影，孤鶴時吟。", "我嘯我歌，或眺或臨。"]'),
('c8c2274a-1730-4aa6-aa1e-101a8c49ad68','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 九','裴潾','唐','唐诗','tang','','[]','鳥之在巢，風起林搖。',59,'全唐诗/poet.tang.27000.json','["鳥之在巢，風起林搖。", "退翔城顛，翠虬捫天。", "雨止雪旋，亦息于淵。", "人皆知進，我獨止焉。", "人皆務明，我獨晦焉。", "邈矣其山默矣其泉。"]'),
('ba9af23d-be6a-4c28-8d70-3217d93247de','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 十','裴潾','唐','唐诗','tang','','[]','寢丘之田，土山之上。',50,'全唐诗/poet.tang.27000.json','["寢丘之田，土山之上。", "孫既貽謀，謝亦遐想。", "儉則爲福，華固難長。", "寧若我心，一泉一壤。", "造適爲足，超然孤賞。"]'),
('36fb43a0-20bd-4b54-a35c-ffc0416a1a51','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 十一','裴潾','唐','唐诗','tang','','[]','其風自西，言發帝庭。',50,'全唐诗/poet.tang.27000.json','["其風自西，言發帝庭。", "飄彼黃素，墮於山楹。", "公拜稽首，靡敢受榮。", "宸嚴再臨，俾撫百城。", "戀此莫處，星言其征。"]'),
('10105ddb-927c-4f5e-9410-8f5c378000c5','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 十二','裴潾','唐','唐诗','tang','','[]','公昔南邁，我不及覩。',50,'全唐诗/poet.tang.27000.json','["公昔南邁，我不及覩。", "言旋舊觀，莫獲安語。", "今則不遑，載騫載舉。", "離憂莫寫，歡好曷敘。", "愴矣東望，泣涕如雨。"]'),
('592b379e-a918-4772-af21-32c487a3afb1','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 十三','裴潾','唐','唐诗','tang','','[]','山嵇之舊，劉盧之恩。',50,'全唐诗/poet.tang.27000.json','["山嵇之舊，劉盧之恩。", "舉世莫尚，惟公是敦。", "哀我蠢蠢，念我諄諄。", "振此鎩翮，扇之騰翻。", "斯德未報，祇誓子孫。"]'),
('c9d28885-f627-4a14-98d0-597dcc484c05','前相國贊皇公早葺平泉山居蹔還憩旋起赴詔命作鎮浙右輙抒懷賦四言詩十四首奉寄 十四','裴潾','唐','唐诗','tang','','[]','迢迢秦塞，南望吳門。',50,'全唐诗/poet.tang.27000.json','["迢迢秦塞，南望吳門。", "對酒不飲，設琴不援。", "何以代面，寄之濡翰。", "何以寫懷，詩以足言。", "無密玉音，以慰我魂。"]'),
('8db38262-c2f3-4be7-9703-e9d2869dba5e','白牡丹','裴潾','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u7261\u4e39", "\u82b1", "\u8d5e\u7f8e", "\u5199\u82b1"]','長安豪貴惜春殘，爭賞先開紫牡丹。',32,'全唐诗/poet.tang.27000.json','["長安豪貴惜春殘，爭賞先開紫牡丹。", "別有玉杯承露冷，無人起就月中看。"]'),
('e2f7f793-499a-4242-a927-9c14f34d721a','送黃明府曄赴岳州湘陰任','劉三復','唐','唐诗','tang','','[]','擬占名場第一科，龍門十上困風波。',64,'全唐诗/poet.tang.27000.json','["擬占名場第一科，龍門十上困風波。", "三年護塞從戎遠，萬里投荒失意多。", "花縣到時銅墨貴，葉舟行處水雲和。", "遙知布惠蘇民後，應向祠堂弔汨羅。"]'),
('04d70b37-7457-4ef9-8347-a3feb23f7ece','留題桂州碧潯亭','韋瓘','唐','唐诗','tang','','[]','半年領郡固無勞，一日爲心素所操。',64,'全唐诗/poet.tang.27000.json','["半年領郡固無勞，一日爲心素所操。", "輪奐未成繩墨在，規模已壯閌閎高。", "理人雖切才常短，薄宦都緣命不遭。", "從此歸耕洛川上，大千江路任風濤。"]'),
('9216018c-ffc5-4454-b218-6072a730da2c','贈毛仙翁','崔郾','唐','唐诗','tang','','[]','存亡去住一壺中，兄事安期弟葛洪。',64,'全唐诗/poet.tang.27000.json','["存亡去住一壺中，兄事安期弟葛洪。", "甲子已過千歲鶴，儀容方稱十年童。", "心靈暗合行人數，藥力潛均造化功。", "終待此身無繫累，武陵山下等黃公。"]'),
('ebd7656b-c115-4c41-8e8a-edb022103efd','鳥散餘花落','孔溫業','唐','唐诗','tang','','[]','美景春堪賞，芳園白日斜。',72,'全唐诗/poet.tang.27000.json','["美景春堪賞，芳園白日斜。", "共看飛好鳥，復見落餘花。", "來往驚翻電，經過想散霞。", "雨餘飄處處，風送滿家家。", "求友聲初去，離枝色可嗟。", "從茲時節換，誰爲惜年華。"]'),
('7ab8533b-5c3e-42ca-9617-ff5f24ae2a46','鳥散餘花落','趙存約','唐','唐诗','tang','','[]','春曉游禽集，幽庭幾樹花。',72,'全唐诗/poet.tang.27000.json','["春曉游禽集，幽庭幾樹花。", "坐來驚豔色，飛去墮晴霞。", "翅拂繁枝落，風添舞影斜。", "彩雲飄玉砌，絳雪下仙家。", "分散音初靜，凋零蘂帶葩。", "空階瞻翫久，應共惜年華。"]'),
('327f473e-94fd-494f-bc8e-b0669a774803','鳥散餘花落','竇洵直','唐','唐诗','tang','','[]','晚樹春歸後，花飛鳥下初。',72,'全唐诗/poet.tang.27000.json','["晚樹春歸後，花飛鳥下初。", "參差分羽翼，零落滿空虛。", "風外清香轉，林邊豔影疎。", "輕盈疑雪舞，髣髴似霞舒。", "萬片情難極，遷喬思有餘。", "微臣一何幸，吟賞對寒居。"]'),
('4b16521f-aac7-429d-a7d0-56e88e242f2e','公無渡河','陳標','唐','唐诗','tang','','[]','陰雲颯颯浪花愁，半度驚湍半挂舟。',64,'全唐诗/poet.tang.27000.json','["陰雲颯颯浪花愁，半度驚湍半挂舟。", "聲盡雲天君不住，命懸魚鱉妾同休。", "黛娥芳臉垂珠淚，羅襪香裾赴碧流。", "餘魄豈能銜木石，獨將遺恨付箜篌。"]'),
('41125efe-e1af-4ec9-a512-d19c6a8e47a6','秦王卷衣','陳標','唐','唐诗','tang','','[]','秦王宮闕靄春煙，珠樹瓊枝近碧天。',64,'全唐诗/poet.tang.27000.json','["秦王宮闕靄春煙，珠樹瓊枝近碧天。", "御氣馨香蘇合啓，簾光浮動水精懸。", "霏微羅縠隨芳袖，宛轉鮫鮹逐寶筵。", "從此咸陽一回首，暮雲愁色已千年。"]'),
('f0d2e822-483e-472b-b8b6-ea1f2511fbbb','倢伃怨','陳標','唐','唐诗','tang','','[]','掌上恩移玉帳空，香珠滿眼泣春風。',64,'全唐诗/poet.tang.27000.json','["掌上恩移玉帳空，香珠滿眼泣春風。", "飄零怨柳凋眉翠，狼籍愁桃墜臉紅。", "鳳輦祗應三殿北，鸞聲不向五湖中。", "笙歌處處迴天睠，獨自無情長信宮。"]'),
('750d40e3-19d7-4959-b574-307f382b2bf1','飲馬長城窟','陳標','唐','唐诗','tang','','[]','日日風吹虜騎塵，年年飲馬漢營人。',64,'全唐诗/poet.tang.27000.json','["日日風吹虜騎塵，年年飲馬漢營人。", "千堆戰骨那知主，萬里枯沙不辨春。", "浴谷氣寒愁墜指，斷崖冰滑恐傷神。", "金鞍玉勒無顏色，淚滿征衣怨暴秦。"]'),
('c7411c10-bd29-4d0b-af79-2803716eb268','江南行','陳標','唐','唐诗','tang','','[]','水光春色滿江天，蘋葉風吹荷葉錢。',64,'全唐诗/poet.tang.27000.json','["水光春色滿江天，蘋葉風吹荷葉錢。", "香蟻翠旗臨岸市，豔娥紅袖渡江船。", "曉驚白鷺聯翩雪，浪蹙青茭瀲灩煙。", "不怕江洲芳草暮，待將秋興折湖蓮。"]'),
('1ff6b9cd-d8c5-447e-8407-e76bd7a01916','長安秋思','陳標','唐','唐诗','tang','','[]','吳女秋機織曙霜，冰蠶吐絲月盈筐。',64,'全唐诗/poet.tang.27000.json','["吳女秋機織曙霜，冰蠶吐絲月盈筐。", "金刀玉指裁縫促，水殿花樓弦管長。", "舞袖慢移凝瑞雪，歌塵微動避雕梁。", "唯愁陌上芳菲度，狼籍風池荷葉黃。"]'),
('aa53dda3-bc9e-4120-9532-588ffbb47f50','贈元和十三年登第進士','陳標','唐','唐诗','tang','','[]','春官南院粉牆東，地色初分月色紅。',64,'全唐诗/poet.tang.27000.json','["春官南院粉牆東，地色初分月色紅。", "文字一千重馬擁，喜歡三十二人同。", "眼看魚變辭凡水，心逐鸚飛出瑞風。", "莫怪雲泥從此別，總曾惆悵去年中。"]'),
('1f0ec67e-c961-4b14-9244-afb3deaf1501','焦桐樹','陳標','唐','唐诗','tang','','[]','江上烹魚採野樵，鸞枝摧折半曾燒。',64,'全唐诗/poet.tang.27000.json','["江上烹魚採野樵，鸞枝摧折半曾燒。", "未經良匠材雖散，待得知音尾已焦。", "若使琢磨徽白玉，便來風律軫青瑤。", "還能萬里傳山水，三峽泉聲豈寂寥。"]'),
('b83367d1-9a67-4d05-bbdf-a2216ead707e','寄友人','陳標','唐','唐诗','tang','','[]','杜甫在時貪入蜀，孟郊生處却歸秦。',32,'全唐诗/poet.tang.27000.json','["杜甫在時貪入蜀，孟郊生處却歸秦。", "如今始會麻姑意，借問山川與後人。"]'),
('1f8c2c69-316d-4d6d-9187-609807527a05','啄木謠','陳標','唐','唐诗','tang','','[]','丁丁向晚急還稀，啄徧庭槐未肯歸。',32,'全唐诗/poet.tang.27000.json','["丁丁向晚急還稀，啄徧庭槐未肯歸。", "終日與君除蠹害，莫嫌無事不頻飛。"]'),
('98e656ec-bb25-4489-8db2-d221b39bb748','僧院牡丹','陳標','唐','唐诗','tang','','[]','琉璃地上開紅豔，碧落天頭散曉霞。',32,'全唐诗/poet.tang.27000.json','["琉璃地上開紅豔，碧落天頭散曉霞。", "應是向西無地種，不然爭肯重蓮花。"]'),
('52c95365-20d8-4e2d-a58d-14deacd1290f','蜀葵','陳標','唐','唐诗','tang','','[]','眼前無奈蜀葵何，淺紫深紅數百窠。',32,'全唐诗/poet.tang.27000.json','["眼前無奈蜀葵何，淺紫深紅數百窠。", "能共牡丹爭幾許，得人嫌處祗緣多。"]'),
('49880621-f759-4488-895f-6374b9942f7a','離家','袁不約','唐','唐诗','tang','','[]','步步遠晨昏，悽心出里門。',48,'全唐诗/poet.tang.27000.json','["步步遠晨昏，悽心出里門。", "見烏唯有淚，看雁更傷魂。", "宿酒寧辭醉，迴書諱苦言。", "野人應怪笑，不解愛田園。"]'),
('beffde01-58c8-4a91-bde5-804bf3f2d130','送人至嶺南','袁不約','唐','唐诗','tang','','[]','度嶺春風暖，花多不識名。',48,'全唐诗/poet.tang.27000.json','["度嶺春風暖，花多不識名。", "瘴煙迷月色，巴路傍溪聲。", "畏藥將銀試，防蛟避水行。", "知君憐酒興，莫殺醉猩猩。"]'),
('ac094642-ea8a-46c1-8d3d-0e9e87485163','長安夜遊','袁不約','唐','唐诗','tang','','[]','鳳城連夜九門通，帝女皇妃出漢宮。',64,'全唐诗/poet.tang.27000.json','["鳳城連夜九門通，帝女皇妃出漢宮。", "千乘寶蓮珠箔捲，萬條銀燭碧紗籠。", "歌聲緩過青樓月，香靄潛來紫陌風。", "長樂曉鐘歸騎後，遺簪墮珥滿街中。"]'),
('a316f200-b99b-454b-93ea-4954abb00df3','病宮人','袁不約','唐','唐诗','tang','','[]','佳人臥病動經秋，簾幕繿縿不挂鉤。',64,'全唐诗/poet.tang.27000.json','["佳人臥病動經秋，簾幕繿縿不挂鉤。", "四體強扶藤夾膝，雙環慵整玉搔頭。", "花顏有幸君王問，藥餌無徵待詔愁。", "惆悵近來銷瘦盡，淚珠時傍枕函流。"]'),
('e96befc1-4720-43ef-9d8f-7d6cb9a85965','句','袁不約','唐','唐诗','tang','','[]','愁聲秋遶杵，寒色碧歸山。',24,'全唐诗/poet.tang.27000.json','["愁聲秋遶杵，寒色碧歸山。", "送將歡笑去，收得寂寥迴。"]'),
('4a7c1be7-94fb-41bc-bd71-8e21092d8f7e','臨邛怨','李餘','唐','唐诗','tang','','[]','藕花衫子柳花裙，多著沈香慢火熏。',32,'全唐诗/poet.tang.27000.json','["藕花衫子柳花裙，多著沈香慢火熏。", "惆悵妝成君不見，空教綠綺伴文君。"]'),
('e1dc8b61-78d2-4f2b-8ffa-eebb5c1bbd2a','寒食','李餘','唐','唐诗','tang','','[]','玉輪江上雨絲絲，公子游春醉不知。',32,'全唐诗/poet.tang.27000.json','["玉輪江上雨絲絲，公子游春醉不知。", "翦渡歸來風正急，水濺鞍帕嫩鵝兒。"]'),
('a6511baa-020e-4819-b1e0-bb23c2585784','句','李餘','唐','唐诗','tang','','[]','長安東門別，立馬生白髮。',36,'全唐诗/poet.tang.27000.json','["長安東門別，立馬生白髮。", "霽後軒蓋繁，南山瑞煙發。", "嘗憂車馬繁，土薄聞水聲。"]'),
('93b4bffb-52b5-4113-82e4-f5aac785bdc2','至日上公獻壽酒','白敏中','唐','唐诗','tang','','[]','候曉天門闢，朝天萬國同。',72,'全唐诗/poet.tang.27000.json','["候曉天門闢，朝天萬國同。", "瑞雲昇觀闕，香氣映華宮。", "日色臨仙籞，龍顏對昊宮。", "羽儀瞻百姓，獻壽侍三公。", "化被君王洽，恩沾草木豐。", "自欣朝玉座，宴此詠皇風。"]'),
('d4bba55e-36f1-47d1-96af-eb87264434f6','賀收復秦原諸州詩','白敏中','唐','唐诗','tang','','[]','一詔皇城四海頒，醜戎無數束身還。',64,'全唐诗/poet.tang.27000.json','["一詔皇城四海頒，醜戎無數束身還。", "戍樓吹笛人休戰，牧野嘶風馬自閑。", "河水九盤收數曲，天山千里鎖諸關。", "西邊北塞今無事，爲報東南夷與蠻。"]'),
('20db07ba-120a-426d-838f-7ff655ffb14a','句','白敏中','唐','唐诗','tang','','[]','南浦花臨水，東樓月映風。',12,'全唐诗/poet.tang.27000.json','["南浦花臨水，東樓月映風。"]'),
('1cbb84c4-b751-49c1-a0a1-ee46f60150cb','遣興','李敬方','唐','唐诗','tang','','[]','果窺丹竈鶴，莫羨白頭翁。',48,'全唐诗/poet.tang.27000.json','["果窺丹竈鶴，莫羨白頭翁。", "日月仙壺外，筋骸藥臼中。", "雲歸無定所，鳥跡不留空。", "何必勞方寸，嶇岐問遠公。"]'),
('f6e67006-ceb4-4603-8276-ad9a416280a1','勸酒','李敬方','唐','唐诗','tang','','[]','不向花前醉，花應解笑人。',48,'全唐诗/poet.tang.27000.json','["不向花前醉，花應解笑人。", "只憂連夜雨，又過一年春。", "日日無窮事，區區有限身。", "若非杯酒裏，何以寄天真。"]'),
('e5f2c534-509d-4899-b3e1-fcb17302f62e','近無西耗','李敬方','唐','唐诗','tang','','[]','遠戎兵壓境，遷客淚橫襟。',48,'全唐诗/poet.tang.27000.json','["遠戎兵壓境，遷客淚橫襟。", "烽候驚春塞，縲囚困越吟。", "自憐牛馬走，未識犬羊心。", "一月無消息，西看日又沈。"]'),
('5ce5402d-3d97-44e8-ad57-0d342ca62ff0','天台晴望','李敬方','唐','唐诗','tang','','[]','天台十二旬，一片雨中春。',48,'全唐诗/poet.tang.27000.json','["天台十二旬，一片雨中春。", "林果黃梅盡，山苗半夏新。", "陽烏晴展翅，陰魄夜飛輪。", "坐冀無雲物，分明見北辰。"]'),
('d48bf7cb-11ad-4a5a-9143-623e60d88bee','聞高侍御卒貶所','李敬方','唐','唐诗','tang','','[]','西京高院長，直氣似吾徒。',48,'全唐诗/poet.tang.27000.json','["西京高院長，直氣似吾徒。", "走馬論邊備，飛聲感廟謨。", "官移人未察，身沒事多符。", "寂寞他年後，名編野史無。"]'),
('fbb98348-1e82-4ddb-a67c-730c3fe2c4a6','題黃山湯院','李敬方','唐','唐诗','tang','','["\u9ec4\u5c71"]','楚鎮惟黃岫，靈泉浴聖源。',288,'全唐诗/poet.tang.27000.json','["楚鎮惟黃岫，靈泉浴聖源。", "煎熬何處所，爐炭孰司存。", "沙暖泉長拂，霜籠水更溫。", "不疏還自決，雖撓未嘗渾。", "地啓巖爲洞，天開石作盆。", "常留今日色，不減故年痕。", "陰燄潛生海，陽光暗燭坤。", "定應鄰火宅，非獨過焦原。", "龍訝經冬潤，鶯疑滿谷暄。", "善烹寒食茗，能變早春園。", "及物功何大，隨流道益尊。", "潔齋齊物主，療病奪醫門。", "外祕千峰秀，旁通百潦奔。", "禪家休問疾，騷客罷招魂。", "臥理黔川守，分憂漢主恩。", "慘傷因有暇，徒御誡無諠。", "癢悶頭風切，爬搔臂力煩。", "披榛通白道，束馬置朱幡。", "謝屐緣危磴，戎裝逗遠村。", "慢遊登竹逕，高步入山根。", "崖巘差行竈，蓬茅過小軒。", "禦寒增帳幕，甃影盡璵璠。", "不與華池語，寧將浴室論。", "洗心過頃刻，浸髮迨朝暾。"]'),
('8c14ddec-9711-4b61-a787-46668fa5d259','太和公主還宮','李敬方','唐','唐诗','tang','','[]','二紀煙塵外，淒涼轉戰歸。',120,'全唐诗/poet.tang.27000.json','["二紀煙塵外，淒涼轉戰歸。", "胡笳悲蔡琰，漢使泣明妃。", "金殿更戎幄，青祛換毳衣。", "登車隨伴仗，謁廟入中闈。", "湯沐疏封在，關山故夢非。", "笑看鴻北向，休詠鵲南飛。", "宮髻憐新樣，庭柯想舊圍。", "生還侍兒少，熟識內家稀。", "鳳去樓扃夜，鸞孤匣掩輝。", "應憐禁園柳，相見倍依依。"]'),
('4998095e-bf24-490a-9ba0-6875b0ab5b4e','汴河直進船','李敬方','唐','唐诗','tang','','[]','汴水通淮利最多，生人爲害亦相和。',32,'全唐诗/poet.tang.27000.json','["汴水通淮利最多，生人爲害亦相和。", "東南四十三州地，取盡脂膏是此河。"]'),
('d0ce935b-6fb7-479d-84db-527c3a1ecd47','享太廟樂章','李回','唐','唐诗','tang','','[]','受天明命，敷祐下土。',40,'全唐诗/poet.tang.27000.json','["受天明命，敷祐下土。", "化時以儉，衛文以武。", "氛消夷夏，俗臻往古。", "億萬斯年，形于律呂。"]'),
('1a666655-aac5-480c-8bbc-256123fa35ec','天長路別朱大山路却寄','李回','唐','唐诗','tang','','[]','驛騎難隨伴，尋山半憶君。',24,'全唐诗/poet.tang.27000.json','["驛騎難隨伴，尋山半憶君。", "蒼崖殘月路，猶數過溪雲。"]'),
('87c8a7a7-08a6-487b-9723-221a5a15a2f8','寄酬朱大後亭夜坐留別','李回','唐','唐诗','tang','','[]','十夜郡城宿，苦吟身未閑。',24,'全唐诗/poet.tang.27000.json','["十夜郡城宿，苦吟身未閑。", "那堪西郭別，雪路問青山。"]'),
('6a0e2208-37cc-4313-9fbc-bb5f834ad559','祖龍行','常楚老','唐','唐诗','tang','','[]','黑雲兵氣射天裂，壯士朝眠夢冤結。',96,'全唐诗/poet.tang.27000.json','["黑雲兵氣射天裂，壯士朝眠夢冤結。", "祖龍一夜死沙丘，胡亥空隨鮑魚轍。", "腐肉偷生三千里，僞書先賜扶蘇死。", "墓接驪山土未乾，瑞光已向芒碭起。", "陳勝城中鼓三下，秦家天地如崩瓦。", "龍蛇撩亂入咸陽，少帝空隨漢家馬。"]'),
('7e9d95f2-d6df-47b8-8283-86fa0a5ba640','江上蚊子','常楚老','唐','唐诗','tang','','[]','飄搖挾翅亞紅腹，江邊夜起如雷哭。',64,'全唐诗/poet.tang.27000.json','["飄搖挾翅亞紅腹，江邊夜起如雷哭。", "請問貪婪一點心，臭腐填腹幾多足。", "越女如花住江曲，嫦娥夜夜凝雙睩。", "怕君撩亂錦窗中，十軸輕綃圍夜玉。"]'),
('5595fd94-857f-40c4-b6a3-7f4bc28ebac3','句','常楚老','唐','唐诗','tang','','[]','一從黃帝葬橋山，碧落千門鎖元氣。',16,'全唐诗/poet.tang.27000.json','["一從黃帝葬橋山，碧落千門鎖元氣。"]'),
('14a78771-6e96-4a41-955b-825661ba6e8e','九成宮','李甘','唐','唐诗','tang','','[]','中原無鹿海無波，鳳輦鸞旗出幸多。',32,'全唐诗/poet.tang.27000.json','["中原無鹿海無波，鳳輦鸞旗出幸多。", "今日故宮歸寂寞，太平功業在山河。"]'),
('6643e428-7022-4038-a724-f4f9c9eaa688','謁李相不遇','平曾','唐','唐诗','tang','','[]','老夫三日門前立，珠箔銀屏晝不開。',32,'全唐诗/poet.tang.27000.json','["老夫三日門前立，珠箔銀屏晝不開。", "詩卷却拋書袋裏，正如閑看華山來。"]'),
('b4f2bb85-098c-4d92-a22d-83d3651363e1','留別薛僕射','平曾','唐','唐诗','tang','','[]','梯山航海幾崎嶇，來謁金陵薜大夫。',64,'全唐诗/poet.tang.27000.json','["梯山航海幾崎嶇，來謁金陵薜大夫。", "毛髮豎時趨劍戟，衣冠儼處拜冰壺。", "誠知兩軸非珠玉，深愧三縑卹旅途。", "明日過江風景好，不堪回首望勾吳。"]'),
('f00cec8f-0bd0-445c-9f34-109ca43f6fb4','縶白馬詩上薛僕射','平曾','唐','唐诗','tang','','[]','白馬披鬃練一團，今朝被絆欲行難。',64,'全唐诗/poet.tang.27000.json','["白馬披鬃練一團，今朝被絆欲行難。", "雪中放去空留跡，月下牽來只見鞍。", "向北長鳴天外遠，臨風斜控耳邊寒。", "自知毛骨還應異，更請孫陽仔細看。"]'),
('55ccb79d-a131-4c08-90da-ae2531029052','題所書黃庭經後','景審','唐','唐诗','tang','','[]','金粉爲書重莫過，黃庭舊許右軍多。',32,'全唐诗/poet.tang.27000.json','["金粉爲書重莫過，黃庭舊許右軍多。", "請看今日酬恩德，何似當年爲愛鵝。"]'),
('6c291074-44f3-4016-bd13-67ab68122dcb','句','景審','唐','唐诗','tang','','[]','暮鵶不噪禁城樹，衙鼓未殘兵衛秋。',16,'全唐诗/poet.tang.27000.json','["暮鵶不噪禁城樹，衙鼓未殘兵衛秋。"]'),
('462d6218-3edd-44ee-a584-e078fea3c365','秋日陝州道中作','顧非熊','唐','唐诗','tang','','[]','孤客秋風裏，驅車入陝西。',48,'全唐诗/poet.tang.27000.json','["孤客秋風裏，驅車入陝西。", "關河午時路，村落一聲雞。", "樹勢標秦遠，天形到岳低。", "誰知我名姓，來往自栖栖。"]'),
('6a833ddf-9889-4067-bf1a-45b7b187c0fd','經杭州','顧非熊','唐','唐诗','tang','','[]','郡郭遶江濆，人家近白雲。',48,'全唐诗/poet.tang.27000.json','["郡郭遶江濆，人家近白雲。", "晚濤臨檻看，夜艣隔城聞。", "浦轉山初盡，虹斜雨未分。", "有誰知我意，心緒逐鷗羣。"]'),
('ba22eeae-0625-4534-977d-3f5e63b7ba6e','經河中','顧非熊','唐','唐诗','tang','','[]','一望蒲城路，關河氣象雄。',48,'全唐诗/poet.tang.27000.json','["一望蒲城路，關河氣象雄。", "樓臺山色裏，楊柳水聲中。", "思起懷吳客，行斜向磧鴻。", "我來尋古跡，唯見舜祠風。"]'),
('ae82846d-b8a4-4953-9aa5-2ae5fd822323','送僧歸洞庭','顧非熊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','江山萬萬重，歸去指何峰。',48,'全唐诗/poet.tang.27000.json','["江山萬萬重，歸去指何峰。", "未入連雲寺，先齋越浪鐘。", "島香廻棧柏，秋蔭出菴松。", "若救吳人病，須降震澤龍。"]'),
('59d616a3-3626-481a-b728-a30d28372228','題覺真上人院','顧非熊','唐','唐诗','tang','','[]','長安車馬地，此院閉松聲。',48,'全唐诗/poet.tang.27000.json','["長安車馬地，此院閉松聲。", "新罷九天講，舊曾諸岳行。", "能詩因作偈，好客豈關名。", "約我中秋夜，同來看月明。"]'),
('30bb32f9-cef8-460c-83ca-4cefa88d0311','寄太白無能禪師','顧非熊','唐','唐诗','tang','','[]','太白山中寺，師居最上方。',48,'全唐诗/poet.tang.27000.json','["太白山中寺，師居最上方。", "獵人偷佛火，櫟鼠戲禪牀。", "定久衣塵積，行稀徑草長。", "有誰來問法，林杪過殘陽。"]'),
('70880198-cb59-423f-be2c-a8ee0186c257','舒州酬別侍御','顧非熊','唐','唐诗','tang','','[]','故交他郡見，下馬失愁容。',48,'全唐诗/poet.tang.27000.json','["故交他郡見，下馬失愁容。", "執手向殘日，分襟在晚鐘。", "鄉心隨皖水，客路過廬峰。", "衆惜君材器，何爲滯所從。"]'),
('f9d3f1a2-135b-4f5b-b415-265d68ed4b46','姚巖寺路懷友','顧非熊','唐','唐诗','tang','','[]','路向姚巖寺，多行洞壑間。',48,'全唐诗/poet.tang.27000.json','["路向姚巖寺，多行洞壑間。", "鶴聲連塢靜，溪色帶村閑。", "疎葉秋前渚，斜陽雨外山。", "憐君不得見，詩思最相關。"]'),
('98a535a0-c89a-4b3a-8608-94c387832330','天河閣到啼猿閣即事','顧非熊','唐','唐诗','tang','','[]','萬壑褒中路，何層不架虛。',48,'全唐诗/poet.tang.27000.json','["萬壑褒中路，何層不架虛。", "濕雲和棧起，燋枿帶畬餘。", "巖狖牽垂果，湍禽接迸魚。", "每逢維艇處，塢裏有人居。"]'),
('3fbf3e9a-0166-4b1d-a29f-e32fa46121a7','夏日會修行段將軍宅','顧非熊','唐','唐诗','tang','','[]','愛君書院靜，莎覆蘚堦濃。',48,'全唐诗/poet.tang.27000.json','["愛君書院靜，莎覆蘚堦濃。", "連穗古藤暗，領雛幽鳥重。", "罇前迎遠客，林杪見晴峰。", "誰謂朱門內，雲山滿座逢。"]'),
('3d165e01-7f1a-4613-b33e-b3367ba85618','送杭州姚員外','顧非熊','唐','唐诗','tang','','[]','浙江江上郡，楊柳到時春。',48,'全唐诗/poet.tang.27000.json','["浙江江上郡，楊柳到時春。", "塹起背城雁，帆分向海人。", "嶠雲侵寺吐，汀月隔樓新。", "靜理更何事，還應詠白蘋。"]'),
('35b3e1af-53dd-4467-a400-111e188da1e4','送樸處士歸新羅','顧非熊','唐','唐诗','tang','','[]','少年離本國，今去已成翁。',48,'全唐诗/poet.tang.27000.json','["少年離本國，今去已成翁。", "客夢孤舟裏，鄉山積水東。", "鼇沈崩巨岸，龍鬬出遙空。", "學得中華語，將歸誰與同。"]'),
('4807ca9e-4a1e-4ea2-bd8e-272b6a2ca841','送馬戴入山','顧非熊','唐','唐诗','tang','','[]','古木亂重重，何人識去蹤。',48,'全唐诗/poet.tang.27000.json','["古木亂重重，何人識去蹤。", "斜陽收萬壑，圓月上三峰。", "雲裏泉縈石，窗間鳥下松。", "唯應採藥客，時與此相逢。"]'),
('65143889-00bd-425a-b7a2-6baaac3d266c','送喻鳧春歸江南','顧非熊','唐','唐诗','tang','','[]','去年登第客，今日及春歸。',48,'全唐诗/poet.tang.27000.json','["去年登第客，今日及春歸。", "鸎影離秦馬，蓮香入楚衣。", "里閭爭慶賀，親戚共光輝。", "唯我門前浦，苔應滿釣磯。"]'),
('4ac52a18-6505-422d-85d4-91dbb897e635','送友人及第歸蘇州','顧非熊','唐','唐诗','tang','','[]','見君先得意，希我命還通。',48,'全唐诗/poet.tang.27000.json','["見君先得意，希我命還通。", "不道才堪竝，多緣蹇共同。", "鶴鳴荒苑內，魚躍夜潮中。", "若問家山路，知連震澤東。"]'),
('72507a26-8c45-4583-9a0b-3165f97d31d5','送皇甫司錄赴黔南幕','顧非熊','唐','唐诗','tang','','[]','黔南從事客，祿利先來饒。',48,'全唐诗/poet.tang.27000.json','["黔南從事客，祿利先來饒。", "官受外臺屈，家移一舸遙。", "夜猿聲不斷，寒木葉微凋。", "遠別因多感，新郎倍寂寥。"]'),
('571faa2b-1ed9-4c49-a8e1-ab59e7d87e6d','寄九華山費拾遺','顧非熊','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','先生九華隱，鳥道隔塵埃。',48,'全唐诗/poet.tang.27000.json','["先生九華隱，鳥道隔塵埃。", "石室和雲住，山田引燒開。", "久閑仙客降，高臥詔書來。", "一入深林去，人間更不回。"]'),
('9c013fd6-7acb-4efc-bda6-9bb3cd816e69','雁','顧非熊','唐','唐诗','tang','','[]','逐暖來南國，迎寒背朔雲。',48,'全唐诗/poet.tang.27000.json','["逐暖來南國，迎寒背朔雲。", "下時波勢出，起處陣形分。", "聲急奔前侶，行低續後羣。", "何人寄書札，絕域可知聞。"]'),
('e2e459be-e53f-49a3-8ee3-9a061e162da8','銅雀妓','顧非熊','唐','唐诗','tang','','[]','鴉散陵樹曉，筵開繐帳空。',48,'全唐诗/poet.tang.27000.json','["鴉散陵樹曉，筵開繐帳空。", "嬋娟寵休妬，歌舞怨來同。", "往事與塵化，新愁生曲終。", "廻軒葉正落，寂寞聽秋風。"]'),
('ea053580-a756-41f5-9531-7abc470d5b50','早秋雨夕','顧非熊','唐','唐诗','tang','','[]','貧居常寂寞，況復是秋天。',48,'全唐诗/poet.tang.27000.json','["貧居常寂寞，況復是秋天。", "黃葉如霜後，清風似水邊。", "中宵疑有雁，當夕暫無蟬。", "就枕終難寐，殘燈滅又然。"]'),
('b76e6627-d4aa-45e2-b056-525e4084bb05','天津橋晚望','顧非熊','唐','唐诗','tang','','[]','晴登洛橋望，寒色古槐稀。',48,'全唐诗/poet.tang.27000.json','["晴登洛橋望，寒色古槐稀。", "流水東不息，翠華西未歸。", "雲收中岳近，鐘出後宮微。", "回首禁門路，羣鴉度落暉。"]'),
('74aa45bf-6bb4-46db-a84c-cd3bce479407','月夜登王屋仙壇','顧非熊','唐','唐诗','tang','','[]','月臨峰頂壇，氣爽覺天寬。',48,'全唐诗/poet.tang.27000.json','["月臨峰頂壇，氣爽覺天寬。", "身去銀河近，衣霑玉露寒。", "雲中日已赤，山外夜初殘。", "即此是仙境，惟愁再上難。"]'),
('d1df20c1-6f20-4553-9f8a-37a0042b0d97','下第後曉坐','顧非熊','唐','唐诗','tang','','[]','遠客滯都邑，老驚時節催。',48,'全唐诗/poet.tang.27000.json','["遠客滯都邑，老驚時節催。", "海邊身夢覺，枕上鼓聲來。", "起見銀河沒，坐知閶闔開。", "何爲此生內，終夜泣塵埃。"]'),
('ac9f79da-507c-49ed-ae85-4089011076fd','下第後送友人不及','顧非熊','唐','唐诗','tang','','[]','失意經寒食，情偏感別離。',48,'全唐诗/poet.tang.27000.json','["失意經寒食，情偏感別離。", "來逢人已去，坐見柳空垂。", "細雨飛黃鳥，新蒲長綠池。", "自傾相送酒，終不展愁眉。"]'),
('d4102d77-4c1e-40f4-855d-f5a5f80c09c8','與無可宿輝公院','顧非熊','唐','唐诗','tang','','[]','夜僧同靜語，秋寺近嚴城。',48,'全唐诗/poet.tang.27000.json','["夜僧同靜語，秋寺近嚴城。", "世路雖多梗，玄心各自明。", "寒池清月彩，危閣聽林聲。", "儻許雙摩頂，隨緣萬劫生。"]'),
('8bb1c792-6718-4fb5-947e-aec175243207','題平陸縣亭','顧非熊','唐','唐诗','tang','','[]','孤亭臨峭岸，別有遠泉來。',48,'全唐诗/poet.tang.27000.json','["孤亭臨峭岸，別有遠泉來。", "山與中條合，河逢一曲廻。", "夜聲多鴈過，晚色亂雲開。", "却自求僮僕，淹留莫謾催。"]'),
('1645b1be-4692-455c-a948-94fbcb57936f','題馬儒乂石門山居','顧非熊','唐','唐诗','tang','','[]','尋君石門隱，山近漸無青。',48,'全唐诗/poet.tang.27000.json','["尋君石門隱，山近漸無青。", "鹿迹入柴戶，樹身穿草亭。", "雲低收藥徑，苔惹取泉瓶。", "此地客難到，夜琴誰共聽。"]'),
('1d7aa4de-e3ba-4770-ba90-be2c7956b837','題春明門外鎮國禪院','顧非熊','唐','唐诗','tang','','[]','空門臨大道，師坐此中禪。',48,'全唐诗/poet.tang.27000.json','["空門臨大道，師坐此中禪。", "過客自生敬，焚香惟默然。", "書燈明象外，古木覆簷前。", "不得如馴鴿，人間萬慮牽。"]'),
('7a25aee5-0a7f-49a7-b5b7-034ce360ef72','夏夜漢渚歸舟即事','顧非熊','唐','唐诗','tang','','[]','扁舟江瀨盡，歸路海山青。',48,'全唐诗/poet.tang.27000.json','["扁舟江瀨盡，歸路海山青。", "巨浸分圓象，危檣入衆星。", "雨遙明電影，蜃曉識樓形。", "不是長遊客，那知造化靈。"]'),
('9a20e634-9863-4185-b537-edd1e01a71df','酬均州鄭使君見送歸茅山','顧非熊','唐','唐诗','tang','','[]','餞行詩意厚，惜別獨筵重。',48,'全唐诗/poet.tang.27000.json','["餞行詩意厚，惜別獨筵重。", "解纜城邊柳，還舟海上峰。", "飲猨當瀨見，浴鳥帶槎逢。", "吏隱應難逐，爲霖是蟄龍。"]'),
('894d9db6-e2b7-46af-835b-0e2e9b992978','成名後將歸茅山酬羣公見送','顧非熊','唐','唐诗','tang','','[]','此名誰不得，人賀至公難。',48,'全唐诗/poet.tang.27000.json','["此名誰不得，人賀至公難。", "素業承家了，離筵去國歡。", "暮天行鴈斷，曉渡落潮寒。", "舊隱茅峰下，松根石上盤。"]'),
('71f2bab5-2f0e-42d2-a7c5-f0853419245e','酬陳摽評事喜及第與段何共貽','顧非熊','唐','唐诗','tang','','[]','至公平得意，自喜不因媒。',48,'全唐诗/poet.tang.27000.json','["至公平得意，自喜不因媒。", "榜入金門去，名從玉案來。", "歡情聽鳥語，笑眼對花開。", "若擬華筵賀，當期醉百杯。"]'),
('152722a1-b480-48bf-b3d7-2083ade96b17','關試後嘉會里聞蟬感懷呈主司','顧非熊','唐','唐诗','tang','','[]','昔聞驚節換，常抱異鄉愁。',48,'全唐诗/poet.tang.27000.json','["昔聞驚節換，常抱異鄉愁。", "今聽當命遂，方歡上國遊。", "吟纔依樹午，風已報庭秋。", "併覺聲聲好，懷恩忽淚流。"]'),
('5e03dc4c-6db3-48e5-b47f-a89a4214f898','贈友人','顧非熊','唐','唐诗','tang','','[]','吾友昔同道，唯予今獨行。',48,'全唐诗/poet.tang.27000.json','["吾友昔同道，唯予今獨行。", "青雲期未遂，白髮鑷還生。", "舊隱連江色，新春聞鳥聲。", "休明獨不遇，何計可歸耕。"]'),
('ecbccaaf-604e-4df9-8bf8-285d371bf887','落第後贈同居友人','顧非熊','唐','唐诗','tang','','[]','有情天地內，多感是詩人。',48,'全唐诗/poet.tang.27000.json','["有情天地內，多感是詩人。", "見月長憐夜，看花又惜春。", "愁爲終日客，閑過少年身。", "寂寞正相對，笙歌滿四隣。"]'),
('c2ad0f7e-30f4-4a96-bf9c-833665e0000c','冬日寄蔡先輩校書京','顧非熊','唐','唐诗','tang','','[]','弱冠下茅嶺，中年道不行。',48,'全唐诗/poet.tang.27000.json','["弱冠下茅嶺，中年道不行。", "舊交因貴絕，新月對愁生。", "旅思風飄葉，歸心鴈過城。", "惟君知我苦，何異爨桐鳴。"]'),
('a3436a72-fd4a-4a92-accd-7b2c33867904','行經褒城寄興元姚從事','顧非熊','唐','唐诗','tang','','[]','往歲客龜城，同時聽鹿鳴。',48,'全唐诗/poet.tang.27000.json','["往歲客龜城，同時聽鹿鳴。", "君兼蓮幕貴，我得桂枝榮。", "棧閣危初盡，褒川路忽平。", "心期一壺酒，靜話別離情。"]'),
('24cff053-e2d3-4f40-965d-2644f80d2672','下第後寄高山人','顧非熊','唐','唐诗','tang','','[]','我家堂屋前，仰視大茅巔。',48,'全唐诗/poet.tang.27000.json','["我家堂屋前，仰視大茅巔。", "潭靜鳥聲異，地寒松色鮮。", "人眠甕牖月，鹿飲竹門泉。", "多愧隣高隱，無成又一年。"]'),
('6e9cdf55-65fc-4815-9eb7-4dbdd6425c20','寄紫閣無名新羅頭陁僧','顧非熊','唐','唐诗','tang','','[]','椶牀已自檠，野宿更何營。',48,'全唐诗/poet.tang.27000.json','["椶牀已自檠，野宿更何營。", "大海誰同過，空山虎共行。", "身心相外盡，鬢髮定中生。", "紫閣人來禮，無名便是名。"]'),
('9c61a0ce-0130-4d5b-a6c1-6a8296dde9ba','送信州盧員外兼寄薛員外','顧非熊','唐','唐诗','tang','','[]','五馬弋陽行，分憂出禁城。',48,'全唐诗/poet.tang.27000.json','["五馬弋陽行，分憂出禁城。", "粉闈移席近，茜斾越疆行。", "德茂榮方漸，仁深瑞必呈。", "疲甿復何幸，前政已殘聲。"]'),
('b5220845-b6b9-4327-86a1-2c58c48d7a23','送于中丞入回鶻','顧非熊','唐','唐诗','tang','','[]','風沙萬里行，邊色看雙旌。',48,'全唐诗/poet.tang.27000.json','["風沙萬里行，邊色看雙旌。", "去展中華禮，將安外國情。", "朝衣驚異俗，牙帳見新正。", "料得歸來路，春深草未生。"]'),
('5a383e0e-2404-4585-b685-0245c23de770','送李廓侍御赴劒南','顧非熊','唐','唐诗','tang','','[]','鳥道見狼烟，元戎正急賢。',48,'全唐诗/poet.tang.27000.json','["鳥道見狼烟，元戎正急賢。", "圖書借朋友，吟詠入戈鋋。", "山色城池近，江聲鼓角連。", "不應誇戰勝，知在檄蠻篇。"]'),
('d7775da5-6f26-4781-80be-677510850259','送友人歸漢陽','顧非熊','唐','唐诗','tang','','[]','罇前別楚客，雲水思縈回。',48,'全唐诗/poet.tang.27000.json','["罇前別楚客，雲水思縈回。", "秦野春將盡，商山花不開。", "鷗驚帆乍起，虹見雨初來。", "自有歸期在，蟬聲處處催。"]'),
('2910c9db-1ce2-4a42-b4ec-7669cfb5b967','送造微上人歸淮南覲兄','顧非熊','唐','唐诗','tang','','[]','到家方坐夏，柳巷對兄禪。',48,'全唐诗/poet.tang.27000.json','["到家方坐夏，柳巷對兄禪。", "雨斷蕪城路，虹分建鄴天。", "赴齋隨野鶴，迎水上漁船。", "終擬歸何處，三湘思渺然。"]'),
('0dff8f05-a6cc-49ba-8b87-db263a7e2f49','賦得江邊柳送陳許郭員外','顧非熊','唐','唐诗','tang','','[]','拂水復含烟，行分古岸邊。',48,'全唐诗/poet.tang.27000.json','["拂水復含烟，行分古岸邊。", "春風正搖落，客思共悠然。", "絮急頻縈水，根靈復繫船。", "微陰覆離岸，祗此醉昏眠。"]'),
('a70e8419-16cf-4659-bb08-e332052b260d','武宗挽歌詞二首 一','顧非熊','唐','唐诗','tang','','[]','睿略皇威遠，英風帝業開。',48,'全唐诗/poet.tang.27000.json','["睿略皇威遠，英風帝業開。", "竹林方受位，薤露忽興哀。", "靜塞妖星落，和戎貴主回。", "龍髯不可附，空見望仙臺。"]'),
('945847a2-6416-4cb4-a46a-b7e11f75a877','武宗挽歌詞二首 二','顧非熊','唐','唐诗','tang','','[]','蒼生期漸泰，皇道欲中興。',48,'全唐诗/poet.tang.27000.json','["蒼生期漸泰，皇道欲中興。", "國用銷靈像，農功復冗僧。", "冕旒辭北闕，歌舞怨西陵。", "惟有金莖石，長宵對玉繩。"]'),
('22944186-b56a-4335-a289-b4ba2fe5a2de','會中賦得新年','顧非熊','唐','唐诗','tang','','[]','萬古如昨日，一年加一晨。',48,'全唐诗/poet.tang.27000.json','["萬古如昨日，一年加一晨。", "暗生無限事，潛老幾多人。", "歸路舊侶盡，故鄉回鴈新。", "那堪獨惆悵，猶是白衣身。"]'),
('978f03f8-0946-4895-a5a4-cfd25760357e','斜谷郵亭翫海棠花','顧非熊','唐','唐诗','tang','','[]','忽識海棠花，令人只嘆嗟。',48,'全唐诗/poet.tang.27000.json','["忽識海棠花，令人只嘆嗟。", "豔繁惟共笑，香近試堪誇。", "駐騎忘山險，持盃任日斜。", "何川是多處，應遶羽人家。"]'),
('5819c12f-8c4d-4dea-b268-b080f64b2336','萬年厲員外宅殘菊','顧非熊','唐','唐诗','tang','','[]','纔過重陽後，人心已爲殘。',48,'全唐诗/poet.tang.27000.json','["纔過重陽後，人心已爲殘。", "近霜須苦惜，帶蝶更宜看。", "色減頻經雨，香銷恐漸寒。", "今朝陶令宅，不醉却應難。"]'),
('f91844ad-5f1a-497e-8ac2-a34ca80f2dbf','題永福寺臨淮亭','顧非熊','唐','唐诗','tang','','[]','淮上前朝寺，因公始建亭。',120,'全唐诗/poet.tang.27000.json','["淮上前朝寺，因公始建亭。", "雖無山可望，多有鶴堪聽。", "引客閑垂釣，看僧靜灌瓶。", "帶潮秋見月，隔竹曉聞經。", "水氣侵衣冷，蘋風入座馨。", "路逢沙獺上，船值海人停。", "砧杵鳴孤戍，烏鳶下遠汀。", "連波芳草闊，極目暮天青。", "創置嗟心匠，幽棲得地形。", "常來勸農事，賴此近郊坰。"]'),
('401d8485-e00c-4420-8c01-176113b98163','陳情上鄭主司','顧非熊','唐','唐诗','tang','','[]','登第久無緣，歸情思渺然。',168,'全唐诗/poet.tang.27000.json','["登第久無緣，歸情思渺然。", "藝慙公道日，身賤太平年。", "未識笙歌樂，虛逢歲月遷。", "羈懷吟獨苦，愁眼媿花妍。", "求達非榮己，修辭欲繼先。", "秦城春十二，吳苑路三千。", "茅屋山嵐入，柴門海浪連。", "遙心猶送鴈，歸夢不離船。", "時節思家夜，風霜作客天。", "庭闈乖旦暮，兄弟阻團圓。", "朝乏新知己，邨荒舊業田。", "受恩期望外，效死誓生前。", "願察爲裘意，彷徉和角篇。", "懇情今吐盡，萬一冀哀憐。"]'),
('17273c57-8d1d-4dfd-8d46-273697da0462','長安清明言懷','顧非熊','唐','唐诗','tang','','[]','明時帝里遇清明，還逐遊人出禁城。',64,'全唐诗/poet.tang.27000.json','["明時帝里遇清明，還逐遊人出禁城。", "九陌芳菲鶯自囀，萬家車馬雨初晴。", "客中下第逢今日，愁裏看花厭此生。", "春色來年誰是主，不堪憔悴更無成。"]'),
('7eb7142a-8529-4fac-8308-c40996337356','出塞即事二首 一','顧非熊','唐','唐诗','tang','','[]','塞山行盡到烏延，萬頃沙堆見極邊。',64,'全唐诗/poet.tang.27000.json','["塞山行盡到烏延，萬頃沙堆見極邊。", "河上月沉鴻鴈起，磧中風度犬羊膻。", "席箕草斷城池外，護柳花開帳幕前。", "此處遊人堪下淚，更聞終日望狼烟。"]'),
('b5126186-6248-4359-a003-cee5aad85f1b','出塞即事二首 二','顧非熊','唐','唐诗','tang','','[]','賀蘭山便是戎疆，此去蕭關路幾荒。',64,'全唐诗/poet.tang.27000.json','["賀蘭山便是戎疆，此去蕭關路幾荒。", "無限城池非漢界，幾多人物在胡鄉。", "諸侯持節望吾土，男子生身負我唐。", "廻望風光成異域，誰能獻計復河湟。"]'),
('412b137e-0bdc-42f5-a863-0fe505d7a332','送李相公昭義平復起彼宣慰員外副行','顧非熊','唐','唐诗','tang','','[]','天井雖收寇未平，所司促戰急王程。',64,'全唐诗/poet.tang.27000.json','["天井雖收寇未平，所司促戰急王程。", "曉馳雲騎穿花去，夜與星郎帶月行。", "新詠盡題關外事，故鄉因過洛陽城。", "時逢寒食遊人識，竟說從來有大名。"]'),
('c0069d54-3182-46ff-95f5-53ccdbd0114d','送從叔尉澠池','顧非熊','唐','唐诗','tang','','[]','同登科第皆清列，尚愛東畿一尉閑。',64,'全唐诗/poet.tang.27000.json','["同登科第皆清列，尚愛東畿一尉閑。", "雖有田園供海畔，且無宗黨在朝班。", "甘貧只爲心知道，晚達多緣性好山。", "白首青衫猶未換，又騎羸馬出函關。"]'),
('0c1f1e51-d8a6-4ee8-b7e7-13f914a471e9','哭韓將軍','顧非熊','唐','唐诗','tang','','[]','將軍不復見儀形，笑語隨風入杳冥。',64,'全唐诗/poet.tang.27000.json','["將軍不復見儀形，笑語隨風入杳冥。", "戰馬舊騎嘶引葬，歌姬新嫁哭辭靈。", "功勳客問求爲誌，服玩僧收與轉經。", "寂寞一家春色裏，百花開落滿山庭。"]'),
('5a0be812-c81a-474f-9d46-9e15b32047b1','崔卿雙白鷺','顧非熊','唐','唐诗','tang','','[]','朝客高清愛水禽，綠波雙鷺在園林。',64,'全唐诗/poet.tang.27000.json','["朝客高清愛水禽，綠波雙鷺在園林。", "立當風裏絲搖急，步遶池邊字印深。", "刷羽競生堪畫勢，依泉各有取魚心。", "我鄉多傍門前見，坐覺煙波思不禁。"]'),
('8f023210-9094-43f8-a06a-e5bae14fdc5d','子夜夏秋二曲 一','顧非熊','唐','唐诗','tang','','[]','相持薄羅扇，綠樹聽鳴蜩。',24,'全唐诗/poet.tang.27000.json','["相持薄羅扇，綠樹聽鳴蜩。", "君筵呈妙舞，香汗濕鮫綃。"]'),
('7943c170-fde5-44e8-9a0f-81e3868767df','子夜夏秋二曲 二','顧非熊','唐','唐诗','tang','','[]','銀牀梧葉下，便覺漏聲長。',24,'全唐诗/poet.tang.27000.json','["銀牀梧葉下，便覺漏聲長。", "露砌蛩吟切，那憐白苧涼。"]'),
('173a6ae5-339f-41b3-bc7c-80b226501adb','關山月','顧非熊','唐','唐诗','tang','','[]','海上清光發，邊營照轉悽。',24,'全唐诗/poet.tang.27000.json','["海上清光發，邊營照轉悽。", "深閨此宵夢，帶月過遼西。"]'),
('453b1c0f-29ed-4b4f-9bb9-7ae63ee0e0d5','採蓮詞','顧非熊','唐','唐诗','tang','','[]','纖手折芙蕖，花灑羅衫濕。',24,'全唐诗/poet.tang.27000.json','["纖手折芙蕖，花灑羅衫濕。", "女伴喚回船，前溪風浪急。"]'),
('e68b10d3-b8c6-4733-9448-868916a2e19f','秋月夜','顧非熊','唐','唐诗','tang','','[]','旅鴈迎風度，階翻月露華。',24,'全唐诗/poet.tang.27000.json','["旅鴈迎風度，階翻月露華。", "砧聲鳴夜永，江上幾多家。"]'),
('9bdf9bc8-f1b6-4e70-b83a-fb85c9fab498','登樓','顧非熊','唐','唐诗','tang','','[]','登樓一南望，淮樹楚山連。',24,'全唐诗/poet.tang.27000.json','["登樓一南望，淮樹楚山連。", "見鴈無書寄，歸吳定此年。"]'),
('af9edce4-1791-41fb-9e1d-2b0ddfe1a863','閶門書感','顧非熊','唐','唐诗','tang','','[]','鳧鷖踏波舞，樹色接橫塘。',24,'全唐诗/poet.tang.27000.json','["鳧鷖踏波舞，樹色接橫塘。", "遠近蘼蕪綠，吳宮總夕陽。"]'),
('b3f131e4-2354-4f67-8418-2afd412cbc89','送內鄉張主簿赴任','顧非熊','唐','唐诗','tang','','[]','松窗久是飡霞客，山縣新爲主印官。',32,'全唐诗/poet.tang.27000.json','["松窗久是飡霞客，山縣新爲主印官。", "混俗故來分利祿，不教長作異人看。"]'),
('b6f96805-d362-4293-b660-3bd24f908e3f','瓜洲送朱萬言','顧非熊','唐','唐诗','tang','','[]','渡頭風晚葉飛頻，君去還吳我入秦。',32,'全唐诗/poet.tang.27000.json','["渡頭風晚葉飛頻，君去還吳我入秦。", "雙淚別家猶未斷，不堪仍送故鄉人。"]'),
('57408a15-f521-4156-b02f-9944ecaafed6','秋夜長安病後作','顧非熊','唐','唐诗','tang','','[]','秋中帝里經旬雨，晴後蟬聲更不聞。',32,'全唐诗/poet.tang.27000.json','["秋中帝里經旬雨，晴後蟬聲更不聞。", "牢落閑庭新病起，故鄉南去雁成羣。"]'),
('6916fd52-acb1-4102-8593-62dd7f0585e5','題王使君片石','顧非熊','唐','唐诗','tang','','[]','勢似孤峯一片成，坐來疑有白雲生。',32,'全唐诗/poet.tang.27000.json','["勢似孤峯一片成，坐來疑有白雲生。", "主人莫怪殷勤看，遠客長懷舊隱情。"]'),
('0c98061d-1bc3-4357-9f67-10ba8add5bc3','暮春早起','顧非熊','唐','唐诗','tang','','[]','柳[梢]暗露滴清晨，簾下偏驚獨起人。',34,'全唐诗/poet.tang.27000.json','["柳[梢]暗露滴清晨，簾下偏驚獨起人。", "鶗鴂數聲花漸落，園林是處總殘春。"]'),
('e4159185-6f10-4319-ab22-00e7667de891','途次懷歸','顧非熊','唐','唐诗','tang','','[]','隴頭禾偃乳烏飛，兀倚征鞍倍憶歸。',32,'全唐诗/poet.tang.27000.json','["隴頭禾偃乳烏飛，兀倚征鞍倍憶歸。", "正值江南新釀熟，可容閑却老萊衣。"]'),
('1bca6d64-f3af-4ae0-9800-e08f7c7acb59','寄陸隱君','顧非熊','唐','唐诗','tang','','[]','相思迢遞隔重城，鳥散堦前竹塢清。',32,'全唐诗/poet.tang.27000.json','["相思迢遞隔重城，鳥散堦前竹塢清。", "定擬秋涼過南崦，長松石上聽泉聲。"]'),
('6ddee2f0-6401-4696-acbe-1599666963a0','寄吳山淨上人','顧非熊','唐','唐诗','tang','','[]','憶共蒲團話夜鐘，別來落葉閟行蹤。',32,'全唐诗/poet.tang.27000.json','["憶共蒲團話夜鐘，別來落葉閟行蹤。", "遙知黛色秋常翫，住向靈巖第幾峯。"]'),
('f8be67bb-49b2-45d0-b4ce-f6ff1996ad74','送徐五綸南行過吳','顧非熊','唐','唐诗','tang','','[]','吳門東去路三千，到得閶門暫泊船。',32,'全唐诗/poet.tang.27000.json','["吳門東去路三千，到得閶門暫泊船。", "老父出迎應倒屣，貧居江上信誰傳。"]'),
('67854d8d-1f5f-4919-b6bc-ff4a38887b76','遊天台山','張祜','唐','唐诗','tang','','[]','崔嵬海西鎮，靈跡傳萬古。',290,'全唐诗/poet.tang.27000.json','["崔嵬海西鎮，靈跡傳萬古。", "羣峰日來朝，累累孫侍祖。", "三茅即拳石，二室猶塊土。", "傍洞窟神仙，中巖宅龍虎。", "名從乾取象，位與坤作輔。", "鸞鶴自相羣，前人空若瞽。", "巉巉割秋碧，媧女徒巧補。", "視聽出塵埃，處高心漸苦。", "纔登招手石，肘底笑天姥。", "仰看華蓋尖，赤日雲上午。", "奔雷撼深谷，下見山脚雨。", "回首望四明，矗若城一堵。", "昏晨邈千態，恐動非自主。", "控鵠大夢中，坐覺身[栩栩]。", "東溟子時月，却孕元化母。", "彭蠡不盈杯，浙江微辨縷。", "石梁屹橫架，萬仞青壁豎。", "却瞰赤城顛，勢來如刀弩。", "盤松國清道，九里天莫覩。", "穹崇上攢三，突兀傍聳五。", "空崖絕凡路，癡立麋與麈。", "邈峻極天門，覰深窺地戶。", "金庭路非遠，徒步將欲舉。", "身樂道家流，惇儒若一矩。"]'),
('471aba7e-b432-471f-a7e5-aaef194c5b8c','送蜀客','張祜','唐','唐诗','tang','','[]','楚客去岷江，西南指天末。',120,'全唐诗/poet.tang.27000.json','["楚客去岷江，西南指天末。", "平生不達意，萬里船一發。", "行行三峽夜，十二峰頂月。", "哀猨別曾林，忽忽聲斷咽。", "嘉陵水初漲，巖嶺耗積雪。", "不妨高唐雲，却藉宋玉說。", "峨眉遠凝黛，脚底谷洞穴。", "錦城晝氳氳，錦水春活活。", "成都滯游地，酒客須醉殺。", "莫戀卓家壚，相如已屑屑。"]'),
('9e466d95-299d-4fe9-af65-0370e1ecc420','團扇郎','張祜','唐','唐诗','tang','','[]','白團扇，今來此去捐。',22,'全唐诗/poet.tang.27000.json','["白團扇，今來此去捐。", "願得入郎手，團圓郎眼前。"]'),
('51073cde-e7d3-482d-9fb8-e3495c273645','西江行','張祜','唐','唐诗','tang','','[]','日下西塞山，南來東庭客。',36,'全唐诗/poet.tang.27000.json','["日下西塞山，南來東庭客。", "晴空一鳥渡，萬里秋江碧。", "惆悵異鄉人，偶言空脉脉。"]'),
('08876f3d-f118-4038-9fc0-95049a32ec17','溳川寺路','張祜','唐','唐诗','tang','','[]','日沉西澗陰，遠驅愁突兀。',36,'全唐诗/poet.tang.27000.json','["日沉西澗陰，遠驅愁突兀。", "煙苔濕凝地，露竹光滴月。", "時見一僧來，脚邊雲勃勃。"]'),
('8788508f-b60f-408d-adaf-917b191693b7','夜雨','張祜','唐','唐诗','tang','','[]','靄靄雲四黑，秋林響空堂。',36,'全唐诗/poet.tang.27000.json','["靄靄雲四黑，秋林響空堂。", "始從寒瓦中，淅瀝斷人腸。", "愁腸方九迴，寂寂夜未央。"]'),
('81cb19d0-a23f-4f8e-925a-fbffa8dcfc6f','秋晚途中作','張祜','唐','唐诗','tang','','[]','落日馳車道，秋郊思不勝。',36,'全唐诗/poet.tang.27000.json','["落日馳車道，秋郊思不勝。", "水雲遙斷緒，山日半銜稜。", "遠吠鄰村處，計想羨他能。"]'),
('d3d6febe-dde8-43be-bb7c-9bf35d2bf4ae','拔蒲歌','張祜','唐','唐诗','tang','','[]','拔蒲來，領郎鏡湖邊。',34,'全唐诗/poet.tang.27000.json','["拔蒲來，領郎鏡湖邊。", "郎心在何處，莫趁新蓮去。", "拔得無心蒲，問郎看好無。"]'),
('e6565488-e11a-4962-b165-0ef5d7edc5ed','車遙遙','張祜','唐','唐诗','tang','','[]','東方曨曨車軋軋，地色不分新去轍。',80,'全唐诗/poet.tang.27000.json','["東方曨曨車軋軋，地色不分新去轍。", "閨門半掩窗半空，斑斑枕花殘淚紅。", "君心若車千萬轉，妾身如轍遺漸遠。", "碧川迢迢山宛宛，馬蹄在耳輪在眼。", "桑間女兒情不淺，莫道野蠶能作繭。"]'),
('2e41547c-d533-4060-b61b-9d2c65653022','捉搦歌','張祜','唐','唐诗','tang','','[]','門上關，牆上棘。',76,'全唐诗/poet.tang.27000.json','["門上關，牆上棘。", "窗中女子聲唧唧，洛陽大道徒自直。", "女子心在婆舍側，嗚嗚籠鳥觸四隅。", "養男男娶婦，養女女嫁夫。", "阿婆六十翁七十，不知女子長日泣，從他嫁去無悒悒。"]'),
('cb3e80da-55d4-48b0-90e3-482b37d9e172','鴈門太守行','張祜','唐','唐诗','tang','','[]','城頭月沒霜如水，趚趚踏沙人似鬼。',72,'全唐诗/poet.tang.27000.json','["城頭月沒霜如水，趚趚踏沙人似鬼。", "燈前拭淚試香裘，長引一聲殘漏子。", "駝囊瀉酒酒一杯，前頭滴血心不回。", "閨中年少妻莫哀，魚金虎竹天上來，鴈門山邊骨成灰。"]'),
('fb9cfdc4-7c10-45da-ae33-7060a52b7dc1','思歸引','張祜','唐','唐诗','tang','','[]','重重作閨清旦鐍，兩耳深聲長不徹。',64,'全唐诗/poet.tang.27000.json','["重重作閨清旦鐍，兩耳深聲長不徹。", "深宮坐愁百年身，一片玉中生憤血。", "焦桐彈罷絲自絕，漠漠暗魂愁夜月。", "故鄉不歸誰共穴，石上作蒲蒲九節。"]'),
('3c9accae-e865-4b1f-b031-f485e34aadad','司馬相如琴歌','張祜','唐','唐诗','tang','','[]','鳳兮鳳兮非無皇，山重水闊不可量。',32,'全唐诗/poet.tang.27000.json','["鳳兮鳳兮非無皇，山重水闊不可量。", "梧桐結陰在朝陽，濯羽弱水鳴高翔。"]'),
('7de5d3f8-14c4-4805-8beb-fbad07c6d34a','雉朝飛操','張祜','唐','唐诗','tang','','[]','朝陽隴東泛暖景，雙啄雙飛雙顧影。',78,'全唐诗/poet.tang.27000.json','["朝陽隴東泛暖景，雙啄雙飛雙顧影。", "朱冠錦襦聊日整，漠漠霧中如衣褧。", "傷心盧女弦，七十老翁長獨眠。", "雄飛在草雌在田，衷腸結憤氣呵天。", "聖人在上心不偏，翁得女妻甚可憐。"]'),
('ce54b4ac-0a92-40b7-a63a-952ecb1ba5ed','觀徐州李司空獵','張祜','唐','唐诗','tang','','[]','曉出郡城東，分圍淺草中。',48,'全唐诗/poet.tang.27000.json','["曉出郡城東，分圍淺草中。", "紅旗開向日，白馬驟迎風。", "背手抽金鏃，翻身控角弓。", "萬人齊指處，一鴈落寒空。"]'),
('ef8e377f-08e2-4b59-9cb2-53a9cb3b58c6','獵','張祜','唐','唐诗','tang','','[]','殘獵渭城東，蕭蕭西北風。',50,'全唐诗/poet.tang.27000.json','["殘獵渭城東，蕭蕭西北風。", "雪花[鷹]背上，冰片馬蹄中。", "臂挂捎荆兔，腰懸落箭鴻。", "歸來逞餘勇，兒子亂彎弓。"]'),
('a75d1fc3-a2ea-4e59-a4b3-d72ce2e52872','鸚鵡','張祜','唐','唐诗','tang','','[]','栖栖南越鳥，色麗思沉淫。',48,'全唐诗/poet.tang.27000.json','["栖栖南越鳥，色麗思沉淫。", "暮隔碧雲海，春依紅樹林。", "雕籠悲斂翅，畫閣豈關心。", "無事能言語，人聞怨恨深。"]'),
('42d10efe-9829-4717-b4a7-d5a9ee67a627','再吟鸚鵡','張祜','唐','唐诗','tang','','[]','萬里去心違，奇毛覺自非。',48,'全唐诗/poet.tang.27000.json','["萬里去心違，奇毛覺自非。", "美人憐解語，凡鳥畏多機。", "未勝無丹嘴，何勞事綠衣。", "雕籠終不戀，會向故山歸。"]'),
('9ca0ab35-1b33-419a-8846-494876c4dbec','酬鄭模司直見寄','張祜','唐','唐诗','tang','','[]','故人滄海曲，聊復話平生。',48,'全唐诗/poet.tang.27000.json','["故人滄海曲，聊復話平生。", "喜是狂奴態，羞爲老婢聲。", "宦途終日薄，身事長年輕。", "猶賴書千卷，長隨一櫂行。"]'),
('fcfb4dd9-9ee5-4c37-b1dc-49b96fe902f8','送蘇紹之歸嶺南','張祜','唐','唐诗','tang','','[]','孤舟越客吟，萬里曠離襟。',48,'全唐诗/poet.tang.27000.json','["孤舟越客吟，萬里曠離襟。", "夜月江流闊，春雲嶺路深。", "珠繁楊氏果，翠耀孔家禽。", "無復天南夢，相思空樹林。"]'),
('09a4d319-d860-4c10-93b5-2f384abb91a9','送沈下賢謫尉南康','張祜','唐','唐诗','tang','','[]','秋風江上草，先是客心摧。',48,'全唐诗/poet.tang.27000.json','["秋風江上草，先是客心摧。", "萬里故人去，一行新鴈來。", "山高雲緒斷，浦逈日波頹。", "莫怪南康遠，相思不可裁。"]'),
('dcd8d4b3-a81b-4723-8aa0-9f9ceeaa5175','送盧弘本浙東覲省','張祜','唐','唐诗','tang','','[]','東望故山高，秋歸值小舠。',48,'全唐诗/poet.tang.27000.json','["東望故山高，秋歸值小舠。", "懷中陸績橘，江上伍員濤。", "好去寧雞口，加餐及蟹螯。", "知君思無倦，爲我續離騷。"]'),
('b361e743-6b84-401e-ba5f-eec9c9da1e2a','晚次荆溪館呈崔明府','張祜','唐','唐诗','tang','','[]','艤舟陽羨館，飛步繚疎楹。',48,'全唐诗/poet.tang.27000.json','["艤舟陽羨館，飛步繚疎楹。", "山暝水雲碧，月涼烟樹清。", "長橋深漾影，遠櫓下搖聲。", "況是無三害，弦歌初政成。"]'),
('3d132f06-64d5-46e5-afc1-08db2268a05e','寄朗州徐員外','張祜','唐','唐诗','tang','','[]','江嶺昔飄蓬，人間值俊雄。',48,'全唐诗/poet.tang.27000.json','["江嶺昔飄蓬，人間值俊雄。", "關西今孔子，城北舊徐公。", "清夜游何處，良辰此不同。", "傷心幾年事，一半在湖中。"]'),
('65202203-84e7-4c2f-a909-5c6e58593f72','旅次上饒溪','張祜','唐','唐诗','tang','','[]','碧溪行幾折，凝櫂宿汀沙。',48,'全唐诗/poet.tang.27000.json','["碧溪行幾折，凝櫂宿汀沙。", "角斷孤城掩，樓深片月斜。", "夜橋昏水氣，秋竹靜霜華。", "更想曾題壁，凋零可歎嗟。"]'),
('35af7ad5-0600-4981-b70a-104294bf358b','送徐彥夫南遷','張祜','唐','唐诗','tang','','[]','萬里客南遷，孤城漲海邊。',48,'全唐诗/poet.tang.27000.json','["萬里客南遷，孤城漲海邊。", "瘴雲秋不斷，陰火夜長然。", "月上行虛市，風廻望舶船。", "知君還自潔，更爲酌貪泉。"]'),
('ae9c0c35-7d44-4800-a636-71768a82c539','送韋整尉長沙','張祜','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u9001\u522b"]','遠遠長沙去，憐君利一官。',48,'全唐诗/poet.tang.27000.json','["遠遠長沙去，憐君利一官。", "風帆彭蠡疾，雲水洞庭寬。", "木客提蔬束，江烏接飯丸。", "莫言卑濕地，未必乏新歡。"]'),
('9629917c-6e7c-4f21-a7bc-c0a495cafcab','送外甥','張祜','唐','唐诗','tang','','[]','衰年生姪少，唯爾最關心。',48,'全唐诗/poet.tang.27000.json','["衰年生姪少，唯爾最關心。", "偶作魏舒別，聊爲殷浩吟。", "白波舟不定，黃葉路難尋。", "自此尊中物，誰當更共斟。"]'),
('0245cd86-9f33-4def-85e5-170d899be663','贈薛鼎臣侍御','張祜','唐','唐诗','tang','','[]','一命前途遠，雙曹小邑閑。',48,'全唐诗/poet.tang.27000.json','["一命前途遠，雙曹小邑閑。", "夜潮人到郭，春霧鳥啼山。", "淺瀨橫沙堰，高巖峻石斑。", "不堪曾倚櫂，猶復夢昇攀。"]'),
('31fec8ee-6f06-4691-bf12-67bd4ee15550','送曾黯游夔州','張祜','唐','唐诗','tang','','[]','不遠夔州路，層波灩澦連。',48,'全唐诗/poet.tang.27000.json','["不遠夔州路，層波灩澦連。", "下來千里峽，入去一條天。", "樹色秋帆上，灘聲夜枕前。", "何堪正危側，百丈半山顛。"]'),
('a36fd787-83d0-4096-b26b-22332c35d408','送李長史歸涪州','張祜','唐','唐诗','tang','','[]','涪江江上客，歲晚却還鄉。',48,'全唐诗/poet.tang.27000.json','["涪江江上客，歲晚却還鄉。", "暮過高唐雨，秋經巫峽霜。", "急灘船失次，疊嶂樹無行。", "好爲題新什，知君思不常。"]'),
('3aa95688-bf8c-4363-9291-b07e934d57e8','贈契衡上人','張祜','唐','唐诗','tang','','[]','小門開板閣，終日是逢迎。',48,'全唐诗/poet.tang.27000.json','["小門開板閣，終日是逢迎。", "語笑人同坐，修持意別行。", "水花秋始發，風竹夏長清。", "一恨悽惶久，憐師記姓名。"]'),
('23d89b00-4560-482f-bb27-14a48f4e8a93','走筆贈許玖赴桂州命','張祜','唐','唐诗','tang','','["\u957f\u6c5f"]','桂林真重德，蓮幕藉殊才。',48,'全唐诗/poet.tang.27000.json','["桂林真重德，蓮幕藉殊才。", "直氣自消瘴，遠心無暫灰。", "劒稜叢石險，箭激亂流迴。", "莫說鴈不到，長江魚盡來。"]'),
('5a458335-6c3f-4394-91d3-703d6a061c19','題上饒亭','張祜','唐','唐诗','tang','','[]','溪亭拂一琴，促軫坐披衿。',48,'全唐诗/poet.tang.27000.json','["溪亭拂一琴，促軫坐披衿。", "夜月水南寺，秋風城外砧。", "早霜紅葉靜，新雨碧潭深。", "唯是壺中物，憂來且自斟。"]'),
('1b7c5fbf-48ca-4c34-b7d5-f433d8537d7b','題僧壁','張祜','唐','唐诗','tang','','[]','出門無一事，忽忽到天涯。',48,'全唐诗/poet.tang.27000.json','["出門無一事，忽忽到天涯。", "客地多逢酒，僧房却厭花。", "棊因王粲覆，鼓是禰衡撾。", "自喜疎成品，生前不怨嗟。"]'),
('2421af36-0f48-4022-b197-4af572ff9257','寄盧載','張祜','唐','唐诗','tang','','[]','故人盧氏子，十載曠佳期。',48,'全唐诗/poet.tang.27000.json','["故人盧氏子，十載曠佳期。", "少見雙魚信，多聞八米詩。", "侏儒他甚飽，欵段爾應羸。", "忽謂今劉二，相逢不熟槌。"]'),
('e7e339d1-6d9a-4850-8afb-a841222b3931','送楊秀才游蜀','張祜','唐','唐诗','tang','','[]','鄂渚逢遊客，瞿塘上去船。',48,'全唐诗/poet.tang.27000.json','["鄂渚逢遊客，瞿塘上去船。", "峽深明月夜，江靜碧雲天。", "舊俗巴渝舞，新聲蜀國弦。", "不堪揮慘恨，一涕自潸然。"]'),
('44447c98-e074-4c92-a87f-aeaf3e1daa34','送楊秀才往夔州','張祜','唐','唐诗','tang','','[]','鄂渚逢游客，瞿塘上去船。',48,'全唐诗/poet.tang.27000.json','["鄂渚逢游客，瞿塘上去船。", "江連萬里海，峽入一條天。", "鳥影沉沙日，猨聲隔樹煙。", "新詩逢北使，爲草幾巴牋。"]'),
('65f8b3e0-d1a5-4283-8836-c27d5cd676cb','途中逢李道實遊蔡州','張祜','唐','唐诗','tang','','[]','征馬漢江頭，逢君上蔡游。',48,'全唐诗/poet.tang.27000.json','["征馬漢江頭，逢君上蔡游。", "野橋經亥市，山路過申州。", "僻地人行澀，荒林虎跡稠。", "殷勤話新守，生物賴諸侯。"]'),
('de416256-7aaf-4731-9ca4-741e8810fb24','富陽道中送王正夫','張祜','唐','唐诗','tang','','[]','㭊㭊上荒原，霜林赤葉翻。',48,'全唐诗/poet.tang.27000.json','["㭊㭊上荒原，霜林赤葉翻。", "孤帆天外出，遠戍日中昏。", "摘橘防深刺，攀蘿畏斷根。", "何堪衰草色，一酌送王孫。"]'),
('433bb237-07f7-40dc-818e-1376f05d047d','送韋正字㭊貫赴制舉','張祜','唐','唐诗','tang','','[]','可愛漢文年，鴻恩蕩海壖。',48,'全唐诗/poet.tang.27000.json','["可愛漢文年，鴻恩蕩海壖。", "木雞方備德，金馬正求賢。", "大戰希游刃，長途在著鞭。", "竚看晁董策，便向史中傳。"]'),
('c30ab797-6c3d-4b12-961f-ceb67106d838','贈貞固上人','張祜','唐','唐诗','tang','','[]','南國披僧籍，高標一道林。',48,'全唐诗/poet.tang.27000.json','["南國披僧籍，高標一道林。", "律儀精氎布，真行正吞針。", "掇火身潛起，焚香口旋吟。", "非論坐中社，余亦舊知音。"]'),
('47715903-0ea7-4db5-8404-1f7a4565d2df','題贈志凝上人','張祜','唐','唐诗','tang','','[]','悟色身無染，觀空事不生。',48,'全唐诗/poet.tang.27000.json','["悟色身無染，觀空事不生。", "道心長日笑，覺路幾年行。", "片月山林靜，孤雲海櫂輕。", "願爲塵外契，一就智珠明。"]'),
('ad6f1bc4-b02f-4058-8eea-0b8f551dcae0','送瓊貞發述懷','張祜','唐','唐诗','tang','','[]','送出南溪日，離情不忍看。',48,'全唐诗/poet.tang.27000.json','["送出南溪日，離情不忍看。", "漸遙猶顧首，帆去意難判。", "最恨臨行夜，相期幾百般。", "但能存歲節，終久得同歡。"]'),
('d4ba62e4-f423-41db-aa27-d81167791722','寄靈澈上人','張祜','唐','唐诗','tang','','[]','老僧何處寺，秋夢繞江濱。',48,'全唐诗/poet.tang.27000.json','["老僧何處寺，秋夢繞江濱。", "獨樹月中鶴，孤舟雲外人。", "榮華長指幻，衰病久觀身。", "應笑無成者，滄洲垂一輪。"]'),
('5cc28d14-9742-45b7-bf7e-6a84e72ab1da','溪行寄京師故人道侶','張祜','唐','唐诗','tang','','[]','白日長多事，清溪偶獨尋。',48,'全唐诗/poet.tang.27000.json','["白日長多事，清溪偶獨尋。", "雲歸秋水闊，月出夜山深。", "坐想天涯去，行悲澤畔吟。", "東郊故人在，應笑未抽簪。"]'),
('f3b76992-febb-40fb-8843-9fa3a00efe2f','贈僧雲栖','張祜','唐','唐诗','tang','','[]','麈尾與筇枝，幾年離石壇。',48,'全唐诗/poet.tang.27000.json','["麈尾與筇枝，幾年離石壇。", "梵餘林雪厚，棊罷岳鐘殘。", "開卷喜先悟，漱瓶知早寒。", "衡陽寺前鴈，今日到長安。"]'),
('8903eabd-bb69-4059-a61f-15184b624218','送魏尚書赴鎮州行營','張祜','唐','唐诗','tang','','[]','河塞日駸駸，恩讐報盡深。',48,'全唐诗/poet.tang.27000.json','["河塞日駸駸，恩讐報盡深。", "伍員忠是節，陸績孝爲心。", "坐激書生憤，行歌壯士吟。", "慙非燕地客，不得受黃金。"]'),
('8e8b5aab-e8bc-40f1-870a-077b448854a5','寄遷客','張祜','唐','唐诗','tang','','[]','萬里南遷客，辛勤嶺路遙。',48,'全唐诗/poet.tang.27000.json','["萬里南遷客，辛勤嶺路遙。", "溪行防水弩，野店避山魈。", "瘴海須求藥，貪泉莫舉瓢。", "但能堅志義，白日甚昭昭。"]'),
('cf6b43ab-bc18-4c23-9fdc-9bae67e6e126','題蘇小小墓','張祜','唐','唐诗','tang','','[]','漠漠窮塵地，蕭蕭古樹林。',48,'全唐诗/poet.tang.27000.json','["漠漠窮塵地，蕭蕭古樹林。", "臉濃花自發，眉恨柳長深。", "夜月人何待，春風鳥爲吟。", "不知誰共穴，徒願結同心。"]'),
('09e0f9f0-c175-4baf-a440-ae73d419b8a7','江南作','張祜','唐','唐诗','tang','','[]','楚塞南行久，秦城北望遙。',36,'全唐诗/poet.tang.27000.json','["楚塞南行久，秦城北望遙。", "少年花已過，衰病柳先凋。", "客淚收迴日，鄉心寄落潮。"]'),
('c71355fc-da6a-471f-8699-74ec1d2e0445','題王右丞山水障二首 一','張祜','唐','唐诗','tang','','[]','精華在筆端，咫尺匠心難。',48,'全唐诗/poet.tang.27000.json','["精華在筆端，咫尺匠心難。", "日月中堂見，江湖滿座看。", "夜凝嵐氣濕，秋浸壁光寒。", "料得昔人意，平生詩思殘。"]'),
('8b6d2894-f861-4c32-b9b8-1bb2fd89c299','題王右丞山水障二首 二','張祜','唐','唐诗','tang','','[]','右丞今已歿，遺畫世間稀。',48,'全唐诗/poet.tang.27000.json','["右丞今已歿，遺畫世間稀。", "咫尺江湖盡，尋常鷗鳥飛。", "山光全在掌，雲氣欲生衣。", "以此常爲玩，平生滄海機。"]'),
('d91cb921-c4c1-41e3-90be-c335549c3e15','將之衡陽道中作','張祜','唐','唐诗','tang','','[]','萬里南方去，扁舟泛自身。',48,'全唐诗/poet.tang.27000.json','["萬里南方去，扁舟泛自身。", "長年無愛物，深話少情人。", "醉臥襟長散，閑書字不真。", "衡陽路猶遠，獨與鴈爲賓。"]'),
('cd3bd10a-c021-4ca3-b765-9a4d11af419f','讀狄梁公傳','張祜','唐','唐诗','tang','','[]','失運廬陵厄，乘時武后尊。',48,'全唐诗/poet.tang.27000.json','["失運廬陵厄，乘時武后尊。", "五丁扶造化，一柱正乾坤。", "上保儲皇位，深然國老勳。", "聖朝雖百代，長合問王孫。"]'),
('7ac446e1-0515-44f1-b2f7-dbe6458861a9','題真娘墓','張祜','唐','唐诗','tang','','[]','佛地葬羅衣，孤魂此是歸。',48,'全唐诗/poet.tang.27000.json','["佛地葬羅衣，孤魂此是歸。", "舞爲蝴蝶夢，歌謝伯勞飛。", "翠髮朝雲在，青蛾夜月微。", "傷心一花落，無復怨春輝。"]'),
('0cdf345b-ec6c-4f1b-9925-3093768879f1','洞庭南館','張祜','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','一逕逗霜林，朱欄遶碧岑。',48,'全唐诗/poet.tang.27000.json','["一逕逗霜林，朱欄遶碧岑。", "地盤雲夢角，山鎮洞庭心。", "樹白看煙起，沙紅見日沉。", "還因此悲屈，惆悵又行吟。"]'),
('1a70b22b-f4f4-40b4-b217-e9e5287f3a1b','題贈仲儀上人院','張祜','唐','唐诗','tang','','[]','星霜幾朝寺，香火靜居人。',48,'全唐诗/poet.tang.27000.json','["星霜幾朝寺，香火靜居人。", "黃葉不經意，青山無事身。", "拋生臺上日，結座履中塵。", "自說一時課，別來詩更新。"]'),
('f7f5f9da-d2b8-4fcb-874a-8dc4d3145e05','題聖女廟','張祜','唐','唐诗','tang','','[]','古廟無人入，蒼皮澀老桐。',48,'全唐诗/poet.tang.27000.json','["古廟無人入，蒼皮澀老桐。", "蟻行蟬殼上，蛇竄雀巢中。", "淺水孤舟泊，輕塵一座蒙。", "晚來雲雨去，荒草是殘風。"]'),
('5e44be48-0485-4dbe-b495-8ab1bbba49b7','題山水障子','張祜','唐','唐诗','tang','','[]','一見秋山色，方憐畫手稀。',48,'全唐诗/poet.tang.27000.json','["一見秋山色，方憐畫手稀。", "波濤連壁動，雲物下簷飛。", "嶺樹冬猶發，江帆暮不歸。", "端然是漁叟，相向日依依。"]'),
('b16c76f9-ee8d-488d-bb5e-9f2e57cbe702','詠風','張祜','唐','唐诗','tang','','[]','搖搖歌扇舉，悄悄舞衣輕。',48,'全唐诗/poet.tang.27000.json','["搖搖歌扇舉，悄悄舞衣輕。", "引笛秋臨塞，吹沙夜遶城。", "向峰迴鴈影，出峽送猨聲。", "何似琴中奏，依依別帶情。"]'),
('f81690f4-5328-40a0-a38b-c574af351b44','奉和令狐相公送陳肱侍御','張祜','唐','唐诗','tang','','[]','高館動離瑟，親賓聊歎稀。',48,'全唐诗/poet.tang.27000.json','["高館動離瑟，親賓聊歎稀。", "笑歌情不盡，歡待禮無違。", "清露府蓮結，碧雲臯鶴飛。", "還家與□惠，雨露豈殊歸。"]'),
('246b35d4-4b94-46e9-af74-cdf154b67288','陪范宣城北樓夜讌','張祜','唐','唐诗','tang','','[]','華軒敞碧流，官妓擁諸侯。',48,'全唐诗/poet.tang.27000.json','["華軒敞碧流，官妓擁諸侯。", "粉項高叢鬢，檀妝慢裹頭。", "亞身摧蠟燭，斜眼送香毬。", "何處偏堪恨，千迴下客籌。"]'),
('f3bddf83-4da5-4094-8ae0-04ec65c23da2','憲宗皇帝挽歌詞','張祜','唐','唐诗','tang','','[]','嗚咽上攀龍，昇平不易逢。',48,'全唐诗/poet.tang.27000.json','["嗚咽上攀龍，昇平不易逢。", "武皇虛好道，文帝未登封。", "壽域無千載，泉門是九重。", "橋山非遠地，雲去莫疑峰。"]'),
('ce697a0b-c392-4c85-9ddb-e83f95a236c4','發蜀客','張祜','唐','唐诗','tang','','[]','風吹魯國人，飄蕩蜀江濱。',48,'全唐诗/poet.tang.27000.json','["風吹魯國人，飄蕩蜀江濱。", "濕地饒蛙黽，衰年足鬼神。", "時清歸去路，日復病來身。", "千萬長堤柳，從他爛熳春。"]'),
('2c59ed55-8d94-42c3-beda-d237f911e37b','江城晚眺','張祜','唐','唐诗','tang','','[]','重檻構雲端，江城四鬱盤。',48,'全唐诗/poet.tang.27000.json','["重檻構雲端，江城四鬱盤。", "河流出郭靜，山色對樓寒。", "浪草侵天白，霜林映日丹。", "悠然此江思，樹杪幾檣竿。"]'),
('b52302ee-da79-4766-b62a-5460d4d8251d','題樟亭','張祜','唐','唐诗','tang','','[]','曉霽憑虛檻，雲山四望通。',48,'全唐诗/poet.tang.27000.json','["曉霽憑虛檻，雲山四望通。", "地盤江岸絕，天映海門空。", "樹色連秋靄，潮聲入夜風。", "年年此光景，催盡白頭翁。"]'),
('9d768f4a-8b6e-48ce-8376-fd45e7d58a75','樂靜','張祜','唐','唐诗','tang','','[]','引手強篸巾，徐徐起病身。',48,'全唐诗/poet.tang.27000.json','["引手強篸巾，徐徐起病身。", "遠心羣野鶴，閑話對村人。", "發匣琴徽靜，開瓶酒味真。", "縱聞兵賦急，原憲本家貧。"]'),
('5f66ef86-de8c-43a5-becb-26a5333aad46','登廣武原','張祜','唐','唐诗','tang','','[]','廣武原西北，華夷此浩然。',48,'全唐诗/poet.tang.27000.json','["廣武原西北，華夷此浩然。", "地盤山入海，河遶國連天。", "遠樹千門邑，高檣萬里船。", "鄉心日云暮，猶在楚城邊。"]'),
('eba8b869-2b97-462c-a8db-e7eccc05567b','觀宋州田大夫打毬','張祜','唐','唐诗','tang','','[]','白馬頓紅纓，梢毬紫袖輕。',48,'全唐诗/poet.tang.27000.json','["白馬頓紅纓，梢毬紫袖輕。", "曉冰蹄下裂，寒瓦杖頭鳴。", "叉手膠黏去，分鬃線道絣。", "自言無戰伐，髀肉已曾生。"]'),
('bab45eb4-da2d-4368-b3ab-01f2fbb32516','題丹陽永泰寺練湖亭','張祜','唐','唐诗','tang','','[]','小檻俯澄鮮，龍宮浸浩然。',48,'全唐诗/poet.tang.27000.json','["小檻俯澄鮮，龍宮浸浩然。", "孤光懸夜月，一片割秋天。", "淺派胤沙草，餘波漂岸船。", "聊當因畎澮，披拂坐潺湲。"]'),
('23553ffd-b8dd-446a-80c5-2b7e4e9e734c','題程氏書齋','張祜','唐','唐诗','tang','','[]','僻巷難通馬，深園不藉籬。',48,'全唐诗/poet.tang.27000.json','["僻巷難通馬，深園不藉籬。", "青蘿纏栢葉，紅粉墜蓮枝。", "雨燕銜泥近，風魚咂網遲。", "緣君尋小阮，好是更題詩。"]'),
('dc1558e5-7994-47f7-8c42-66cef9229046','毀浮圖年逢東林寺舊','張祜','唐','唐诗','tang','','[]','可惜東林寺，空門失所依。',48,'全唐诗/poet.tang.27000.json','["可惜東林寺，空門失所依。", "翻經謝靈運，畫壁陸探微。", "隙地泉聲在，荒途馬跡稀。", "殷勤話僧輩，未敢保儒衣。"]'),
('255c4435-29ed-49a7-ac0e-2d41e75c8786','貴池道中作','張祜','唐','唐诗','tang','','[]','羸驂驅野岸，山遠路盤盤。',48,'全唐诗/poet.tang.27000.json','["羸驂驅野岸，山遠路盤盤。", "清露月華曉，碧江星影寒。", "離羣徒長泣，去國自加餐。", "霄漢寧無舊，相哀自語端。"]'),
('7bc6dbff-6141-4453-aca6-f7af8bae486f','喜王子載話舊','張祜','唐','唐诗','tang','','[]','相逢青眼日，相歎白頭時。',48,'全唐诗/poet.tang.27000.json','["相逢青眼日，相歎白頭時。", "累話三朝事，重看一局棊。", "歡娛非老大，成長是嬰兒。", "且盡尊中物，無煩更後期。"]'),
('0682aa38-f390-49e9-8685-b8195c3a5420','秋日病中','張祜','唐','唐诗','tang','','[]','析析簷前竹，秋聲拂簟涼。',48,'全唐诗/poet.tang.27000.json','["析析簷前竹，秋聲拂簟涼。", "病加陰已久，愁覺夜初長。", "坐拾車前子，行看肘後方。", "無端憂食忌，開鏡倍萎黃。"]'),
('f0958fb4-f2de-40dc-a56e-7af16de68faf','訪許用晦','張祜','唐','唐诗','tang','','[]','遠郭日曛曛，停橈一訪君。',48,'全唐诗/poet.tang.27000.json','["遠郭日曛曛，停橈一訪君。", "小橋通野水，高樹入江雲。", "酒興曾無敵，詩情舊逸羣。", "怪來音信少，五十我無聞。"]'),
('5502e22e-e55f-4e74-9af1-31f64cef2223','題海鹽南館','張祜','唐','唐诗','tang','','[]','故人營此地，臺館尚依依。',48,'全唐诗/poet.tang.27000.json','["故人營此地，臺館尚依依。", "黑夜山魈語，黃昏海燕歸。", "舊陰楊葉在，殘雨槿花稀。", "無復南亭賞，高簷紅燭輝。"]'),
('6cca6f72-4783-4d6e-99d1-08f6cd768459','晚秋江上作','張祜','唐','唐诗','tang','','[]','萬里窮秋客，蕭條對落暉。',48,'全唐诗/poet.tang.27000.json','["萬里窮秋客，蕭條對落暉。", "煙霞山鳥散，風雨廟神歸。", "地遠蛩聲切，天長鴈影稀。", "那堪正砧杵，幽思想寒衣。"]'),
('ffaf9870-e688-45d5-94ed-d66d4843783e','吳宮曲','張祜','唐','唐诗','tang','','[]','日下苑西宮，花飄香徑紅。',48,'全唐诗/poet.tang.27000.json','["日下苑西宮，花飄香徑紅。", "玉釵斜白燕，羅帶弄青蟲。", "皓齒初含雪，柔枝欲斷風。", "可憐傾國豔，誰信女爲戎。"]'),
('4869ef2f-3ebd-45f2-84d9-4235d3047681','賦昭君塚','張祜','唐','唐诗','tang','','[]','萬里關山塚，明妃舊死心。',48,'全唐诗/poet.tang.27000.json','["萬里關山塚，明妃舊死心。", "恨爲秋色晚，愁結暮雲陰。", "夜切胡風起，天高漢月臨。", "已知無玉貌，何事送黃金。"]'),
('5b2ef31a-a526-458d-997a-cf47b28081ce','哭汴州陸大夫','張祜','唐','唐诗','tang','','[]','利劒太堅操，何妨拔一毛。',48,'全唐诗/poet.tang.27000.json','["利劒太堅操，何妨拔一毛。", "冤深陸機霧，憤積伍員濤。", "直道非無驗，明時不錄勞。", "誰當青史上，卒爲顯詞褒。"]'),
('44bd0cd6-7abf-4c99-89c9-207af5f06fb2','晚夏歸別業','張祜','唐','唐诗','tang','','[]','古岸扁舟晚，荒園一徑微。',48,'全唐诗/poet.tang.27000.json','["古岸扁舟晚，荒園一徑微。", "鳥啼新果熟，花落故人稀。", "宿潤侵苔甃，斜陽照竹扉。", "相逢盡鄉老，無復話時機。"]'),
('22ec3a40-03e1-4ed4-b676-461cb5413f53','公子行','張祜','唐','唐诗','tang','','[]','春色滿城池，杯盤著處移。',48,'全唐诗/poet.tang.27000.json','["春色滿城池，杯盤著處移。", "鐙金斜鴈子，鞍帕嫩鵝兒。", "買笑歌桃李，尋歌折柳枝。", "可憐明月夜，長是管弦隨。"]'),
('71770c5a-2ae6-438e-96f6-0e98dcdb8c3f','題曾氏園林','張祜','唐','唐诗','tang','','[]','十畝長堤宅，蕭疎半老槐。',48,'全唐诗/poet.tang.27000.json','["十畝長堤宅，蕭疎半老槐。", "醉眠風卷簟，棋罷月移堦。", "斫樹遺桑斧，澆花濕笋鞋。", "還將齊物論，終歲自安排。"]'),
('1dd04cce-7799-4b5c-b4ea-a675bc2517e0','讀始興公傳','張祜','唐','唐诗','tang','','[]','歿世議方存，昇平道幾論。',48,'全唐诗/poet.tang.27000.json','["歿世議方存，昇平道幾論。", "詩情光日月，筆力動乾坤。", "亂首光雄筭，朝綱在典墳。", "明時封禪績，山下見丘門。"]'),
('e5e7282c-6608-491e-b386-79c4c22528be','中秋月','張祜','唐','唐诗','tang','','[]','碧落桂含姿，清秋是素期。',36,'全唐诗/poet.tang.27000.json','["碧落桂含姿，清秋是素期。", "一年逢好夜，萬里見明時。", "絕域行應久，高城下更遲。"]'),
('0468380b-83f8-4ea8-bf36-e95d71bc7b6a','江西道中作三首 一','張祜','唐','唐诗','tang','','[]','日落江村遠，煙霞度幾重。',48,'全唐诗/poet.tang.27000.json','["日落江村遠，煙霞度幾重。", "問人孤驛路，驅馬亂山峰。", "夜入霜林火，寒生水寺鐘。", "淒涼哭途意，行處又饑凶。"]'),
('c56496ca-aa35-4ede-8617-223b709a085f','江西道中作三首 二','張祜','唐','唐诗','tang','','[]','西江江上月，遠遠照征衣。',48,'全唐诗/poet.tang.27000.json','["西江江上月，遠遠照征衣。", "夜色草中網，秋聲林外機。", "渚田牛路熟，石岸客船稀。", "無復是鄉井，鷓鴣聊自飛。"]'),
('1d6cf905-0e0f-470c-99eb-aeac30da4387','江西道中作三首 三','張祜','唐','唐诗','tang','','[]','秋灘一望平，遠遠見山城。',48,'全唐诗/poet.tang.27000.json','["秋灘一望平，遠遠見山城。", "落日啼烏桕，空林露寄生。", "燒畬殘火色，盪槳夜溪聲。", "況是曾遊處，桑田小變更。"]'),
('1bac9f9a-7997-4257-b489-4f545b3a8326','題常州水西館','張祜','唐','唐诗','tang','','[]','隟地叢筠植，修廊列堵環。',48,'全唐诗/poet.tang.27000.json','["隟地叢筠植，修廊列堵環。", "樓臺疎占水，岡岸遠成山。", "盡日草深映，無風舟自閑。", "聊當俟芳夕，一泛芰荷間。"]'),
('f17426ee-fed4-4748-86f3-0797f4b4729e','題李瀆山居玉潭','張祜','唐','唐诗','tang','','[]','古樹千年色，蒼崖百尺陰。',48,'全唐诗/poet.tang.27000.json','["古樹千年色，蒼崖百尺陰。", "髮寒泉氣靜，神駭玉光沉。", "上穴青冥小，中連碧海深。", "何當煙月下，一聽夜龍吟。"]'),
('bca936e1-9ae3-4381-9cff-944ef52ae7f4','題陸墉金沙洞居','張祜','唐','唐诗','tang','','[]','東溪泉一眼，歸臥愜高疎。',48,'全唐诗/poet.tang.27000.json','["東溪泉一眼，歸臥愜高疎。", "決水金沙靜，梯雲石壁虛。", "細吟搔短髮，深話笑長裾。", "莫道遺名品，嘗聞入洛初。"]'),
('4d091a80-4b04-4182-adc8-67134550ec8e','題陸敦禮山居伏牛潭','張祜','唐','唐诗','tang','','[]','伏牛真怪事，餘勝幾人諳。',48,'全唐诗/poet.tang.27000.json','["伏牛真怪事，餘勝幾人諳。", "日彩沉青壁，煙容靜碧潭。", "泛心何慮冷，漱齒詎忘甘。", "幸挈壺中物，期君正興酣。"]'),
('63de0ccb-8500-4ba7-aa56-9ed242c13c55','旅次石頭岸','張祜','唐','唐诗','tang','','[]','行行石頭岸，身事兩相違。',48,'全唐诗/poet.tang.27000.json','["行行石頭岸，身事兩相違。", "舊國日邊遠，故人江上稀。", "水聲寒不盡，山色暮相依。", "惆悵未成語，數行鵶又飛。"]'),
('f2b0b0f1-ab53-4073-ae79-25809269c906','觀宋州于使君家樂琵琶','張祜','唐','唐诗','tang','','[]','歷歷四弦分，重來上界聞。',48,'全唐诗/poet.tang.27000.json','["歷歷四弦分，重來上界聞。", "玉盤飛夜雹，金磬入秋雲。", "隴霧笳凝水，砂風鴈咽羣。", "不堪天塞恨，青塚是昭君。"]'),
('242d5465-f3be-4024-837b-98481381a915','箏','張祜','唐','唐诗','tang','','[]','綽綽下雲煙，微收皓腕鮮。',48,'全唐诗/poet.tang.27000.json','["綽綽下雲煙，微收皓腕鮮。", "夜風生碧柱，春水咽紅弦。", "翠佩輕猶觸，鶯枝澀未遷。", "芳音何更妙，清月共嬋娟。"]'),
('fabbd19f-4b61-4c3a-98a9-e00e97fafc96','歌','張祜','唐','唐诗','tang','','[]','一夜列三清，聞歌曲阜城。',48,'全唐诗/poet.tang.27000.json','["一夜列三清，聞歌曲阜城。", "雪飛紅燼影，珠貫碧雲聲。", "皓齒嬌微發，青蛾怨自生。", "不知新弟子，誰解囀喉輕。"]'),
('b25b532b-b89c-45aa-84c7-af0093a606da','笙','張祜','唐','唐诗','tang','','[]','董雙成一妙，歷歷韻風篁。',48,'全唐诗/poet.tang.27000.json','["董雙成一妙，歷歷韻風篁。", "清露鶴聲遠，碧雲仙吹長。", "氣侵銀項濕，膏胤漆瓢香。", "曲罷不知處，巫山空夕陽。"]'),
('0e78a10e-17cb-43ab-b509-55724b206df9','五弦','張祜','唐','唐诗','tang','','[]','小小月輪中，斜抽半袖紅。',48,'全唐诗/poet.tang.27000.json','["小小月輪中，斜抽半袖紅。", "玉瓶秋滴水，珠箔夜懸風。", "徵調侵弦乙，商聲過指攏。", "只愁纔曲罷，雲雨去巴東。"]'),
('3917e030-def4-4749-8c3f-e04262954563','𥷑篥','張祜','唐','唐诗','tang','','[]','一管妙清商，纖紅玉指長。',48,'全唐诗/poet.tang.27000.json','["一管妙清商，纖紅玉指長。", "雪藤新換束，霞錦旋抽囊。", "併揭聲猶遠，深含曲未央。", "坐中知密顧，微笑是周郎。"]'),
('40dbe539-a4d5-4dbf-accb-519472d8e09f','笛','張祜','唐','唐诗','tang','','[]','紫清人一管，吹在月堂中。',48,'全唐诗/poet.tang.27000.json','["紫清人一管，吹在月堂中。", "鴈起雪雲夕，龍吟煙水空。", "虜塵深漢地，羌思切邊風。", "試弄陽春曲，西園桃已紅。"]'),
('46245022-d7dc-4bff-806e-5c1c8f516c8d','舞','張祜','唐','唐诗','tang','','[]','荆臺呈妙舞，雲雨半羅衣。',48,'全唐诗/poet.tang.27000.json','["荆臺呈妙舞，雲雨半羅衣。", "褭褭腰疑折，褰褰袖欲飛。", "霧輕紅躑躅，風豔紫薔薇。", "強許傳新態，人間弟子稀。"]'),
('fb3cd026-e2b5-4438-926d-4f72a4a972b3','箜篌','張祜','唐','唐诗','tang','','[]','星漢夜牢牢，深簾調更高。',48,'全唐诗/poet.tang.27000.json','["星漢夜牢牢，深簾調更高。", "亂流公莫度，沉骨嫗空嘷。", "向月輕輪甲，迎風重紉絛。", "不堪聞別引，滄海恨波濤。"]'),
('78635faa-875b-4359-a027-9381da646165','簫','張祜','唐','唐诗','tang','','[]','清籟遠愔愔，秦樓夜思深。',48,'全唐诗/poet.tang.27000.json','["清籟遠愔愔，秦樓夜思深。", "碧空人已去，滄海鳳難尋。", "杳妙和雲絕，依微向水沉。", "還將九成意，高閣竚芳音。"]'),
('6e0fcac2-79cb-4774-8307-2f5831ef41a9','夕次桐廬','張祜','唐','唐诗','tang','','[]','百里清溪口，扁舟此去過。',48,'全唐诗/poet.tang.27000.json','["百里清溪口，扁舟此去過。", "晚潮風勢急，寒葉雨聲多。", "戍出山頭鼓，樵通竹裏歌。", "不堪無酒夜，廻首夢煙波。"]'),
('2666512f-a08f-4a6a-9043-4d053b499361','入潼關','張祜','唐','唐诗','tang','','[]','都城三百里，雄險此廻環。',48,'全唐诗/poet.tang.27000.json','["都城三百里，雄險此廻環。", "地勢遙尊嶽，河流側讓關。", "秦皇曾虎視，漢祖昔龍顏。", "何處梟兇輩，干戈自不閑。"]'),
('ab580f7a-8008-4b08-9abd-4b4f9b9b5b3c','南宮歎亦述玄宗追恨太真妃事','張祜','唐','唐诗','tang','','[]','北陸冰初結，南宮漏更長。',48,'全唐诗/poet.tang.27000.json','["北陸冰初結，南宮漏更長。", "何勞却睡草，不驗返魂香。", "月隱仙娥豔，風殘夢蝶揚。", "徒悲舊行跡，一夜玉堦霜。"]'),
('83e71318-7dd4-4abc-91cb-e6b92c9c5afc','題平望驛','張祜','唐','唐诗','tang','','[]','一派吳興水，西來此驛分。',48,'全唐诗/poet.tang.27000.json','["一派吳興水，西來此驛分。", "路遙經幾日，身去是孤雲。", "雨氣朝忙蟻，雷聲夜聚蚊。", "何堪秋草色，到處重離羣。"]'),
('a95f8c7b-64d8-40e2-8bd9-ecf99200dde3','隋宮懷古','張祜','唐','唐诗','tang','','[]','廢宮深苑路，煬帝此東行。',48,'全唐诗/poet.tang.27000.json','["廢宮深苑路，煬帝此東行。", "往事餘山色，流年是水聲。", "古牆丹雘盡，深棟黑煤生。", "惆悵從今客，經過未了情。"]'),
('eb5e6b66-7858-4ec5-9eb5-a591cdb04434','偶蘇求至話別','張祜','唐','唐诗','tang','','[]','幾年滄海別，萬里白頭吟。',48,'全唐诗/poet.tang.27000.json','["幾年滄海別，萬里白頭吟。", "夜月江流闊，春雲嶺路深。", "珠繁楊氏果，翠耀孔家禽。", "無復天南夢，相思空樹林。"]'),
('b4603701-24f5-41d8-84c6-ff0a8fb96d25','秋霽','張祜','唐','唐诗','tang','','[]','垂老歸休意，棲棲陋巷中。',48,'全唐诗/poet.tang.27000.json','["垂老歸休意，棲棲陋巷中。", "暗燈棋子落，殘語酒瓶空。", "滴羃侵簷露，虛疎入檻風。", "何妨一蟬嘒，自抱木蘭叢。"]'),
('7f8fd6c9-2031-49c5-a39e-3c843727fa8c','詠史二首 一','張祜','唐','唐诗','tang','','[]','漢代非良計，西戎世世塵。',48,'全唐诗/poet.tang.27000.json','["漢代非良計，西戎世世塵。", "無何求善馬，不筭苦生民。", "外國讐虛結，中華憤莫伸。", "却教爲後恥，昭帝遠和親。"]'),
('fe3140f6-002e-4bfd-b105-77c568031625','詠史二首 二','張祜','唐','唐诗','tang','','[]','留名魯連去，於世絕遺音。',48,'全唐诗/poet.tang.27000.json','["留名魯連去，於世絕遺音。", "盡愛聊城下，寧知滄海深。", "偶然飛一箭，無事在千金。", "迴望凌煙閣，何人是此心。"]'),
('d90a049e-fe22-46f0-bf37-11d1ebca0068','洞房燕','張祜','唐','唐诗','tang','','[]','清曉洞房開，佳人喜燕來。',48,'全唐诗/poet.tang.27000.json','["清曉洞房開，佳人喜燕來。", "乍疑釵上動，輕似掌中迴。", "暗語臨窗戶，深窺傍鏡臺。", "新妝正含思，莫拂畫梁埃。"]'),
('1be19bff-39d7-4e19-b4c6-708e8bb4564b','答僧贈柱杖','張祜','唐','唐诗','tang','','[]','千迴掌上橫，珍重遠方情。',48,'全唐诗/poet.tang.27000.json','["千迴掌上橫，珍重遠方情。", "客問何人與，閩僧寄一莖。", "畫空疑未決，卓地計初成。", "幸以文堪採，扶持力不輕。"]'),
('4e1cb3e8-eede-4bcc-8436-afad4811972e','鷺鷥','張祜','唐','唐诗','tang','','[]','深窺思不窮，揭趾淺沙中。',48,'全唐诗/poet.tang.27000.json','["深窺思不窮，揭趾淺沙中。", "一點山光淨，孤飛潭影空。", "暗棲松葉露，雙下蓼花風。", "好是滄波侶，垂絲趣亦同。"]'),
('31739c8a-53cb-453e-ac6f-882d7d4a0e35','塞下','張祜','唐','唐诗','tang','','[]','萬里配長征，連年慣野營。',48,'全唐诗/poet.tang.27000.json','["萬里配長征，連年慣野營。", "入羣來揀馬，拋伴去擒生。", "箭插雕翎闊，弓盤鵲角輕。", "問看行近遠，西去受降城。"]'),
('1f9d3623-c289-42c7-bb56-173019420a88','憶雲陽宅','張祜','唐','唐诗','tang','','[]','一別雲陽宅，深愁度歲華。',48,'全唐诗/poet.tang.27000.json','["一別雲陽宅，深愁度歲華。", "翠濃春檻柳，紅滿夜庭花。", "鳥影垂纖竹，魚行踐淺沙。", "聊當因寤寐，歸思浩無涯。"]'),
('d91195b6-b050-4d82-8f0c-eea6f7621ee2','題造微禪師院','張祜','唐','唐诗','tang','','[]','夜香聞偈後，岑寂掩雙扉。',48,'全唐诗/poet.tang.27000.json','["夜香聞偈後，岑寂掩雙扉。", "照竹燈和雪，穿雲月到衣。", "草堂疎磬斷，江寺故人稀。", "唯憶江南雨，春風獨鳥歸。"]'),
('ed6c65a3-54f8-44c0-8efc-4d2139835842','酬武藴之乙丑之歲始見華髮余自悲遂成繼和','張祜','唐','唐诗','tang','','[]','賈生年尚少，華髮近相侵。',48,'全唐诗/poet.tang.27000.json','["賈生年尚少，華髮近相侵。", "不是流光促，因緣別恨深。", "憐君成苦調，感我獨長吟。", "豈料清秋日，星星共映簪。"]'),
('0389ac55-6fe0-4775-a662-1e40f2bcca50','題萬道人禪房','張祜','唐','唐诗','tang','','[]','何處鑿禪壁，西南江上峰。',48,'全唐诗/poet.tang.27000.json','["何處鑿禪壁，西南江上峰。", "殘陽過遠水，落葉滿疎鐘。", "世事靜中去，道心塵外逢。", "欲知情不動，牀下虎留蹤。"]'),
('1239a628-d570-4564-8b09-26069f02d4d0','病後訪山客','張祜','唐','唐诗','tang','','[]','久病倦衾枕，獨行來訪君。',48,'全唐诗/poet.tang.27000.json','["久病倦衾枕，獨行來訪君。", "因逢歸馬客，共對出溪雲。", "新月坐中見，暮蟬愁處聞。", "相歡貴無事，莫想路歧分。"]'),
('3b2ecfea-a5dd-40ea-86f9-1b8d518fca48','題松汀驛','張祜','唐','唐诗','tang','','[]','山色遠含空，蒼茫澤國東。',48,'全唐诗/poet.tang.27000.json','["山色遠含空，蒼茫澤國東。", "海明先見日，江白逈聞風。", "鳥道高原去，人煙小徑通。", "那知舊遺逸，不在五湖中。"]'),
('022b9dfe-8b9e-4a06-94c4-fc80ad85d73c','處士隱居','張祜','唐','唐诗','tang','','[]','斜日半飛閤，高簾輕翳空。',48,'全唐诗/poet.tang.27000.json','["斜日半飛閤，高簾輕翳空。", "清香芙蓉水，碧冷琅玕風。", "絕岸派沿洑，修廊趾崇隆。", "唯當餌仙朮，坐作朱顏翁。"]'),
('e7b46a9e-9dd8-444c-baa2-645422ee243a','早春錢塘湖晚眺','張祜','唐','唐诗','tang','','["\u897f\u6e56"]','落日下林坂，撫襟睇前蹤。',48,'全唐诗/poet.tang.27000.json','["落日下林坂，撫襟睇前蹤。", "輕澌流迴浦，殘雪明高峰。", "仰視天宇曠，俯登雲樹重。", "聊當問真界，昨夜西巒鐘。"]'),
('a333076f-418d-4a0e-b2df-d6cb6cc2d3bf','濠州水館','張祜','唐','唐诗','tang','','[]','高閣去煩燠，客心遂安舒。',48,'全唐诗/poet.tang.27000.json','["高閣去煩燠，客心遂安舒。", "清流中浴鳥，白石下遊魚。", "秋樹色凋翠，夜橋聲褭虛。", "南軒更何待，坐見玉蟾蜍。"]'),
('f3a2fec4-5ca6-49b4-b91f-d15b6183b1e0','石頭城寺','張祜','唐','唐诗','tang','','[]','山勢抱煙光，重門突兀傍。',48,'全唐诗/poet.tang.27000.json','["山勢抱煙光，重門突兀傍。", "連簷金像閣，半壁石龕廊。", "碧樹藂高頂，清池占下方。", "徒悲宦遊意，盡日老僧房。"]'),
('6d98867a-8ee3-455c-937e-e139e8872671','傷遷客歿南中','張祜','唐','唐诗','tang','','[]','故人何處歿，謫宦極南天。',48,'全唐诗/poet.tang.27000.json','["故人何處歿，謫宦極南天。", "遠地身狼狽，窮途事果然。", "白鬚纔過海，丹旐却歸船。", "腸斷相逢路，新來客又遷。"]'),
('debd62ef-a8e3-4f3a-a5c1-50f9e43627fa','烏夜啼','張祜','唐','唐诗','tang','','[]','忽忽南飛返，危絲共怨悽。',48,'全唐诗/poet.tang.27000.json','["忽忽南飛返，危絲共怨悽。", "暗霜移樹宿，殘夜遶枝啼。", "咽絕聲重敘，愔淫思乍迷。", "不妨還報喜，悞使玉顏低。"]'),
('97e6ffa3-42a8-40da-b43b-b91972fc3d1e','題潤州金山寺','張祜','唐','唐诗','tang','','[]','一宿金山寺，超然離世羣。',48,'全唐诗/poet.tang.27000.json','["一宿金山寺，超然離世羣。", "僧歸夜船月，龍出曉堂雲。", "樹色中流見，鐘聲兩岸聞。", "翻思在朝市，終日醉醺醺。"]'),
('d48d14df-81c4-4f6a-aeac-deaf91f0aa63','題潤州甘露寺','張祜','唐','唐诗','tang','','[]','千重構橫險，高步出塵埃。',48,'全唐诗/poet.tang.27000.json','["千重構橫險，高步出塵埃。", "日月光先見，江山勢盡來。", "冷雲歸水石，清露滴樓臺。", "況是東溟上，平生意一開。"]'),
('01d61dfa-6c6e-421d-a5b3-c7db62f9d7fe','題杭州孤山寺','張祜','唐','唐诗','tang','','[]','樓臺聳碧岑，一徑入湖心。',48,'全唐诗/poet.tang.27000.json','["樓臺聳碧岑，一徑入湖心。", "不雨山長潤，無雲水自陰。", "斷橋荒蘚澀，空院落花深。", "猶憶西窗月，鐘聲在北林。"]'),
('00437c8e-467d-42ab-95f2-8f5861dcac31','題餘杭縣龍泉觀','張祜','唐','唐诗','tang','','[]','四迴山一面，臺殿已嵯峨。',48,'全唐诗/poet.tang.27000.json','["四迴山一面，臺殿已嵯峨。", "中路見山遠，上方行石多。", "天晴花氣漫，地煖鳥音和。", "徒漱葛仙井，此生其奈何。"]'),
('84c7b669-bfce-421f-97f7-1c1c2c830deb','題徑山大覺禪師影堂','張祜','唐','唐诗','tang','','[]','超然彼岸人，一徑謝微塵。',48,'全唐诗/poet.tang.27000.json','["超然彼岸人，一徑謝微塵。", "見相即非相，觀身豈是身。", "空門性未滅，舊里化猶新。", "謾指堂中影，誰言影似真。"]'),
('edce7bfc-ef8e-4368-9b92-7a1a5ab22a9c','題濠州鍾離寺','張祜','唐','唐诗','tang','','[]','遙遙東郭寺，數里占原田。',48,'全唐诗/poet.tang.27000.json','["遙遙東郭寺，數里占原田。", "遠岫碧光合，長淮清派連。", "院藏歸鳥樹，鐘到落帆船。", "唯羨空門叟，棲心盡百年。"]'),
('ec6c2efd-5898-4304-a7a5-cc0b53fd77ee','秋夜宿靈隱寺師上人','張祜','唐','唐诗','tang','','[]','月色荒城外，江聲野寺中。',48,'全唐诗/poet.tang.27000.json','["月色荒城外，江聲野寺中。", "貧知交道薄，老信釋門空。", "露葉凋堦蘚，風枝戞井桐。", "不妨無酒夜，閑話值生公。"]'),
('bf00650b-5f81-4662-a1c3-6057ad702e4b','題蘇州靈巖寺','張祜','唐','唐诗','tang','','[]','碧海西陵岸，吳王此盛時。',48,'全唐诗/poet.tang.27000.json','["碧海西陵岸，吳王此盛時。", "山行今佛寺，水見舊宮池。", "亡國人遺恨，空門事少悲。", "聊當值僧語，盡日把松枝。"]'),
('69bcb23b-61c1-4621-8b2c-566979560625','題蘇州楞伽寺','張祜','唐','唐诗','tang','','[]','樓臺山半腹，又此一經行。',48,'全唐诗/poet.tang.27000.json','["樓臺山半腹，又此一經行。", "樹隔夫差苑，溪連句踐城。", "上坡松徑澀，深坐石池清。", "況是西峰頂，淒涼故國情。"]'),
('e9a7953f-cdb6-4320-8e09-e5c10ec98a38','題蘇州思益寺','張祜','唐','唐诗','tang','','[]','四面山形斷，樓臺此逈臨。',48,'全唐诗/poet.tang.27000.json','["四面山形斷，樓臺此逈臨。", "兩峰高崪屼，一水下淫滲。", "鑿石西龕小，穿松北塢深。", "會當來結社，長日爲僧吟。"]'),
('b31f5017-c4eb-40c7-b471-4324303e780e','題重居寺','張祜','唐','唐诗','tang','','[]','浮圖經近郭，長日羨僧閑。',48,'全唐诗/poet.tang.27000.json','["浮圖經近郭，長日羨僧閑。", "竹徑深開院，松門遠對山。", "重廊標板榜，高殿鎖金環。", "更問尋雷室，西行咫尺間。"]'),
('d5a42c23-c204-439b-b183-beaf340447a2','題善權寺','張祜','唐','唐诗','tang','','[]','碧峰南一寺，最勝是仙源。',48,'全唐诗/poet.tang.27000.json','["碧峰南一寺，最勝是仙源。", "峻坂依巖壁，清泉泄洞門。", "金函崇寶藏，玉樹閟靈根。", "寄謝香花叟，高蹤不可援。"]'),
('cbdc815b-beef-4b44-b0fa-1827783a7311','題南陵隱靜寺','張祜','唐','唐诗','tang','','[]','松逕上登攀，深行煙靄間。',48,'全唐诗/poet.tang.27000.json','["松逕上登攀，深行煙靄間。", "合流廚下水，對聳殿前山。", "潤壁鳥音逈，泉源僧步閑。", "更憐飛一錫，天外與雲還。"]'),
('8b0ad859-5403-4a15-949d-3eca181c104b','題丘山寺','張祜','唐','唐诗','tang','','[]','幾代儒家業，何年佛寺碑。',48,'全唐诗/poet.tang.27000.json','["幾代儒家業，何年佛寺碑。", "地平邊海處，江出上山時。", "故國人長往，空門事可知。", "淒涼問禪客，身外即無爲。"]'),
('d2eb9f22-3cee-4a3c-912b-5517e5b62b0e','題道光上人山院','張祜','唐','唐诗','tang','','[]','真僧上方界，山路正巖巖。',48,'全唐诗/poet.tang.27000.json','["真僧上方界，山路正巖巖。", "地僻泉長冷，亭香草不凡。", "火田生白菌，煙岫老青杉。", "盡日唯山水，當知律行嚴。"]'),
('6c0b135c-2944-43fa-9f8d-710552aa51cb','贈廬山僧','張祜','唐','唐诗','tang','','["\u5e90\u5c71"]','一室鑪峰下，荒榛手自開。',48,'全唐诗/poet.tang.27000.json','["一室鑪峰下，荒榛手自開。", "粉牌新薤葉，竹援小葱臺。", "樹黑雲歸去，山明日上來。", "便知心是佛，堅坐對寒灰。"]'),
('e2784a5e-182e-46d2-8c43-e31f57071b05','題惠山寺','張祜','唐','唐诗','tang','','[]','舊宅人何在，空門客自過。',48,'全唐诗/poet.tang.27000.json','["舊宅人何在，空門客自過。", "泉聲到池盡，山色上樓多。", "小洞生斜竹，重堦夾細莎。", "殷勤望城市，雲水暮鐘和。"]'),
('e3c02394-0732-4cea-b2bb-c794309774fb','題虎丘寺','張祜','唐','唐诗','tang','','[]','輕櫂駐廻流，門登西虎丘。',48,'全唐诗/poet.tang.27000.json','["輕櫂駐廻流，門登西虎丘。", "霧青山月曉，雲白海天秋。", "倚殿松株澀，欹庭石片幽。", "青蛾幾時墓，空色尚悠悠。"]'),
('c5b7b747-6561-4c1d-a7f6-a2fe20bcfa79','題普賢寺','張祜','唐','唐诗','tang','','[]','何人知寺路，松竹暗春山。',48,'全唐诗/poet.tang.27000.json','["何人知寺路，松竹暗春山。", "潭黑龍應在，巢空鶴未還。", "經年來客倦，半日與僧閑。", "更共嘗新茗，聞鐘笑語間。"]'),
('00efc79c-9bb4-422b-91ef-17b63f75e523','題虎丘東寺','張祜','唐','唐诗','tang','','[]','雲樹擁崔嵬，深行異俗埃。',48,'全唐诗/poet.tang.27000.json','["雲樹擁崔嵬，深行異俗埃。", "寺門山外入，石壁地中開。", "仰砌池光動，登樓海氣來。", "傷心萬古意，金玉葬寒灰。"]'),
('4dee45ee-d6ab-412c-af24-f2a9eb1eac05','題虎丘西寺','張祜','唐','唐诗','tang','','[]','囂塵楚城外，一寺枕通波。',48,'全唐诗/poet.tang.27000.json','["囂塵楚城外，一寺枕通波。", "松色入門遠，岡形連院多。", "花時長到處，別路半經過。", "惆悵舊禪客，空房深薜蘿。"]'),
('05b8984a-df8b-4921-9f58-1ab8e47143aa','題招隱寺','張祜','唐','唐诗','tang','','[]','千年戴顒宅，佛廟此崇修。',48,'全唐诗/poet.tang.27000.json','["千年戴顒宅，佛廟此崇修。", "古井人名在，清泉鹿跡幽。", "竹光寒閉院，山影夜藏樓。", "未得高僧旨，烟霞空暫游。"]'),
('d0e3011b-1b79-4444-bb8a-8b48a73833d5','塞下曲','張祜','唐','唐诗','tang','','[]','二十逐嫖姚，分兵遠戍遼。',48,'全唐诗/poet.tang.27000.json','["二十逐嫖姚，分兵遠戍遼。", "雪迷經塞夜，冰壯渡河朝。", "促放雕難下，生騎馬未調。", "小儒何足問，看取劒橫腰。"]'),
('f3b29b23-4f34-431a-b26b-cdcc116d485c','宿淮陰水館','張祜','唐','唐诗','tang','','[]','積水自成陰，昏昏月映林。',48,'全唐诗/poet.tang.27000.json','["積水自成陰，昏昏月映林。", "五更離浦櫂，一夜隔淮砧。", "漂母鄉非遠，王孫道豈沉。", "不當無健嫗，誰肯效前心。"]'),
('5f908feb-281c-4a58-8a88-bcef641a0ded','題小松','張祜','唐','唐诗','tang','','[]','何處斸雲煙，新移此館前。',48,'全唐诗/poet.tang.27000.json','["何處斸雲煙，新移此館前。", "碧姿塵不染，清影露長鮮。", "聳地心纔直，凌雲操未全。", "可悲人自老，何日是千年。"]'),
('06798167-53e9-4e1b-b84f-b150edd78eac','夏日梅溪館寄龐舍人','張祜','唐','唐诗','tang','','[]','東陽賓禮重，高館望行期。',48,'全唐诗/poet.tang.27000.json','["東陽賓禮重，高館望行期。", "埽簟因松葉，篸瓜使竹枝。", "捲簾聞鳥近，翻枕夢人遲。", "坐聽津橋說，今營太守碑。"]'),
('e1baf79d-303c-4618-880a-4def8c930a78','感河上兵','張祜','唐','唐诗','tang','','[]','一聞河塞上，非是欲權兵。',48,'全唐诗/poet.tang.27000.json','["一聞河塞上，非是欲權兵。", "首尾誠須畏，膏肓慎勿輕。", "多門徒可入，盡室且思行。", "莫爲無媒者，滄浪不濯纓。"]'),
('9386657b-8cda-4db1-858e-5a8383d6314d','贈淮南將','張祜','唐','唐诗','tang','','[]','年少好風情，垂鞭眦睚行。',48,'全唐诗/poet.tang.27000.json','["年少好風情，垂鞭眦睚行。", "帶金獅子小，裘錦麒麟獰。", "揀匠裝銀鐙，堆錢買鈿箏。", "李陵雖效死，時論亦輕生。"]'),
('306a632c-38f4-4f3e-836b-dfa2bf80fcfc','題惠昌上人','張祜','唐','唐诗','tang','','[]','半巖開一室，香穟細氛氳。',48,'全唐诗/poet.tang.27000.json','["半巖開一室，香穟細氛氳。", "石上漱秋水，月中行夏雲。", "律持僧講疏，經誦梵書文。", "好是風廊下，遙遙挂褐裙。"]'),
('0bf0531a-3cb5-4466-a9cc-f6c4f17ff105','塞上曲','張祜','唐','唐诗','tang','','[]','邊風捲地時，日暮帳初移。',48,'全唐诗/poet.tang.27000.json','["邊風捲地時，日暮帳初移。", "磧逈三通角，山寒一點旗。", "連收榻索馬，引滿射雕兒。", "莫道功勳細，將軍昔戍師。"]'),
('32bc27d8-4816-4861-8d31-7f16bfee4a7b','折楊柳','張祜','唐','唐诗','tang','','[]','紅粉青樓曙，垂楊仲月春。',48,'全唐诗/poet.tang.27000.json','["紅粉青樓曙，垂楊仲月春。", "懷君重攀折，非妾妬腰身。", "舞帶縈絲斷，嬌娥向葉嚬。", "橫吹凡幾曲，獨自最愁人。"]'),
('457215d8-5b31-4dd1-a740-44782cc8d86e','採桑','張祜','唐','唐诗','tang','','[]','自古多征戰，由來尚甲兵。',48,'全唐诗/poet.tang.27000.json','["自古多征戰，由來尚甲兵。", "長驅千里去，一舉兩番平。", "按劒從沙漠，歌謠滿帝京。", "寄言天下將，須立武功名。"]'),
('611b2dc6-4b63-43d0-abd9-756e35877aa1','禪智寺','張祜','唐','唐诗','tang','','[]','寶殿依山嶮，臨虛勢若吞。',48,'全唐诗/poet.tang.27000.json','["寶殿依山嶮，臨虛勢若吞。", "畫簷齊木末，香砌壓雲根。", "遠景窗中岫，孤煙竹裏村。", "憑高聊一望，鄉思隔吳門。"]'),
('65a085c2-ae00-48e8-bd5b-e90e75ac846b','寄題商洛王隱居','張祜','唐','唐诗','tang','','[]','近逢商洛口，知爾坐南塘。',48,'全唐诗/poet.tang.27000.json','["近逢商洛口，知爾坐南塘。", "草閣平春水，柴門掩夕陽。", "隨蜂收野蜜，尋麝採生香。", "更憶前年醉，松花滿石牀。"]'),
('c262e600-c86e-4305-a903-07c6c0095a5d','送客歸湘楚','張祜','唐','唐诗','tang','','[]','無辭一杯酒，昔日與君深。',48,'全唐诗/poet.tang.27000.json','["無辭一杯酒，昔日與君深。", "秋色換歸鬢，曙光生別心。", "桂花山廟冷，楓樹水樓陰。", "此路千餘里，應勞楚客吟。"]'),
('fe9a5351-1a97-4423-b912-224a05f6f7ac','登金山寺','張祜','唐','唐诗','tang','','[]','古今斯島絕，南北大江分。',48,'全唐诗/poet.tang.27000.json','["古今斯島絕，南北大江分。", "水闊吞滄海，亭高宿斷雲。", "返潮千澗落，啼鳥半空聞。", "皆是登臨處，歸航酒半醺。"]'),
('432793dc-50bb-4dfc-8cad-af3bc0cc759f','洛陽感寓','張祜','唐','唐诗','tang','','[]','擾擾都城曉四開，不關名利也塵埃。',64,'全唐诗/poet.tang.27000.json','["擾擾都城曉四開，不關名利也塵埃。", "千門甲第身遙入，萬里銘旌死後來。", "洛水暮煙橫莽蒼，邙山秋日露崔嵬。", "須知此事堪爲鏡，莫遣黃金漫作堆。"]'),
('81852780-9711-4914-9ec8-02518757ca1f','從軍行','張祜','唐','唐诗','tang','','[]','少年金紫就光輝，直指邊城虎翼飛。',64,'全唐诗/poet.tang.27000.json','["少年金紫就光輝，直指邊城虎翼飛。", "一卷旌收千騎虜，萬全身出百重圍。", "黃雲斷塞尋鷹去，白草連天射鴈歸。", "白首漢廷刀筆吏，丈夫功業本相依。"]'),
('53de701e-8484-436d-96c1-baa1a45a3c05','愛妾換馬 一','張祜','唐','唐诗','tang','','[]','一面妖桃千里蹄，嬌姿駿骨價應齊。',64,'全唐诗/poet.tang.27000.json','["一面妖桃千里蹄，嬌姿駿骨價應齊。", "乍牽玉勒辭金棧，催整花鈿出繡閨。", "去日豈無沾袂泣，歸時還有頓銜嘶。", "嬋娟躞蹀春風裏，揮手搖鞭楊柳隄。"]'),
('2fb21aab-5fbe-48c0-a2cd-115f3f176a36','愛妾換馬 二','張祜','唐','唐诗','tang','','[]','綺閣香銷華廐空，忍將行雨換追風。',64,'全唐诗/poet.tang.27000.json','["綺閣香銷華廐空，忍將行雨換追風。", "休憐柳葉雙眉翠，卻愛桃花兩耳紅。", "侍宴永辭春色裏，趁朝休立漏聲中。", "恩勞未盡情先盡，暗泣嘶風兩意同。"]'),
('b680d1fe-bf1e-4466-974a-de893bbf9b2a','病宮人','張祜','唐','唐诗','tang','','[]','佳人臥病動經秋，簾幕繿縿不挂鉤。',64,'全唐诗/poet.tang.27000.json','["佳人臥病動經秋，簾幕繿縿不挂鉤。", "四體強扶藤夾膝，雙鬟慵插玉搔頭。", "花顏有幸君王問，藥餌無徵待詔愁。", "惆悵近來消瘦盡，淚珠時傍枕函流。"]'),
('f11908ea-5957-4516-9d5b-469e17951926','觀杭州柘枝','張祜','唐','唐诗','tang','','[]','舞停歌罷鼓連摧，軟骨仙蛾暫起來。',64,'全唐诗/poet.tang.27000.json','["舞停歌罷鼓連摧，軟骨仙蛾暫起來。", "紅罨畫衫纏腕出，碧排方胯背腰來。", "旁收拍拍金鈴擺，却踏聲聲錦袎摧。", "看著遍頭香袖褶，粉屏香帕又重隈。"]'),
('3aa73b90-73e9-4c75-a9aa-1674237b18af','周員外席上觀柘枝','張祜','唐','唐诗','tang','','[]','畫鼓拖環錦臂攘，小娥雙換舞衣裳。',64,'全唐诗/poet.tang.27000.json','["畫鼓拖環錦臂攘，小娥雙換舞衣裳。", "金絲蹙霧紅衫薄，銀蔓垂花紫帶長。", "鸞影乍迴頭並舉，鳳聲初歇翅齊張。", "一時欻腕招殘拍，斜斂輕身拜玉郎。"]'),
('e1b77311-782a-4896-ae57-eba253485995','觀楊瑗柘枝','張祜','唐','唐诗','tang','','[]','促疊蠻鼉引柘枝，卷簷虛帽帶交垂。',64,'全唐诗/poet.tang.27000.json','["促疊蠻鼉引柘枝，卷簷虛帽帶交垂。", "紫羅衫宛蹲身處，紅錦靴柔踏節時。", "微動翠蛾拋舊態，緩遮檀口唱新詞。", "看看舞罷輕雲起，却赴襄王夢裏期。"]'),
('a11bdd12-03f3-452b-bede-bf2285567cf7','感王將軍柘枝妓歿','張祜','唐','唐诗','tang','','[]','寂寞春風舊柘枝，舞人休唱曲休吹。',64,'全唐诗/poet.tang.27000.json','["寂寞春風舊柘枝，舞人休唱曲休吹。", "鴛鴦鈿帶拋何處，孔雀羅衫付阿誰。", "畫鼓不聞招節拍，錦靴空想挫腰肢。", "今來座上偏惆悵，曾是堂前教徹時。"]'),
('961ac853-eb63-4444-8981-1b7cadbf7b0a','揚州法雲寺雙檜','張祜','唐','唐诗','tang','','[]','謝家雙植本圖榮，樹老人因地變更。',64,'全唐诗/poet.tang.27000.json','["謝家雙植本圖榮，樹老人因地變更。", "朱頂鶴知深蓋偃，白眉僧見小枝生。", "高臨月殿秋雲影，靜入風簷夜雨聲。", "縱使百年爲上壽，綠陰終借暫時行。"]'),
('2779692f-7f70-4a58-b21d-3bdc8901aed4','憶游天台寄道流','張祜','唐','唐诗','tang','','[]','憶昨天台到赤城，幾朝仙籟耳中生。',48,'全唐诗/poet.tang.27000.json','["憶昨天台到赤城，幾朝仙籟耳中生。", "雲龍出水風聲過，海鶴鳴臯日色清。", "石筍半山移步險，桂花當洞拂衣輕。"]'),
('3372ccf7-d860-40e8-997f-cf7c6b84e045','寄王尊師','張祜','唐','唐诗','tang','','[]','天台南洞一靈仙，骨聳冰稜貌瑩然。',64,'全唐诗/poet.tang.27000.json','["天台南洞一靈仙，骨聳冰稜貌瑩然。", "曾對浦雲長昧齒，重來華表不知年。", "溪橋晚下玄龜出，草露朝行白鹿眠。", "猶憶夜深華蓋上，更無人處話丹田。"]'),
('10bddc06-23bd-46ad-8693-0baacfde429a','公子行','張祜','唐','唐诗','tang','','[]','錦堂晝永繡簾垂，立却花驄待出時。',64,'全唐诗/poet.tang.27000.json','["錦堂晝永繡簾垂，立却花驄待出時。", "紅粉美人擎酒勸，青衣年少臂鷹隨。", "輕將玉杖敲花片，旋把金鞭約柳枝。", "近地獨遊三五騎，等閑行傍曲江池。"]'),
('58555a27-99b1-4882-871a-ad83bf29e326','寓懷寄蘇州劉郎中','張祜','唐','唐诗','tang','','[]','一聞周召佐明時，西望都門強策羸。',64,'全唐诗/poet.tang.27000.json','["一聞周召佐明時，西望都門強策羸。", "天子好文才自薄，諸侯力薦命猶奇。", "賀知章口徒勞說，孟浩然身更不疑。", "唯是勝遊行未遍，欲離京國尚遲遲。"]'),
('50ccdb84-ebf0-4305-82ed-1fb40aa437f7','和杜牧之齊山登高','張祜','唐','唐诗','tang','','[]','秋溪南岸菊霏霏，急管煩弦對落暉。',64,'全唐诗/poet.tang.27000.json','["秋溪南岸菊霏霏，急管煩弦對落暉。", "紅葉樹深山徑斷，碧雲江靜浦帆稀。", "不堪孫盛嘲時笑，願送王弘醉夜歸。", "流落正憐芳意在，砧聲徒促授寒衣。"]'),
('00fd873f-2d0c-4a25-9293-993e9b6c5c83','題于越亭','張祜','唐','唐诗','tang','','[]','扁舟亭下駐煙波，十五年遊重此過。',64,'全唐诗/poet.tang.27000.json','["扁舟亭下駐煙波，十五年遊重此過。", "洲觜露沙人渡淺，樹稍藏竹鳥啼多。", "山銜落照欹紅蓋，水蹙斜文捲綠羅。", "腸斷中秋正圓月，夜來誰唱異鄉歌。"]'),
('157a64a0-b1f1-438e-9084-f57426ddd787','秋夜登潤州慈和寺上方','張祜','唐','唐诗','tang','','[]','清夜浮埃暫歇鄽，塔輪金照露華鮮。',64,'全唐诗/poet.tang.27000.json','["清夜浮埃暫歇鄽，塔輪金照露華鮮。", "人行中路月生海，鶴語上方星滿天。", "樓影半連深岸水，鐘聲寒徹遠林煙。", "僧房閉盡下樓去，一半夢魂離世緣。"]'),
('c0de8d08-bafb-4837-a151-54eada922d85','寄獻蕭相公','張祜','唐','唐诗','tang','','[]','東去江干是勝遊，鼎湖興望不堪愁。',64,'全唐诗/poet.tang.27000.json','["東去江干是勝遊，鼎湖興望不堪愁。", "謝安近日違朝旨，傅說當時允帝求。", "暫向聊城飛一箭，長爲滄海繫扁舟。", "分明此事無人見，白首相看未肯休。"]'),
('0ba7afd7-757e-4c18-8219-c58cc11fb9f6','哭京兆龐尹','張祜','唐','唐诗','tang','','[]','楊子江頭昔共迷，一爲京兆隔雲泥。',64,'全唐诗/poet.tang.27000.json','["楊子江頭昔共迷，一爲京兆隔雲泥。", "故人昨日同時弔，舊馬今朝別處嘶。", "向壁愁眉無復畫，扶牀稚齒已能啼。", "也知世路名堪貴，誰信莊周論物齊。"]'),
('3e66d9b7-7d38-48ef-8ab5-2f4f2c4de829','送周尚書赴滑臺','張祜','唐','唐诗','tang','','[]','楚謠襦袴整三年，喉舌新恩下九天。',64,'全唐诗/poet.tang.27000.json','["楚謠襦袴整三年，喉舌新恩下九天。", "鼓角雄都分節鉞，蛇龍舊國罷樓船。", "崑河已在兵鈐內，堂柳空留鶴嶺前。", "多病無由酬一顧，鄢陵千騎去翩翩。"]'),
('22d6a17d-b08b-4ed5-89a7-147753166d24','和杜使君九華樓見寄','張祜','唐','唐诗','tang','','[]','孤城高柳曉鳴鴉，風簾半鉤清露華。',64,'全唐诗/poet.tang.27000.json','["孤城高柳曉鳴鴉，風簾半鉤清露華。", "九峰聚翠宿危檻，一夜孤光懸冷沙。", "出岸遠暉帆欲落，入谿寒影鴈差斜。", "杜陵歸去春應早，莫厭青山謝朓家。"]'),
('75df160d-ca74-43bc-91e8-cf4ca83929d1','送人歸蜀','張祜','唐','唐诗','tang','','[]','錦城春色泝江源，三峽經過幾夜猨。',64,'全唐诗/poet.tang.27000.json','["錦城春色泝江源，三峽經過幾夜猨。", "紅樹兩厓開霽色，碧巖千仞漲波痕。", "蕭蕭暮雨荆王夢，漠漠春煙蜀帝魂。", "長怨相如留滯處，富家還憶卓王孫。"]'),
('0bda5e94-938b-4bdf-95ec-3d820a8c9e24','酬答柳宗言秀才見贈','張祜','唐','唐诗','tang','','[]','南下天台厭絕冥，五湖波上汎如萍。',64,'全唐诗/poet.tang.27000.json','["南下天台厭絕冥，五湖波上汎如萍。", "江鷗自戲爲蹤跡，野鹿閑驚是性靈。", "任子偶垂滄海釣，戴逵虛認少微星。", "金門後俊徒相唁，且爲人間寄茯苓。"]'),
('74184ddc-8468-479e-aa57-fbf1b33c4cf1','題杭州天竺寺','張祜','唐','唐诗','tang','','[]','西南山最勝，一界是諸天。',72,'全唐诗/poet.tang.27000.json','["西南山最勝，一界是諸天。", "上路穿巖竹，分流入寺泉。", "躡雲丹井畔，望月石橋邊。", "洞壑江聲遠，樓臺海氣連。", "塔明春嶺雪，鐘散暮松煙。", "何處去猶恨，更看峰頂蓮。"]'),
('9f664fc6-608d-42f2-b58c-ef3c705ebf84','題杭州靈隱寺','張祜','唐','唐诗','tang','','[]','峰巒開一掌，朱檻幾環延。',72,'全唐诗/poet.tang.27000.json','["峰巒開一掌，朱檻幾環延。", "佛地花分界，僧房竹引泉。", "五更樓下月，十里郭中煙。", "後塔聳亭後，前山橫閣前。", "溪沙涵水靜，澗石點苔鮮。", "好是呼猨久，西巖深響連。"]'),
('a52e078a-29ee-4bf2-ab6b-c52ee818fd23','中秋夜杭州翫月','張祜','唐','唐诗','tang','','[]','萬古太陰精，中秋海上生。',96,'全唐诗/poet.tang.27000.json','["萬古太陰精，中秋海上生。", "鬼愁緣辟照，人愛爲高明。", "歷歷華星遠，霏霏薄暈縈。", "影流江不盡，輪曳谷無聲。", "似鏡當樓曉，如珠出浦盈。", "岸沙全借白，山木半含清。", "小檻循環看，長堤蹋陣行。", "殷勤未歸客，煙水夜來情。"]'),
('4580450e-054a-41ee-ac7c-d573941e213f','高閑上人','張祜','唐','唐诗','tang','','[]','座上辭安國，禪房戀沃州。',96,'全唐诗/poet.tang.27000.json','["座上辭安國，禪房戀沃州。", "道心黃葉老，詩思碧雲秋。", "卷軸朝廷餞，書函內庫收。", "陶欣入社叟，生怯論經儔。", "日色屏初揭，風聲筆未休。", "長波溢海岸，大點出嵩丘。", "不絕羲之法，難窮智永流。", "殷勤一牋在，留著看銀鉤。"]'),
('679f1a3f-383d-4647-b6d2-8988e4267c73','題靈隱寺師一上人十韻','張祜','唐','唐诗','tang','','[]','八十空門子，深山土木骸。',120,'全唐诗/poet.tang.27000.json','["八十空門子，深山土木骸。", "片衣閑自衲，單食老長齋。", "道性終能遣，人情少不乖。", "樔枸居上院，薜荔俯層階。", "洗鉢前臨水，窺門外有柴。", "朗吟揮竹拂，高楫曳芒鞋。", "迸笋斜穿塢，飛泉下噴崖。", "種花忻土潤，撥石慮沙埋。", "舊往師招隱，初臨我詠懷。", "何當緣興翫，更爲表新牌。"]'),
('a2fc68e1-b766-4d04-b8f0-26d923b4e5b0','投常州從兄中丞','張祜','唐','唐诗','tang','','[]','扁舟何所往，言入善人邦。',120,'全唐诗/poet.tang.27000.json','["扁舟何所往，言入善人邦。", "舊愛鵬摶海，今聞虎渡江。", "士因爲政樂，儒爲說詩降。", "素履冰容靜，新詞玉潤樅。", "金魚聊解帶，畫鷁稍移樁。", "邀妓思逃席，留賓命倒缸。", "史材誰是伍，經術世無雙。", "廣廈當宏構，洪鐘併待撞。", "成龍須講邴，展驥莫先龐。", "應念宗中末，秋螢照一牕。"]'),
('738ea38e-7926-44cc-9ace-b644f3b4deac','送王昌涉侍御','張祜','唐','唐诗','tang','','[]','十里指東平，軍前首出征。',96,'全唐诗/poet.tang.27000.json','["十里指東平，軍前首出征。", "諸侯青服舊，御史紫衣榮。", "入陳梟心死，分圍虎力生。", "畫時安楚塞，刻日下齊城。", "號令朝移幕，偷蹤夜斫營。", "雲梯曾險上，地道慣深行。", "舉斾招降將，投戈趁敗兵。", "自慙居虜者，當此立功名。"]'),
('5040a6b9-8575-4978-ae5f-eddedd82026f','少年樂','張祜','唐','唐诗','tang','','[]','二十便封侯，名居第一流。',72,'全唐诗/poet.tang.27000.json','["二十便封侯，名居第一流。", "綠鬟深小院，清管下高樓。", "醉把金船擲，閑敲玉鐙遊。", "帶盤紅鼴鼠，袍砑紫犀牛。", "錦袋歸調箭，羅鞋起撥毬。", "眼前長貴盛，那信世間愁。"]'),
('3880dd89-5719-4fa5-82e2-86bf6329a9d3','華清宮和杜舍人','張祜','唐','唐诗','tang','','[]','五十年天子，離宮舊粉牆。',288,'全唐诗/poet.tang.27000.json','["五十年天子，離宮舊粉牆。", "登封時正泰，御宇日初長。", "上位先名實，中興事憲章。", "舉戎輕甲胄，餘地取河湟。", "道帝玄元祖，儒封孔子王。", "因緣百司署，藂會一人湯。", "渭水波搖綠，秦山草半黃。", "馬頭開夜照，鷹眼利星芒。", "下箭朱弓滿，鳴鞭皓腕攘。", "畋思獲呂望，諫祇避周昌。", "兔迹貪前逐，梟心不早防。", "幾添鸚鵡勸，頻賜荔支嘗。", "月鎖千門靜，天高一笛涼。", "細音搖翠佩，輕步宛霓裳。", "禍亂根潛結，昇平意遽忘。", "衣冠逃犬虜，鼙鼓動漁陽。", "外戚心殊迫，中途事可量。", "雪埋妃子貌，刃斷祿兒腸。", "近侍煙塵隔，前蹤輦路荒。", "益知迷寵佞，惟恨喪忠良。", "北闕尊明主，南宮遜上皇。", "禁清餘鳳吹，池冷映龍光。", "祝壽山猶在，流年水共傷。", "杜鵑魂厭蜀，蝴蝶夢悲莊。"]'),
('f14db484-e8c2-4bfc-8a42-95ac02f41574','穆護砂','張祜','唐','唐诗','tang','','[]','玉管朝朝弄，清歌日日新。',24,'全唐诗/poet.tang.27000.json','["玉管朝朝弄，清歌日日新。", "折花當驛路，寄與隴頭人。"]'),
('cafbc059-b035-4aed-9592-01c51be8eb59','思歸樂二首 一','張祜','唐','唐诗','tang','','[]','晚日催弦管，春風入綺羅。',24,'全唐诗/poet.tang.27000.json','["晚日催弦管，春風入綺羅。", "杏花如有意，偏落舞衫多。"]'),
