('e8f3ea6d-cf39-424c-b483-3f557f56b0bf','孟才人歎','張祜','唐','唐诗','tang','','[]','偶因歌態詠嬌嚬，傳唱宮中十二春。',32,'全唐诗/poet.tang.27000.json','["偶因歌態詠嬌嚬，傳唱宮中十二春。", "却爲一聲河滿子，下泉須弔舊才人。"]'),
('27903dde-9692-4fc3-b9d2-c03a176e26be','聽簡上人吹蘆管三首 一','張祜','唐','唐诗','tang','','[]','蜀國僧吹蘆一枝，隴西游客淚先垂。',32,'全唐诗/poet.tang.27000.json','["蜀國僧吹蘆一枝，隴西游客淚先垂。", "至今留得新聲在，却爲中原人不知。"]'),
('ea91be6d-fb29-44e1-aee5-53875699344e','聽簡上人吹蘆管三首 二','張祜','唐','唐诗','tang','','[]','細蘆僧管夜沈沈，越鳥巴猨寄恨吟。',32,'全唐诗/poet.tang.27000.json','["細蘆僧管夜沈沈，越鳥巴猨寄恨吟。", "吹到耳邊聲盡處，一條絲斷碧雲心。"]'),
('6790eaa6-d1c9-4868-a78d-08a0c7b6417b','聽簡上人吹蘆管三首 三','張祜','唐','唐诗','tang','','[]','月落江城樹繞鴉，一聲蘆管是天涯。',32,'全唐诗/poet.tang.27000.json','["月落江城樹繞鴉，一聲蘆管是天涯。", "分明西國人來說，赤佛堂西是漢家。"]'),
('9439f354-b5fd-49d2-8142-99828b73eab3','聽岳州徐員外彈琴','張祜','唐','唐诗','tang','','[]','玉律潛符一古琴，哲人心見聖人心。',32,'全唐诗/poet.tang.27000.json','["玉律潛符一古琴，哲人心見聖人心。", "盡日南風似遺意，九疑猨鳥滿山吟。"]'),
('5f564bda-46fc-4dfd-b27e-d08725343e3e','鉤弋夫人詞','張祜','唐','唐诗','tang','','[]','惆悵雲陵事不迴，萬金重更築仙臺。',32,'全唐诗/poet.tang.27000.json','["惆悵雲陵事不迴，萬金重更築仙臺。", "莫言天上無消息，猶是夫人作鳥來。"]'),
('ac6cdfa4-14f4-401a-a4b7-b1d3354d623b','鴻溝','張祜','唐','唐诗','tang','','[]','龍蛇百戰爭天下，各制雄心指此溝。',32,'全唐诗/poet.tang.27000.json','["龍蛇百戰爭天下，各制雄心指此溝。", "寧似九州分國土，地圖初割海中流。"]'),
('63dbfe11-242b-4a60-8c55-bfe5f7230cae','悲納鐵','張祜','唐','唐诗','tang','','[]','長聞爲政古諸侯，使佩刀人盡佩牛。',32,'全唐诗/poet.tang.27000.json','["長聞爲政古諸侯，使佩刀人盡佩牛。", "誰謂今來正耕墾，却銷農器作戈矛。"]'),
('e8a64325-11a5-40b9-af4e-42f834e91395','胡渭州','張祜','唐','唐诗','tang','','["\u957f\u6c5f"]','亭亭孤月照行舟，寂寂長江萬里流。',32,'全唐诗/poet.tang.27000.json','["亭亭孤月照行舟，寂寂長江萬里流。", "鄉國不知何處是，雲山漫漫使人愁。"]'),
('bebccba0-7ac5-437e-a953-f91c86d7deda','破陣樂','張祜','唐','唐诗','tang','','[]','秋風四面足風沙，塞外征人暫別家。',32,'全唐诗/poet.tang.27000.json','["秋風四面足風沙，塞外征人暫別家。", "千里不辭行路遠，時光早晚到天涯。"]'),
('1f740d6e-dc77-436e-8743-64fd0cb8dc36','楓橋','張祜','唐','唐诗','tang','','[]','長洲苑外草蕭蕭，卻算游城歲月遙。',32,'全唐诗/poet.tang.27000.json','["長洲苑外草蕭蕭，卻算游城歲月遙。", "唯有別時今不忘，暮煙疎雨過楓橋。"]'),
('3561d89c-77fe-4e95-9d57-b2d718949259','句','張祜','唐','唐诗','tang','','[]','萬國見清道，一身成白頭。',88,'全唐诗/poet.tang.27000.json','["萬國見清道，一身成白頭。", "此地榮辱盛，豈宜山中人。", "椿兒遶樹春園裏，桂子尋花夜月中。", "一身扶杖二兒隨。", "夏雨蓮苞破，秋風桂子彫。", "杜鵑花發杜鵑叫，烏臼花生烏臼啼。", "茶風無奈筆，酒禿不勝簪。"]'),
('3f9ded2c-701c-48c5-bb42-8148b98df9f0','荅李昌期','楊洵美','唐','唐诗','tang','','[]','三山載羣仙，峨峨鹹浪中。',60,'全唐诗/poet.tang.27000.json','["三山載羣仙，峨峨鹹浪中。", "雲衣剪不得，此路安可從。", "我生亦何事，出門如飛蓬。", "白日又黃昏，所悲瑤草空。", "蟲聲故鄉夢，枕上禾黍風。"]'),
('5bcf3329-95e1-410f-b6fd-7f99bbdd191a','宮詞','長孫翱','唐','唐诗','tang','','[]','一道甘泉接御溝，上皇行處不曾秋。',32,'全唐诗/poet.tang.27000.json','["一道甘泉接御溝，上皇行處不曾秋。", "誰言水是無情物，也到宮前咽不流。"]'),
('c5bff5dc-b6bc-4694-8aa9-1be72babf78a','和于中丞登越王樓見寄','盧求','唐','唐诗','tang','','[]','高情推謝守，善政屬綿州。',48,'全唐诗/poet.tang.27000.json','["高情推謝守，善政屬綿州。", "未落紫泥詔，閑登白雪樓。", "晴江如送日，寒嶺鎮迎秋。", "滿壁朝天士，唯予不繫舟。"]'),
('5b604f1b-8e67-4786-b813-e73fda0f33ea','雨','歐陽衮','唐','唐诗','tang','','[]','細雨弄春陰，餘寒入晝深。',48,'全唐诗/poet.tang.27000.json','["細雨弄春陰，餘寒入晝深。", "山姿輕薄霧，煙色澹幽林。", "鹿踐莓苔滑，魚牽水荇沈。", "懷情方未已，清酒漫須斟。"]'),
('10b5887d-00d2-4028-b30d-1554f6303e82','田家','歐陽衮','唐','唐诗','tang','','[]','黯黯日將夕，牛羊村外來。',48,'全唐诗/poet.tang.27000.json','["黯黯日將夕，牛羊村外來。", "巖阿青氣發，籬落杏花開。", "草木應初感，鶬鶊亦已催。", "晚間春作好，行樂不須猜。"]'),
('518a8139-2a76-4240-a09c-c11cbbd7330f','神光寺','歐陽衮','唐','唐诗','tang','','[]','香剎懸青磴，飛樓界碧空。',48,'全唐诗/poet.tang.27000.json','["香剎懸青磴，飛樓界碧空。", "石門棲怖鴿，慈塔繞歸鴻。", "有法將心鏡，無名屬性通。", "從來樂幽寂，尋覓未能窮。"]'),
('2987bf38-3eb9-4921-997e-63f73ddb87c7','和項斯遊頭陀寺上方','歐陽衮','唐','唐诗','tang','','[]','步入桃源裏，晴花更滿枝。',48,'全唐诗/poet.tang.27000.json','["步入桃源裏，晴花更滿枝。", "峰迴山意曠，林杳竹光遲。", "遠寺尋龍藏，名香發雁池。", "間能將遠語，況及上陽時。"]'),
('d627c5e2-ffbc-46e5-a7c3-93bfa7acf5c9','秦原道中','歐陽衮','唐','唐诗','tang','','[]','分險架長瀾，斜梁控夕巒。',48,'全唐诗/poet.tang.27000.json','["分險架長瀾，斜梁控夕巒。", "宿雲依嶺斷，初月入江寒。", "緇化秦裘敝，塵驚漢策殘。", "無言倦行旅，遙路屬時難。"]'),
('adf79114-7087-45d8-aabd-0785e3b87c57','月峰寺憶理公','歐陽衮','唐','唐诗','tang','','[]','共來江海上，清論一宵同。',48,'全唐诗/poet.tang.27000.json','["共來江海上，清論一宵同。", "禪榻渾依舊，心期浩已空。", "驚春花落樹，聞梵澗搖風。", "二諦欣咨啓，還應夢寐通。"]'),
('eed70620-1d1b-4b42-979b-93d0c86a4b89','寄陳去疾進士','歐陽衮','唐','唐诗','tang','','[]','放跡疑辭垢，棲心亦道門。',48,'全唐诗/poet.tang.27000.json','["放跡疑辭垢，棲心亦道門。", "玄言蘿幌馥，詩思竹爐溫。", "解帶搖花落，彈琴散鳥喧。", "江山茲夕意，唯有素交存。"]'),
('cc996bf3-c19e-4646-9bf2-4a2985b40380','聽郢客歌陽春白雪','歐陽衮','唐','唐诗','tang','','[]','寂聽郢中人，高歌已絕倫。',72,'全唐诗/poet.tang.27000.json','["寂聽郢中人，高歌已絕倫。", "臨風飄白雪，向日奏陽春。", "調雅偏盈耳，聲長杳入神。", "連連貫珠並，嬝嬝遏雲頻。", "度曲知難和，凝情想任真。", "周郎如賞羨，莫使滯芳晨。"]'),
('d794d28c-ae8b-4aed-95b5-ba69e8b876ec','南澗寺','歐陽衮','唐','唐诗','tang','','[]','春寺無人亂鳥啼，藤蘿陰磴野僧迷。',64,'全唐诗/poet.tang.27000.json','["春寺無人亂鳥啼，藤蘿陰磴野僧迷。", "雲藏古壁遺龍象，草沒香臺抱鹿麛。", "松籟泠泠疑梵唄，柳煙歷歷見招提。", "爲耽寂樂親禪侶，莫怪閑行費馬蹄。"]'),
('c11f31b0-1281-4177-b874-b85ce67272e4','獻歲書情','裴夷直','唐','唐诗','tang','','[]','白髮添雙鬢，空宮又一年。',48,'全唐诗/poet.tang.27000.json','["白髮添雙鬢，空宮又一年。", "音書鴻不到，夢寐兔空懸。", "地遠星辰側，天高雨露偏。", "聖期知有感，雲海漫相連。"]'),
('3730d401-ecd8-46d1-acb3-f8c577d7e1da','奉和大梁相公重九日軍中宴會之什','裴夷直','唐','唐诗','tang','','[]','今古同嘉節，歡娛但異名。',48,'全唐诗/poet.tang.27000.json','["今古同嘉節，歡娛但異名。", "陶公緣綠醑，謝傅爲蒼生。", "酒泛金英麗，詩通玉律清。", "何言辭物累，方繫萬人情。"]'),
('3cc7e2e0-9bf5-4198-8d41-53a109a56646','奉和大梁相公同張員外重九日宴集','裴夷直','唐','唐诗','tang','','[]','重九思嘉節，追歡從謝公。',48,'全唐诗/poet.tang.27000.json','["重九思嘉節，追歡從謝公。", "酒清欺玉露，菊盛愧金風。", "不待秋蟾白，須沈落照紅。", "更將門下客，酬和管弦中。"]'),
('582a0b30-3ddf-4db9-bbcd-dd0f231c46bf','同樂天中秋夜洛河翫月二首 一','裴夷直','唐','唐诗','tang','','[]','清洛半秋懸璧月，綵船當夕泛銀河。',64,'全唐诗/poet.tang.27000.json','["清洛半秋懸璧月，綵船當夕泛銀河。", "蒼龍頷底珠皆沒，白帝心邊鏡乍磨。", "海上幾時霜雪積，人間此夜管弦多。", "須知天地爲鑪意，盡取黃金鑄作波。"]');
